+++ b/App/Layers/W1/Tests/ERM/ERMFinChargeMemoMultPostGrp.Codeunit.al
@@ -0,0 +1,190 @@
+codeunit 139999 "ERM Fin Charge Memo Mult Post Grp"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Finance Charge Memo] [Multiple Posting Groups]
+    end;
+
+    var
+        LibraryERM: Codeunit "Library - ERM";
+        LibrarySales: Codeunit "Library - Sales";
+        LibrarySetupStorage: Codeunit "Library - Setup Storage";
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        Assert: Codeunit Assert;
+        isInitialized: Boolean;
+
+    [Test]
+    [HandlerFunctions('SuggestFinChargeMemoLinesRequestPageHandler')]
+    [Scope('OnPrem')]
+    procedure IssueFinChargeMemoWithAltCustomerPostingGroupUsesCorrectReceivablesAccount()
+    var
+        Customer: Record Customer;
+        OriginalCustomerPostingGroup: Record "Customer Posting Group";
+        AlternativeCustomerPostingGroup: Record "Customer Posting Group";
+        FinanceChargeTerms: Record "Finance Charge Terms";
+        FinanceChargeMemoHeader: Record "Finance Charge Memo Header";
+        IssuedFinChargeMemoHeader: Record "Issued Fin. Charge Memo Header";
+        GLEntry: Record "G/L Entry";
+        CustLedgerEntry: Record "Cust. Ledger Entry";
+        InvoiceDate: Date;
+        FinanceChargeDate: Date;
+    begin
+        // [SCENARIO] When issuing a Finance Charge Memo with an alternative Customer Posting Group,
+        // the G/L entries should be posted to the Receivables Account of the alternative posting group,
+        // not the original customer's posting group.
+        Initialize();
+
+        // [GIVEN] Sales & Receivables Setup with "Allow Multiple Posting Groups" enabled
+        SetSalesAllowMultiplePostingGroups(true);
+
+        // [GIVEN] Finance charge terms with Post Interest enabled
+        CreateFinanceChargeTerms(FinanceChargeTerms);
+
+        // [GIVEN] A customer with "Allow Multiple Posting Groups" enabled
+        LibrarySales.CreateCustomer(Customer);
+        OriginalCustomerPostingGroup.Get(Customer."Customer Posting Group");
+        Customer.Validate("Allow Multiple Posting Groups", true);
+        Customer.Validate("Fin. Charge Terms Code", FinanceChargeTerms.Code);
+        Customer.Modify(true);
+
+        // [GIVEN] An alternative customer posting group with a different Receivables Account
+        LibrarySales.CreateCustomerPostingGroup(AlternativeCustomerPostingGroup);
+        // Create the alternative posting group relationship
+        LibrarySales.CreateAltCustomerPostingGroup(Customer."Customer Posting Group", AlternativeCustomerPostingGroup.Code);
+
+        // [GIVEN] A posted sales invoice
+        InvoiceDate := WorkDate();
+        FinanceChargeDate := InvoiceDate + 62;
+        CreateAndPostSalesInvoice(Customer, InvoiceDate, LibraryRandom.RandDecInRange(1000, 2000, 2));
+
+        // [GIVEN] A finance charge memo with the alternative customer posting group
+        CreateFinanceChargeMemoWithLines(FinanceChargeMemoHeader, Customer, FinanceChargeDate);
+        FinanceChargeMemoHeader.Get(FinanceChargeMemoHeader."No.");
+        FinanceChargeMemoHeader.Validate("Customer Posting Group", AlternativeCustomerPostingGroup.Code);
+        FinanceChargeMemoHeader.Modify(true);
+
+        // [WHEN] The finance charge memo is issued
+        LibraryERM.IssueFinanceChargeMemo(FinanceChargeMemoHeader);
+
+        // [THEN] The issued finance charge memo has the alternative customer posting group
+        FindIssuedFinanceChargeMemo(IssuedFinChargeMemoHeader, FinanceChargeMemoHeader);
+        Assert.AreEqual(
+            AlternativeCustomerPostingGroup.Code,
+            IssuedFinChargeMemoHeader."Customer Posting Group",
+            'Issued Finance Charge Memo should have the alternative Customer Posting Group');
+
+        // [THEN] The Customer Ledger Entry has the alternative customer posting group
+        CustLedgerEntry.SetRange("Customer No.", Customer."No.");
+        CustLedgerEntry.SetRange("Document Type", CustLedgerEntry."Document Type"::"Finance Charge Memo");
+        CustLedgerEntry.SetRange("Document No.", IssuedFinChargeMemoHeader."No.");
+        CustLedgerEntry.FindFirst();
+        Assert.AreEqual(
+            AlternativeCustomerPostingGroup.Code,
+            CustLedgerEntry."Customer Posting Group",
+            'Customer Ledger Entry should have the alternative Customer Posting Group');
+
+        // [THEN] G/L entries are posted to the alternative posting group's Receivables Account
+        GLEntry.SetRange("Document Type", GLEntry."Document Type"::"Finance Charge Memo");
+        GLEntry.SetRange("Document No.", IssuedFinChargeMemoHeader."No.");
+        GLEntry.SetRange("G/L Account No.", AlternativeCustomerPostingGroup."Receivables Account");
+        Assert.RecordIsNotEmpty(GLEntry);
+
+        // [THEN] G/L entries are NOT posted to the original posting group's Receivables Account
+        GLEntry.SetRange("G/L Account No.", OriginalCustomerPostingGroup."Receivables Account");
+        Assert.RecordIsEmpty(GLEntry);
+    end;
+
+    local procedure Initialize()
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"ERM Fin Charge Memo Mult Post Grp");
+
+        LibrarySetupStorage.Restore();
+        if isInitialized then
+            exit;
+
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"ERM Fin Charge Memo Mult Post Grp");
+
+        LibrarySetupStorage.Save(DATABASE::"Sales & Receivables Setup");
+        isInitialized := true;
+        Commit();
+
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"ERM Fin Charge Memo Mult Post Grp");
+    end;
+
+    local procedure SetSalesAllowMultiplePostingGroups(AllowMultiplePostingGroups: Boolean)
+    var
+        SalesReceivablesSetup: Record "Sales & Receivables Setup";
+    begin
+        SalesReceivablesSetup.Get();
+        SalesReceivablesSetup."Allow Multiple Posting Groups" := AllowMultiplePostingGroups;
+        SalesReceivablesSetup."Check Multiple Posting Groups" := "Posting Group Change Method"::"Alternative Groups";
+        SalesReceivablesSetup.Modify();
+    end;
+
+    local procedure CreateFinanceChargeTerms(var FinanceChargeTerms: Record "Finance Charge Terms")
+    begin
+        LibraryERM.CreateFinanceChargeTerms(FinanceChargeTerms);
+        FinanceChargeTerms.Validate("Interest Calculation", FinanceChargeTerms."Interest Calculation"::"Open Entries");
+        FinanceChargeTerms.Validate("Interest Calculation Method", FinanceChargeTerms."Interest Calculation Method"::"Average Daily Balance");
+        FinanceChargeTerms.Validate("Interest Rate", 1.5);
+        FinanceChargeTerms.Validate("Interest Period (Days)", 30);
+        FinanceChargeTerms.Validate("Minimum Amount (LCY)", 10);
+        FinanceChargeTerms.Validate("Additional Fee (LCY)", 0);
+        Evaluate(FinanceChargeTerms."Grace Period", '<5D>');
+        Evaluate(FinanceChargeTerms."Due Date Calculation", '<1M>');
+        FinanceChargeTerms.Validate("Post Interest", true);
+        FinanceChargeTerms.Validate("Post Additional Fee", false);
+        FinanceChargeTerms.Modify(true);
+    end;
+
+    local procedure CreateAndPostSalesInvoice(Customer: Record Customer; PostingDate: Date; LineAmount: Decimal)
+    var
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+    begin
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Invoice, Customer."No.");
+        SalesHeader.Validate("Posting Date", PostingDate);
+        SalesHeader.Modify(true);
+
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::"G/L Account", LibraryERM.CreateGLAccountWithSalesSetup(), 1);
+        SalesLine.Validate("Unit Price", LineAmount);
+        SalesLine.Modify(true);
+
+        LibrarySales.PostSalesDocument(SalesHeader, true, true);
+    end;
+
+    local procedure CreateFinanceChargeMemoWithLines(var FinanceChargeMemoHeader: Record "Finance Charge Memo Header"; Customer: Record Customer; PostingDate: Date)
+    var
+        FinanceChargeMemoPage: TestPage "Finance Charge Memo";
+    begin
+        LibraryERM.CreateFinanceChargeMemoHeader(FinanceChargeMemoHeader, Customer."No.");
+        FinanceChargeMemoHeader.Validate("Posting Date", PostingDate);
+        FinanceChargeMemoHeader.Validate("Document Date", PostingDate);
+        FinanceChargeMemoHeader.Modify(true);
+
+        Commit();
+
+        FinanceChargeMemoPage.OpenEdit();
+        FinanceChargeMemoPage.FILTER.SetFilter("No.", FinanceChargeMemoHeader."No.");
+        FinanceChargeMemoPage.SuggestFinChargeMemoLines.Invoke();
+        FinanceChargeMemoPage.Close();
+    end;
+
+    local procedure FindIssuedFinanceChargeMemo(var IssuedFinChargeMemoHeader: Record "Issued Fin. Charge Memo Header"; FinanceChargeMemoHeader: Record "Finance Charge Memo Header")
+    begin
+        IssuedFinChargeMemoHeader.SetRange("Customer No.", FinanceChargeMemoHeader."Customer No.");
+        IssuedFinChargeMemoHeader.SetRange("Pre-Assigned No.", FinanceChargeMemoHeader."No.");
+        IssuedFinChargeMemoHeader.FindFirst();
+    end;
+
+    [RequestPageHandler]
+    [Scope('OnPrem')]
+    procedure SuggestFinChargeMemoLinesRequestPageHandler(var SuggestFinChargeMemoLines: TestRequestPage "Suggest Fin. Charge Memo Lines")
+    begin
+        SuggestFinChargeMemoLines.OK().Invoke();
+    end;
+}

diff --git a/App/Layers/W1/Tests/SCM/SCMItemJnlLineUOMValidation.Codeunit.al b/App/Layers/W1/Tests/SCM/SCMItemJnlLineUOMValidation.Codeunit.al
