@@ -0,0 +1,145 @@
+codeunit 137298 "SCM Item Jnl Line UOM Validation"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Item Journal] [Unit of Measure] [SCM]
+    end;
+
+    var
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        Assert: Codeunit Assert;
+        isInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure ChangingItemNoClearsUnitOfMeasureCode()
+    var
+        Item1: Record Item;
+        Item2: Record Item;
+        ItemUnitOfMeasure1: Record "Item Unit of Measure";
+        ItemUnitOfMeasure2: Record "Item Unit of Measure";
+        ItemJournalLine: Record "Item Journal Line";
+        ItemJournalBatch: Record "Item Journal Batch";
+        ItemJournalTemplate: Record "Item Journal Template";
+        UnitOfMeasure1: Record "Unit of Measure";
+        UnitOfMeasure2: Record "Unit of Measure";
+    begin
+        // [SCENARIO] When changing Item No. on Item Journal Line, the Unit of Measure Code should be cleared and revalidated
+        // This prevents validation errors when the new item has a different UOM than the previous item
+
+        // [GIVEN] Two items with different Unit of Measure Codes
+        Initialize();
+
+        // Create first item with a specific UOM (e.g., PCS)
+        LibraryInventory.CreateUnitOfMeasureCode(UnitOfMeasure1);
+        LibraryInventory.CreateItem(Item1);
+        LibraryInventory.CreateItemUnitOfMeasure(ItemUnitOfMeasure1, Item1."No.", UnitOfMeasure1.Code, 1);
+        Item1.Validate("Base Unit of Measure", UnitOfMeasure1.Code);
+        Item1.Modify(true);
+
+        // Create second item with a different UOM (e.g., BOX)
+        LibraryInventory.CreateUnitOfMeasureCode(UnitOfMeasure2);
+        LibraryInventory.CreateItem(Item2);
+        LibraryInventory.CreateItemUnitOfMeasure(ItemUnitOfMeasure2, Item2."No.", UnitOfMeasure2.Code, 1);
+        Item2.Validate("Base Unit of Measure", UnitOfMeasure2.Code);
+        Item2.Modify(true);
+
+        // Create Item Journal Line for first item
+        LibraryInventory.SelectItemJournalTemplateName(ItemJournalTemplate, ItemJournalTemplate.Type::Item);
+        LibraryInventory.SelectItemJournalBatchName(ItemJournalBatch, ItemJournalBatch."Template Type"::Item, ItemJournalTemplate.Name);
+        LibraryInventory.ClearItemJournal(ItemJournalTemplate, ItemJournalBatch);
+        LibraryInventory.CreateItemJournalLine(
+            ItemJournalLine, ItemJournalBatch."Journal Template Name", ItemJournalBatch.Name,
+            ItemJournalLine."Entry Type"::"Positive Adjmt.", Item1."No.", LibraryRandom.RandDec(10, 2));
+
+        // Verify first item's UOM is set
+        Assert.AreEqual(UnitOfMeasure1.Code, ItemJournalLine."Unit of Measure Code",
+            'Unit of Measure Code should be set to first item''s base UOM');
+
+        // [WHEN] Change Item No. to second item
+        ItemJournalLine.Validate("Item No.", Item2."No.");
+
+        // [THEN] Unit of Measure Code should be cleared and revalidated to the new item's UOM
+        // Without the fix, this would fail with: "The field Unit of Measure Code of table Item Journal Line 
+        // contains a value (PCS) that cannot be found in the related table (Item Unit of Measure)."
+        Assert.AreEqual(UnitOfMeasure2.Code, ItemJournalLine."Unit of Measure Code",
+            'Unit of Measure Code should be updated to second item''s base UOM');
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure ChangingItemNoInReclassJournalClearsUOM()
+    var
+        Item1: Record Item;
+        Item2: Record Item;
+        ItemUnitOfMeasure1: Record "Item Unit of Measure";
+        ItemUnitOfMeasure2: Record "Item Unit of Measure";
+        ItemJournalLine: Record "Item Journal Line";
+        ItemJournalBatch: Record "Item Journal Batch";
+        ItemJournalTemplate: Record "Item Journal Template";
+        UnitOfMeasure1: Record "Unit of Measure";
+        UnitOfMeasure2: Record "Unit of Measure";
+    begin
+        // [SCENARIO] When changing Item No. on Item Reclassification Journal Line, the Unit of Measure Code should be cleared
+        // This is the specific scenario from the bug report
+
+        // [GIVEN] Two items with different Unit of Measure Codes
+        Initialize();
+
+        // Create first item with UOM "PCS"
+        LibraryInventory.CreateUnitOfMeasureCode(UnitOfMeasure1);
+        LibraryInventory.CreateItem(Item1);
+        LibraryInventory.CreateItemUnitOfMeasure(ItemUnitOfMeasure1, Item1."No.", UnitOfMeasure1.Code, 1);
+        Item1.Validate("Base Unit of Measure", UnitOfMeasure1.Code);
+        Item1.Modify(true);
+
+        // Create second item with different UOM
+        LibraryInventory.CreateUnitOfMeasureCode(UnitOfMeasure2);
+        LibraryInventory.CreateItem(Item2);
+        LibraryInventory.CreateItemUnitOfMeasure(ItemUnitOfMeasure2, Item2."No.", UnitOfMeasure2.Code, 1);
+        Item2.Validate("Base Unit of Measure", UnitOfMeasure2.Code);
+        Item2.Modify(true);
+
+        // Create Item Reclassification Journal Line for first item
+        LibraryInventory.SelectItemJournalTemplateName(ItemJournalTemplate, ItemJournalTemplate.Type::Transfer);
+        LibraryInventory.SelectItemJournalBatchName(ItemJournalBatch, ItemJournalBatch."Template Type"::Transfer, ItemJournalTemplate.Name);
+        LibraryInventory.ClearItemJournal(ItemJournalTemplate, ItemJournalBatch);
+        LibraryInventory.CreateItemJournalLine(
+            ItemJournalLine, ItemJournalBatch."Journal Template Name", ItemJournalBatch.Name,
+            ItemJournalLine."Entry Type"::Transfer, Item1."No.", LibraryRandom.RandDec(10, 2));
+
+        // Verify first item's UOM is set
+        Assert.AreEqual(UnitOfMeasure1.Code, ItemJournalLine."Unit of Measure Code",
+            'Unit of Measure Code should be set to first item''s base UOM');
+
+        // [WHEN] Delete Item No. and add second item (simulating the repro steps)
+        ItemJournalLine.Validate("Item No.", '');  // Clear item first
+        ItemJournalLine.Validate("Item No.", Item2."No.");  // Add new item
+
+        // [THEN] Unit of Measure Code should be cleared and revalidated to the new item's UOM
+        Assert.AreEqual(UnitOfMeasure2.Code, ItemJournalLine."Unit of Measure Code",
+            'Unit of Measure Code should be updated to second item''s base UOM after clearing and re-adding item');
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"SCM Item Jnl Line UOM Validation");
+
+        if isInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"SCM Item Jnl Line UOM Validation");
+
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+
+        isInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"SCM Item Jnl Line UOM Validation");
+    end;
+}

