+    begin
+        // [FEATURE] [Purchase] [Item] [Variant]
+        // [SCENARIO] When creating a new price list line for an item with variants, the variant code should not be preset from the previous line.
+        Initialize(true);
+
+        // [GIVEN] Item 'I' with two Variants 'V1' and 'V2'
+        LibraryInventory.CreateItem(Item);
+        LibraryInventory.CreateItemVariant(ItemVariant[1], Item."No.");
+        LibraryInventory.CreateItemVariant(ItemVariant[2], Item."No.");
+
+        // [GIVEN] Price list for 'All Vendors'
+        LibraryPriceCalculation.CreatePriceHeader(PriceListHeader, "Price Type"::Purchase, "Price Source Type"::"All Vendors", '');
