+        // [GIVEN] Add first line for Item 'I' with Variant 'V1'
+        PurchasePriceList.Lines.New();
+        PurchasePriceList.Lines."Asset Type".SetValue("Price Asset Type"::Item);
+        PurchasePriceList.Lines."Asset No.".SetValue(Item."No.");
+        PurchasePriceList.Lines."Variant Code".SetValue(ItemVariant[1].Code);
+        PurchasePriceList.Lines."Direct Unit Cost".SetValue(50);
+
+        // [WHEN] Add a new line for the same Item 'I'
+        PurchasePriceList.Lines.New();
+        PurchasePriceList.Lines."Asset Type".SetValue("Price Asset Type"::Item);
+        PurchasePriceList.Lines."Asset No.".SetValue(Item."No.");
+
+        // [THEN] "Variant Code" should be blank (not preset from previous line)
+        PurchasePriceList.Lines."Variant Code".AssertEquals('');
