+++ b/App/Layers/W1/Tests/Job/RecurringJobJournalTests.Codeunit.al
@@ -0,0 +1,166 @@
+// ------------------------------------------------------------------------------------------------
+// Copyright (c) Microsoft Corporation. All rights reserved.
+// Licensed under the MIT License. See License.txt in the project root for license information.
+// ------------------------------------------------------------------------------------------------
+codeunit 136399 "Recurring Job Journal Tests"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Recurring Job Journal]
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryJob: Codeunit "Library - Job";
+        LibraryResource: Codeunit "Library - Resource";
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryUtility: Codeunit "Library - Utility";
+        IsInitialized: Boolean;
+
+    [Test]
+    [HandlerFunctions('ConfirmHandlerYes,MessageHandler')]
+    procedure RecurringVariableMethodPreservesUnitCostAndPrice()
+    var
+        JobTask: Record "Job Task";
+        JobJournalTemplate: Record "Job Journal Template";
+        JobJournalBatch: Record "Job Journal Batch";
+        JobJournalLine: Record "Job Journal Line";
+        Resource: Record Resource;
+        OriginalUnitCost: Decimal;
+        OriginalUnitPrice: Decimal;
+    begin
+        // [SCENARIO] When posting a Recurring Job Journal line with Variable method, Unit Cost and Unit Price should be preserved after posting
+        // [GIVEN] A Recurring Job Journal Template and Batch
+        Initialize();
+        CreateRecurringJobJournalBatch(JobJournalTemplate, JobJournalBatch);
+
+        // [GIVEN] A Job with Job Task
+        CreateJobWithJobTask(JobTask);
+
+        // [GIVEN] A Resource with known Unit Cost and Unit Price
+        LibraryResource.CreateResource(Resource, '');
+        Resource.Validate("Direct Unit Cost", LibraryRandom.RandDecInRange(10, 100, 2));
+        Resource.Validate("Unit Price", LibraryRandom.RandDecInRange(50, 200, 2));
+        Resource.Modify(true);
+
+        // [GIVEN] A Recurring Job Journal Line with Variable method, Type Resource, Quantity, Unit Cost and Unit Price
+        CreateRecurringJobJournalLine(JobJournalLine, JobJournalTemplate.Name, JobJournalBatch.Name, JobTask, Resource."No.");
+        OriginalUnitCost := JobJournalLine."Unit Cost";
+        OriginalUnitPrice := JobJournalLine."Unit Price";
+
+        // [WHEN] The Recurring Job Journal is posted
+        CODEUNIT.Run(CODEUNIT::"Job Jnl.-Post Batch", JobJournalLine);
+
+        // [THEN] The Job Journal Line should still exist (recurring)
+        JobJournalLine.SetRange("Journal Template Name", JobJournalTemplate.Name);
+        JobJournalLine.SetRange("Journal Batch Name", JobJournalBatch.Name);
+        JobJournalLine.FindFirst();
+
+        // [THEN] Unit Cost and Unit Price should be preserved (not zeroed out)
+        Assert.AreEqual(OriginalUnitCost, JobJournalLine."Unit Cost",
+            'Unit Cost should be preserved after posting recurring variable method job journal line');
+        Assert.AreEqual(OriginalUnitPrice, JobJournalLine."Unit Price",
+            'Unit Price should be preserved after posting recurring variable method job journal line');
+
+        // [THEN] Quantity should be zeroed (Variable method)
+        Assert.AreEqual(0, JobJournalLine.Quantity,
+            'Quantity should be zeroed after posting recurring variable method job journal line');
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(CODEUNIT::"Recurring Job Journal Tests");
+        if IsInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(CODEUNIT::"Recurring Job Journal Tests");
+
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.CreateGeneralPostingSetupData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        LibraryERMCountryData.UpdateJournalTemplMandatory(false);
+
+        IsInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(CODEUNIT::"Recurring Job Journal Tests");
+    end;
+
+    local procedure CreateJobWithJobTask(var JobTask: Record "Job Task")
+    var
+        Job: Record Job;
+        Customer: Record Customer;
+        LibrarySales: Codeunit "Library - Sales";
+    begin
+        LibrarySales.CreateCustomer(Customer);
+        LibraryJob.CreateJob(Job, Customer."No.");
+        LibraryJob.CreateJobTask(Job, JobTask);
+    end;
+
+    local procedure CreateRecurringJobJournalBatch(var JobJournalTemplate: Record "Job Journal Template"; var JobJournalBatch: Record "Job Journal Batch")
+    var
+        NoSeries: Record "No. Series";
+        NoSeriesLine: Record "No. Series Line";
+        LibraryNoSeries: Codeunit "Library - No. Series";
+    begin
+        // Create a Recurring Job Journal Template
+        JobJournalTemplate.Init();
+        JobJournalTemplate.Validate(Name, LibraryUtility.GenerateRandomCode(JobJournalTemplate.FieldNo(Name), DATABASE::"Job Journal Template"));
+        JobJournalTemplate.Insert(true);
+        JobJournalTemplate.Validate(Recurring, true);
+        JobJournalTemplate.Modify(true);
+
+        // Create No. Series for posting
+        LibraryNoSeries.CreateNoSeries(NoSeries, true, false, false);
+        LibraryNoSeries.CreateNoSeriesLine(NoSeriesLine, NoSeries.Code, '', '');
+
+        // Create Job Journal Batch
+        JobJournalBatch.Init();
+        JobJournalBatch.Validate("Journal Template Name", JobJournalTemplate.Name);
+        JobJournalBatch.Validate(Name, LibraryUtility.GenerateRandomCode(JobJournalBatch.FieldNo(Name), DATABASE::"Job Journal Batch"));
+        JobJournalBatch.Insert(true);
+        JobJournalBatch.Validate("Posting No. Series", NoSeries.Code);
+        JobJournalBatch.Modify(true);
+    end;
+
+    local procedure CreateRecurringJobJournalLine(var JobJournalLine: Record "Job Journal Line"; TemplateName: Code[10]; BatchName: Code[10]; JobTask: Record "Job Task"; ResourceNo: Code[20])
+    var
+        RecurringFrequency: DateFormula;
+    begin
+        Evaluate(RecurringFrequency, '<1M>');
+
+        JobJournalLine.Init();
+        JobJournalLine.Validate("Journal Template Name", TemplateName);
+        JobJournalLine.Validate("Journal Batch Name", BatchName);
+        JobJournalLine.Validate("Line No.", 10000);
+        JobJournalLine.Insert(true);
+
+        JobJournalLine.Validate("Posting Date", WorkDate());
+        JobJournalLine.Validate("Document No.", LibraryUtility.GenerateGUID());
+        JobJournalLine.Validate("Job No.", JobTask."Job No.");
+        JobJournalLine.Validate("Job Task No.", JobTask."Job Task No.");
+        JobJournalLine.Validate("Line Type", JobJournalLine."Line Type"::Billable);
+        JobJournalLine.Validate(Type, JobJournalLine.Type::Resource);
+        JobJournalLine.Validate("No.", ResourceNo);
+        JobJournalLine.Validate(Quantity, LibraryRandom.RandIntInRange(1, 10));
+        JobJournalLine.Validate("Recurring Method", JobJournalLine."Recurring Method"::Variable);
+        JobJournalLine.Validate("Recurring Frequency", RecurringFrequency);
+        JobJournalLine.Modify(true);
+    end;
+
+    [ConfirmHandler]
+    procedure ConfirmHandlerYes(Question: Text[1024]; var Reply: Boolean)
+    begin
+        Reply := true;
+    end;
+
+    [MessageHandler]
+    procedure MessageHandler(Message: Text[1024])
+    begin
+        // Empty handler to suppress messages
+    end;
+}

diff --git a/App/Layers/W1/Tests/SCM/SCMInvtPickInvoiceDiscount.Codeunit.al b/App/Layers/W1/Tests/SCM/SCMInvtPickInvoiceDiscount.Codeunit.al
new file mode 100644
index 00000000..074f12b1
--- /dev/null
+++ b/App/Layers/W1/Tests/SCM/SCMInvtPickInvoiceDiscount.Codeunit.al
@@ -0,0 +1,190 @@
+codeunit 137164 "SCM Invt. Pick Invoice Discount"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Warehouse] [Inventory Pick] [Invoice Discount] [Currency]
+        isInitialized := false;
+    end;
+
+    var
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryWarehouse: Codeunit "Library - Warehouse";
+        LibraryERM: Codeunit "Library - ERM";
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        Assert: Codeunit Assert;
+        isInitialized: Boolean;
+        InvPickCreatedMsg: Label 'Number of Invt. Pick activities created';
+
+    [Test]
+    [HandlerFunctions('MessageHandler')]
+    [Scope('OnPrem')]
+    procedure InvDiscountPreservedWhenPostingInvtPickWithDifferentPostingDate()
+    var
+        Item: Record Item;
+        Location: Record Location;
+        Bin: Record Bin;
+        Customer: Record Customer;
+        Currency: Record Currency;
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        WarehouseActivityHeader: Record "Warehouse Activity Header";
+        WarehouseActivityLine: Record "Warehouse Activity Line";
+        WarehouseEmployee: Record "Warehouse Employee";
+        Quantity: Decimal;
+        UnitPrice: Decimal;
+        OriginalInvDiscountAmount: Decimal;
+        InitialPostingDate: Date;
+        FuturePostingDate: Date;
+    begin
+        // [FEATURE] [Invoice Discount] [Currency] [Inventory Pick]
+        // [SCENARIO] Invoice Discount should be preserved when posting inventory pick with different posting date that causes currency factor update
+
+        // [GIVEN] Initialize test data
+        Initialize();
+        Quantity := LibraryRandom.RandIntInRange(5, 10);
+        UnitPrice := LibraryRandom.RandDecInRange(100, 1000, 2);
+        InitialPostingDate := WorkDate();
+        FuturePostingDate := CalcDate('<+2W>', WorkDate());
+
+        // [GIVEN] Create currency with different exchange rates for initial date and future date
+        CreateCurrencyWithTwoExchangeRates(Currency, InitialPostingDate, FuturePostingDate);
+
+        // [GIVEN] Create location with Require Pick and Bin Mandatory
+        LibraryWarehouse.CreateLocationWMS(Location, true, false, true, false, false);
+        LibraryWarehouse.CreateBin(Bin, Location.Code, 'BIN-01', '', '');
+        Location.Validate("Default Bin Code", Bin.Code);
+        Location.Modify(true);
+
+        // [GIVEN] Create warehouse employee for the location
+        LibraryWarehouse.CreateWarehouseEmployee(WarehouseEmployee, Location.Code, false);
+
+        // [GIVEN] Create item and post positive adjustment to the location/bin
+        LibraryInventory.CreateItem(Item);
+        CreateAndPostItemJournalLine(Item."No.", Location.Code, Bin.Code, Quantity * 2);
+
+        // [GIVEN] Create customer with currency code
+        LibrarySales.CreateCustomer(Customer);
+        Customer.Validate("Currency Code", Currency.Code);
+        Customer.Modify(true);
+
+        // [GIVEN] Create sales order with currency and item
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Order, Customer."No.");
+        SalesHeader.Validate("Posting Date", InitialPostingDate);
+        SalesHeader.Modify(true);
+
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, Item."No.", Quantity);
+        SalesLine.Validate("Location Code", Location.Code);
+        SalesLine.Validate("Bin Code", Bin.Code);
+        SalesLine.Validate("Unit Price", UnitPrice);
+        SalesLine.Modify(true);
+
+        // [GIVEN] Set invoice discount amount on sales line
+        OriginalInvDiscountAmount := Round(SalesLine."Line Amount" * 0.1); // 10% discount
+        SalesLine.Validate("Inv. Discount Amount", OriginalInvDiscountAmount);
+        SalesLine.Modify(true);
+
+        // [GIVEN] Release sales order
+        LibrarySales.ReleaseSalesDocument(SalesHeader);
+
+        // [GIVEN] Create inventory pick from sales order
+        LibraryWarehouse.CreateInvtPutPickSalesOrder(SalesHeader);
+
+        // [GIVEN] Find the created inventory pick and set quantity to handle
+        FindWarehouseActivityLine(WarehouseActivityLine, WarehouseActivityLine."Source Document"::"Sales Order", SalesHeader."No.", WarehouseActivityLine."Activity Type"::"Invt. Pick");
+        WarehouseActivityHeader.Get(WarehouseActivityLine."Activity Type", WarehouseActivityLine."No.");
+        LibraryWarehouse.AutoFillQtyInventoryActivity(WarehouseActivityHeader);
+
+        // [GIVEN] Change posting date on inventory pick to future date (which has different exchange rate)
+        WarehouseActivityHeader.Validate("Posting Date", FuturePostingDate);
+        WarehouseActivityHeader.Modify(true);
+
+        // [WHEN] Post inventory pick as ship
+        LibraryWarehouse.PostInventoryActivity(WarehouseActivityHeader, false);
+
+        // [THEN] Sales line invoice discount amount should be preserved
+        SalesLine.Get(SalesLine."Document Type", SalesLine."Document No.", SalesLine."Line No.");
+        Assert.AreEqual(
+            OriginalInvDiscountAmount,
+            SalesLine."Inv. Discount Amount",
+            'Invoice Discount Amount should be preserved after posting inventory pick with different posting date');
+
+        // [THEN] Sales header posting date should be updated to match inventory pick posting date
+        SalesHeader.Get(SalesHeader."Document Type", SalesHeader."No.");
+        Assert.AreEqual(
+            FuturePostingDate,
+            SalesHeader."Posting Date",
+            'Sales Header Posting Date should be updated to inventory pick posting date');
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(CODEUNIT::"SCM Invt. Pick Invoice Discount");
+
+        if isInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(CODEUNIT::"SCM Invt. Pick Invoice Discount");
+
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        LibraryERMCountryData.UpdateSalesReceivablesSetup();
+
+        isInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(CODEUNIT::"SCM Invt. Pick Invoice Discount");
+    end;
+
+    local procedure CreateCurrencyWithTwoExchangeRates(var Currency: Record Currency; Date1: Date; Date2: Date)
+    var
+        ExchangeRate1: Decimal;
+        ExchangeRate2: Decimal;
+    begin
+        LibraryERM.CreateCurrency(Currency);
+
+        // Create different exchange rates for two dates to trigger currency factor update
+        ExchangeRate1 := LibraryRandom.RandDecInRange(1, 2, 2);
+        ExchangeRate2 := LibraryRandom.RandDecInRange(2, 3, 2);
+
+        LibraryERM.CreateExchangeRate(Currency.Code, Date1, ExchangeRate1, ExchangeRate1);
+        LibraryERM.CreateExchangeRate(Currency.Code, Date2, ExchangeRate2, ExchangeRate2);
+    end;
+
+    local procedure CreateAndPostItemJournalLine(ItemNo: Code[20]; LocationCode: Code[10]; BinCode: Code[20]; Quantity: Decimal)
+    var
+        ItemJournalLine: Record "Item Journal Line";
+        ItemJournalTemplate: Record "Item Journal Template";
+        ItemJournalBatch: Record "Item Journal Batch";
+    begin
+        LibraryInventory.SelectItemJournalTemplateName(ItemJournalTemplate, ItemJournalTemplate.Type::Item);
+        LibraryInventory.SelectItemJournalBatchName(ItemJournalBatch, ItemJournalTemplate.Type::Item, ItemJournalTemplate.Name);
+
+        LibraryInventory.CreateItemJournalLine(
+            ItemJournalLine, ItemJournalTemplate.Name, ItemJournalBatch.Name,
+            ItemJournalLine."Entry Type"::"Positive Adjmt.", ItemNo, Quantity);
+        ItemJournalLine.Validate("Location Code", LocationCode);
+        ItemJournalLine.Validate("Bin Code", BinCode);
+        ItemJournalLine.Modify(true);
+
+        LibraryInventory.PostItemJournalLine(ItemJournalTemplate.Name, ItemJournalBatch.Name);
+    end;
+
+    local procedure FindWarehouseActivityLine(var WarehouseActivityLine: Record "Warehouse Activity Line"; SourceDocument: Enum "Warehouse Activity Source Document"; SourceNo: Code[20]; ActivityType: Enum "Warehouse Activity Type")
+    begin
+        WarehouseActivityLine.SetRange("Source Document", SourceDocument);
+        WarehouseActivityLine.SetRange("Source No.", SourceNo);
+        WarehouseActivityLine.SetRange("Activity Type", ActivityType);
+        WarehouseActivityLine.FindFirst();
+    end;
+
+    [MessageHandler]
+    procedure MessageHandler(Message: Text[1024])
+    begin
+        // Message handler for inventory pick creation message
+    end;
+}

diff --git a/App/Layers/W1/Tests/ERM/SalesInvoiceItemTrackingTest.Codeunit.al b/App/Layers/W1/Tests/ERM/SalesInvoiceItemTrackingTest.Codeunit.al
new file mode 100644
index 00000000..4ebda660
--- /dev/null
+++ b/App/Layers/W1/Tests/ERM/SalesInvoiceItemTrackingTest.Codeunit.al
@@ -0,0 +1,176 @@
+codeunit 134499 "Sales Invoice Item Tracking Test"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Sales Invoice] [Item Tracking] [Get Shipment Lines]
+        IsInitialized := false;
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryItemTracking: Codeunit "Library - Item Tracking";
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryUtility: Codeunit "Library - Utility";
+        LibraryVariableStorage: Codeunit "Library - Variable Storage";
+        LibraryRandom: Codeunit "Library - Random";
+        IsInitialized: Boolean;
+        TrackingOption: Option AssignSerialNo,AssignLotNo,VerifyLotNo,SelectEntries,AssignLot;
+
+    [Test]
+    [HandlerFunctions('ItemTrackingLinesPageHandler,ItemTrackingSummaryPageHandler')]
+    [Scope('OnPrem')]
+    procedure ItemTrackingPreservedWhenQtyReducedOnSalesInvFromShipment()
+    var
+        Item: Record Item;
+        Customer: Record Customer;
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        SalesHeaderInvoice: Record "Sales Header";
+        SalesLineInvoice: Record "Sales Line";
+        SalesShipmentHeader: Record "Sales Shipment Header";
+        SalesShipmentLine: Record "Sales Shipment Line";
+        ReservationEntry: Record "Reservation Entry";
+        SalesGetShipment: Codeunit "Sales-Get Shipment";
+        ItemTrackingCode: Record "Item Tracking Code";
+        LotNo: Code[50];
+        OriginalQty: Decimal;
+        ReducedQty: Decimal;
+    begin
+        // [FEATURE] [Item Tracking] [Get Shipment Lines]
+        // [SCENARIO] When the quantity in a Sales Invoice is changed after using 'Get Shipment Lines' 
+        // and an item with item tracking lines and reserve always, the tracking information should be preserved.
+        Initialize();
+
+        // [GIVEN] Item with Lot Tracking and Reserve = Always, Costing Method = FIFO
+        OriginalQty := 3;
+        ReducedQty := 2;
+        LotNo := LibraryUtility.GenerateGUID();
+        CreateItemWithLotTrackingAndReserveAlways(Item, ItemTrackingCode);
+
+        // [GIVEN] Post positive adjustment to inventory with lot tracking
+        PostPositiveAdjustmentWithLotNo(Item."No.", LotNo, OriginalQty);
+
+        // [GIVEN] Create Sales Order with the item, assign item tracking
+        LibrarySales.CreateCustomer(Customer);
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Order, Customer."No.");
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, Item."No.", OriginalQty);
+
+        // Enqueue values for ItemTrackingLinesPageHandler (Select Entries mode)
+        LibraryVariableStorage.Enqueue(TrackingOption::SelectEntries);
+        SalesLine.OpenItemTrackingLines();
+
+        // [GIVEN] Post shipment only (Ship)
+        SalesShipmentHeader.Get(LibrarySales.PostSalesDocument(SalesHeader, true, false));
+
+        // [GIVEN] Create Sales Invoice using "Get Shipment Lines"
+        SalesShipmentLine.SetRange("Document No.", SalesShipmentHeader."No.");
+        SalesShipmentLine.FindFirst();
+        LibrarySales.CreateSalesHeader(SalesHeaderInvoice, SalesHeaderInvoice."Document Type"::Invoice, Customer."No.");
+        SalesGetShipment.SetSalesHeader(SalesHeaderInvoice);
+        SalesGetShipment.CreateInvLines(SalesShipmentLine);
+
+        // [GIVEN] Verify item tracking lines exist on the invoice line before modification
+        SalesLineInvoice.SetRange("Document Type", SalesHeaderInvoice."Document Type");
+        SalesLineInvoice.SetRange("Document No.", SalesHeaderInvoice."No.");
+        SalesLineInvoice.SetRange(Type, SalesLineInvoice.Type::Item);
+        SalesLineInvoice.FindFirst();
+
+        ReservationEntry.SetSourceFilter(
+            Database::"Sales Line", SalesLineInvoice."Document Type".AsInteger(),
+            SalesLineInvoice."Document No.", SalesLineInvoice."Line No.", false);
+        Assert.RecordIsNotEmpty(ReservationEntry);
+
+        // [WHEN] Reduce the quantity on the sales invoice line from 3 to 2
+        SalesLineInvoice.Validate(Quantity, ReducedQty);
+        SalesLineInvoice.Modify(true);
+
+        // [THEN] Item tracking lines should still exist (not be deleted)
+        ReservationEntry.Reset();
+        ReservationEntry.SetSourceFilter(
+            Database::"Sales Line", SalesLineInvoice."Document Type".AsInteger(),
+            SalesLineInvoice."Document No.", SalesLineInvoice."Line No.", false);
+        Assert.RecordIsNotEmpty(ReservationEntry);
+
+        // [THEN] The sales invoice can be posted successfully
+        LibrarySales.PostSalesDocument(SalesHeaderInvoice, true, true);
+
+        LibraryVariableStorage.AssertEmpty();
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"Sales Invoice Item Tracking Test");
+        LibraryVariableStorage.Clear();
+
+        if IsInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"Sales Invoice Item Tracking Test");
+
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        LibraryERMCountryData.UpdateSalesReceivablesSetup();
+
+        IsInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"Sales Invoice Item Tracking Test");
+    end;
+
+    local procedure CreateItemWithLotTrackingAndReserveAlways(var Item: Record Item; var ItemTrackingCode: Record "Item Tracking Code")
+    begin
+        // Create Item Tracking Code with Lot Specific Tracking
+        LibraryItemTracking.CreateItemTrackingCode(ItemTrackingCode, false, true);
+        ItemTrackingCode.Validate("Lot Specific Tracking", true);
+        ItemTrackingCode.Modify(true);
+
+        // Create Item with the tracking code and Reserve = Always
+        LibraryInventory.CreateItem(Item);
+        Item.Validate("Item Tracking Code", ItemTrackingCode.Code);
+        Item.Validate("Lot Nos.", LibraryUtility.GetGlobalNoSeriesCode());
+        Item.Validate(Reserve, Item.Reserve::Always);
+        Item.Validate("Costing Method", Item."Costing Method"::FIFO);
+        Item.Modify(true);
+    end;
+
+    local procedure PostPositiveAdjustmentWithLotNo(ItemNo: Code[20]; LotNo: Code[50]; Quantity: Decimal)
+    var
+        ItemJournalLine: Record "Item Journal Line";
+    begin
+        LibraryInventory.CreateItemJournalLineInItemTemplate(ItemJournalLine, ItemNo, '', '', Quantity);
+        LibraryVariableStorage.Enqueue(TrackingOption::AssignLotNo);
+        LibraryVariableStorage.Enqueue(LotNo);
+        LibraryVariableStorage.Enqueue(Quantity);
+        ItemJournalLine.OpenItemTrackingLines(false);
+        LibraryInventory.PostItemJournalLine(ItemJournalLine."Journal Template Name", ItemJournalLine."Journal Batch Name");
+    end;
+
+    [ModalPageHandler]
+    procedure ItemTrackingLinesPageHandler(var ItemTrackingLines: TestPage "Item Tracking Lines")
+    var
+        TrackingOptionValue: Option;
+    begin
+        TrackingOptionValue := LibraryVariableStorage.DequeueInteger();
+        case TrackingOptionValue of
+            TrackingOption::AssignLotNo:
+                begin
+                    ItemTrackingLines."Lot No.".SetValue(LibraryVariableStorage.DequeueText());
+                    ItemTrackingLines."Quantity (Base)".SetValue(LibraryVariableStorage.DequeueDecimal());
+                end;
+            TrackingOption::SelectEntries:
+                ItemTrackingLines."Select Entries".Invoke();
+        end;
+        ItemTrackingLines.OK().Invoke();
+    end;
+
+    [ModalPageHandler]
+    procedure ItemTrackingSummaryPageHandler(var ItemTrackingSummary: TestPage "Item Tracking Summary")
+    begin
+        ItemTrackingSummary.OK().Invoke();
+    end;
+}

diff --git a/App/Layers/W1/Tests/ERM/IssuedReminderEmailTests.Codeunit.al b/App/Layers/W1/Tests/ERM/IssuedReminderEmailTests.Codeunit.al
new file mode 100644
index 00000000..5d8106c2
--- /dev/null
+++ b/App/Layers/W1/Tests/ERM/IssuedReminderEmailTests.Codeunit.al
@@ -0,0 +1,207 @@
+codeunit 134906 "Issued Reminder Email Tests"
+{
+    // [FEATURE] [Issued Reminder] [Email]
+    // Tests for verifying that issued reminder emails are properly logged in customer sent email history.
+
+    EventSubscriberInstance = Manual;
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryERM: Codeunit "Library - ERM";
+        LibraryUtility: Codeunit "Library - Utility";
+        IsInitialized: Boolean;
+        CapturedSourceTableIDs: List of [Integer];
+        CapturedSourceIDs: List of [Guid];
+        EventSubscribed: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure IssuedReminderEmailLogsCustomerAsRelatedSource()
+    var
+        Customer: Record Customer;
+        IssuedReminderHeader: Record "Issued Reminder Header";
+        IssuedReminderEmailTests: Codeunit "Issued Reminder Email Tests";
+        CustomerFound: Boolean;
+        i: Integer;
+    begin
+        // [SCENARIO] When sending an email for an issued reminder, the customer should be added as a related source
+        // so that the email appears in the customer's sent email history.
+        Initialize();
+
+        // [GIVEN] A customer with reminder terms
+        CreateCustomerWithReminderTerms(Customer);
+
+        // [GIVEN] An issued reminder for the customer
+        CreateIssuedReminder(IssuedReminderHeader, Customer."No.");
+
+        // [WHEN] The email sending code path is invoked for the issued reminder
+        IssuedReminderEmailTests.SetEventSubscribed(true);
+        BindSubscription(IssuedReminderEmailTests);
+        InvokeEmailSendingCodePath(IssuedReminderHeader);
+        IssuedReminderEmailTests.GetCapturedSourceTables(CapturedSourceTableIDs, CapturedSourceIDs);
+        UnbindSubscription(IssuedReminderEmailTests);
+
+        // [THEN] The Customer table should be in the source tables list (for the related source - customer receiving the document)
+        CustomerFound := false;
+        for i := 1 to CapturedSourceTableIDs.Count do
+            if CapturedSourceTableIDs.Get(i) = Database::Customer then begin
+                CustomerFound := true;
+                break;
+            end;
+
+        Assert.IsTrue(CustomerFound, 'Customer table should be added as a related source when sending an issued reminder email. ' +
+            'Without this, the email will not appear in the customer''s sent email history.');
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure IssuedReminderEmailLogsCorrectCustomerSystemId()
+    var
+        Customer: Record Customer;
+        IssuedReminderHeader: Record "Issued Reminder Header";
+        IssuedReminderEmailTests: Codeunit "Issued Reminder Email Tests";
+        CustomerSystemId: Guid;
+        CustomerFound: Boolean;
+        i: Integer;
+    begin
+        // [SCENARIO] When sending an email for an issued reminder, the correct customer system ID should be logged
+        // so that the email is associated with the right customer.
+        Initialize();
+
+        // [GIVEN] A customer with reminder terms
+        CreateCustomerWithReminderTerms(Customer);
+        CustomerSystemId := Customer.SystemId;
+
+        // [GIVEN] An issued reminder for the customer
+        CreateIssuedReminder(IssuedReminderHeader, Customer."No.");
+
+        // [WHEN] The email sending code path is invoked for the issued reminder
+        IssuedReminderEmailTests.SetEventSubscribed(true);
+        BindSubscription(IssuedReminderEmailTests);
+        InvokeEmailSendingCodePath(IssuedReminderHeader);
+        IssuedReminderEmailTests.GetCapturedSourceTables(CapturedSourceTableIDs, CapturedSourceIDs);
+        UnbindSubscription(IssuedReminderEmailTests);
+
+        // [THEN] The Customer's SystemId should be in the source IDs list
+        CustomerFound := false;
+        for i := 1 to CapturedSourceTableIDs.Count do
+            if CapturedSourceTableIDs.Get(i) = Database::Customer then
+                if CapturedSourceIDs.Get(i) = CustomerSystemId then begin
+                    CustomerFound := true;
+                    break;
+                end;
+
+        Assert.IsTrue(CustomerFound, 'The correct customer SystemId should be logged when sending an issued reminder email. ' +
+            'The Issued Reminder Header uses "Customer No." field, not "Sell-to Customer No."');
+    end;
+
+    local procedure Initialize()
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"Issued Reminder Email Tests");
+
+        if IsInitialized then
+            exit;
+
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"Issued Reminder Email Tests");
+
+        IsInitialized := true;
+        Commit();
+
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"Issued Reminder Email Tests");
+    end;
+
+    local procedure CreateCustomerWithReminderTerms(var Customer: Record Customer)
+    var
+        ReminderTerms: Record "Reminder Terms";
+    begin
+        LibrarySales.CreateCustomer(Customer);
+        LibraryERM.CreateReminderTerms(ReminderTerms);
+        Customer.Validate("Reminder Terms Code", ReminderTerms.Code);
+        Customer.Modify(true);
+    end;
+
+    local procedure CreateIssuedReminder(var IssuedReminderHeader: Record "Issued Reminder Header"; CustomerNo: Code[20])
+    var
+        Customer: Record Customer;
+    begin
+        Customer.Get(CustomerNo);
+
+        IssuedReminderHeader.Init();
+        IssuedReminderHeader."No." := LibraryUtility.GenerateGUID();
+        IssuedReminderHeader.Validate("Customer No.", CustomerNo);
+        IssuedReminderHeader.Name := Customer.Name;
+        IssuedReminderHeader."Document Date" := WorkDate();
+        IssuedReminderHeader."Posting Date" := WorkDate();
+        IssuedReminderHeader."Due Date" := CalcDate('<1M>', WorkDate());
+        IssuedReminderHeader.Insert(true);
+    end;
+
+    local procedure InvokeEmailSendingCodePath(IssuedReminderHeader: Record "Issued Reminder Header")
+    var
+        ReportSelections: Record "Report Selections";
+    begin
+        // Set up basic report selection for reminders if not exists
+        SetupReminderReportSelection();
+
+        // Use SendEmailInForeground which is a public procedure that eventually calls SendEmailDirectly
+        // This triggers the code path where the source tables are populated
+        // SourceIsCustomer = true because reminders are customer documents
+        ReportSelections.SendEmailInForeground(
+            IssuedReminderHeader.RecordId,
+            IssuedReminderHeader."No.",
+            'Reminder',
+            "Report Selection Usage"::Reminder.AsInteger(),
+            true,  // SourceIsCustomer
+            IssuedReminderHeader."Customer No.");
+    end;
+
+    local procedure SetupReminderReportSelection()
+    var
+        ReportSelections: Record "Report Selections";
+    begin
+        if not ReportSelections.Get(ReportSelections.Usage::Reminder, '1') then begin
+            ReportSelections.Init();
+            ReportSelections.Usage := ReportSelections.Usage::Reminder;
+            ReportSelections.Sequence := '1';
+            ReportSelections."Report ID" := Report::Reminder;
+            ReportSelections."Use for Email Attachment" := true;
+            if ReportSelections.Insert() then;
+        end;
+    end;
+
+    procedure SetEventSubscribed(Value: Boolean)
+    begin
+        EventSubscribed := Value;
+        Clear(CapturedSourceTableIDs);
+        Clear(CapturedSourceIDs);
+    end;
+
+    procedure GetCapturedSourceTables(var OutSourceTableIDs: List of [Integer]; var OutSourceIDs: List of [Guid])
+    begin
+        OutSourceTableIDs := CapturedSourceTableIDs;
+        OutSourceIDs := CapturedSourceIDs;
+    end;
+
+    [EventSubscriber(ObjectType::Table, Database::"Report Selections", 'OnSendEmailDirectlyOnBeforeSend', '', false, false)]
+    local procedure OnSendEmailDirectlyOnBeforeSendSubscriber(var ReportSelections: Record "Report Selections"; ReportUsage: Enum "Report Selection Usage"; RecordVariant: Variant; var DocNo: Code[20]; var DocName: Text[150]; FoundBody: Boolean; FoundAttachment: Boolean; var EmailBody: Codeunit "Temp Blob"; var DefaultEmailAddress: Text[250]; ShowDialog: Boolean; var TempAttachReportSelections: Record "Report Selections" temporary; var CustomReportSelection: Record "Custom Report Selection"; var AllEmailsWereSuccessful: Boolean; var IsHandled: Boolean; var SourceTableIDs: List of [Integer]; var SourceIDs: List of [Guid]; var SourceRelationTypes: List of [Integer])
+    begin
+        if not EventSubscribed then
+            exit;
+
+        // Capture the source tables for verification
+        CapturedSourceTableIDs := SourceTableIDs;
+        CapturedSourceIDs := SourceIDs;
+
+        // Prevent actual email sending
+        IsHandled := true;
+        AllEmailsWereSuccessful := true;
+    end;
+}

diff --git a/App/Layers/W1/Tests/Job/InvPickATOOnJobPlanning.Codeunit.al b/App/Layers/W1/Tests/Job/InvPickATOOnJobPlanning.Codeunit.al
