+++ b/App/Layers/W1/Tests/Job/InvPickATOOnJobPlanning.Codeunit.al
@@ -0,0 +1,310 @@
+codeunit 136323 "Inv. Pick ATO On Job Planning"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Job] [Inventory Pick] [Assembly-to-Order]
+        IsInitialized := false;
+    end;
+
+    var
+        LocationWithBinMandatoryInvtPick: Record Location;
+        Bin1: Record Bin;
+        Bin2: Record Bin;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryJob: Codeunit "Library - Job";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryUtility: Codeunit "Library - Utility";
+        LibraryWarehouse: Codeunit "Library - Warehouse";
+        LibraryRandom: Codeunit "Library - Random";
+        LibrarySetupStorage: Codeunit "Library - Setup Storage";
+        LibraryERM: Codeunit "Library - ERM";
+        Assert: Codeunit Assert;
+        IsInitialized: Boolean;
+
+    [Test]
+    [HandlerFunctions('MessageHandler')]
+    [Scope('OnPrem')]
+    procedure CreateInvtPickForJobPlanningLineWithAssembleToOrder()
+    var
+        ParentItem: Record Item;
+        CompItem1: Record Item;
+        CompItem2: Record Item;
+        Job: Record Job;
+        JobTask: Record "Job Task";
+        JobPlanningLine: Record "Job Planning Line";
+        AssemblyHeader: Record "Assembly Header";
+        WarehouseActivityLine: Record "Warehouse Activity Line";
+        ATOLink: Record "Assemble-to-Order Link";
+        Qty: Integer;
+    begin
+        // [FEATURE] [WMS] Support Inventory Pick for Job Planning Lines with Assembly-to-Order
+        // [SCENARIO] Create Inventory Pick for Job Planning Line with Qty. to Assemble should create pick lines for assembly components
+
+        // [GIVEN] An assembly item with 2 components
+        Initialize();
+        CreateAssemblyItemWithBOM(ParentItem, CompItem1, CompItem2);
+
+        // [GIVEN] Component items have enough inventory on location with 'Bin Mandatory' = Yes and 'Job Consump. Whse. Handling' = 'Inventory Pick'
+        Qty := LibraryRandom.RandIntInRange(5, 10);
+        CreateAndPostInvtAdjustmentWithUnitCost(CompItem1."No.", LocationWithBinMandatoryInvtPick.Code, Bin1.Code, Qty * 10, LibraryRandom.RandDec(10, 2));
+        CreateAndPostInvtAdjustmentWithUnitCost(CompItem2."No.", LocationWithBinMandatoryInvtPick.Code, Bin1.Code, Qty * 10, LibraryRandom.RandDec(10, 2));
+
+        // [GIVEN] A job with a planning line for the assembly item with Qty. to Assemble set
+        CreateJobWithJobTask(JobTask);
+        Job.Get(JobTask."Job No.");
+
+        CreateJobPlanningLineWithAssemblyItem(JobPlanningLine, JobTask, ParentItem."No.", LocationWithBinMandatoryInvtPick.Code, Bin2.Code, Qty);
+
+        // [GIVEN] Assembly order is created
+        ATOLink.SetRange(Type, ATOLink.Type::Job);
+        ATOLink.SetRange("Job No.", JobTask."Job No.");
+        ATOLink.SetRange("Job Task No.", JobTask."Job Task No.");
+        ATOLink.SetRange("Document Line No.", JobPlanningLine."Line No.");
+        Assert.RecordIsNotEmpty(ATOLink);
+
+        JobPlanningLine.AsmToOrderExists(AssemblyHeader);
+        Assert.AreNotEqual('', AssemblyHeader."No.", 'Assembly order should be created');
+
+        Commit();
+
+        // [WHEN] Create Inventory Pick is run for the Job
+        LibraryWarehouse.CreateInvtPutPickMovement("Warehouse Request Source Document"::"Job Usage", Job."No.", false, true, false);
+
+        // [THEN] Warehouse activity lines are created for the assembly components (ATO pick lines)
+        WarehouseActivityLine.SetRange("Activity Type", WarehouseActivityLine."Activity Type"::"Invt. Pick");
+        WarehouseActivityLine.SetRange("Source No.", Job."No.");
+        WarehouseActivityLine.SetRange("Assemble to Order", true);
+        Assert.RecordIsNotEmpty(WarehouseActivityLine);
+
+        // [THEN] The pick lines contain the component items
+        WarehouseActivityLine.SetRange("Item No.", CompItem1."No.");
+        Assert.RecordIsNotEmpty(WarehouseActivityLine);
+
+        WarehouseActivityLine.SetRange("Item No.", CompItem2."No.");
+        Assert.RecordIsNotEmpty(WarehouseActivityLine);
+    end;
+
+    [Test]
+    [HandlerFunctions('MessageHandler')]
+    [Scope('OnPrem')]
+    procedure CreateInvtPickForJobATOWithAlwaysCreatePickLines()
+    var
+        ParentItem: Record Item;
+        CompItem1: Record Item;
+        CompItem2: Record Item;
+        Job: Record Job;
+        JobTask: Record "Job Task";
+        JobPlanningLine: Record "Job Planning Line";
+        AssemblyHeader: Record "Assembly Header";
+        WarehouseActivityLine: Record "Warehouse Activity Line";
+        ATOLink: Record "Assemble-to-Order Link";
+        Qty: Integer;
+    begin
+        // [FEATURE] [WMS] Support Inventory Pick for Job Planning Lines with Assembly-to-Order
+        // [SCENARIO] Create Inventory Pick for Job Planning Line with Qty. to Assemble when "Always Create Pick Lines" is enabled
+        // This scenario specifically tests the fix for the bin lookup error when creating ATO picks
+
+        // [GIVEN] An assembly item with 2 components
+        Initialize();
+        CreateAssemblyItemWithBOM(ParentItem, CompItem1, CompItem2);
+
+        // [GIVEN] Location has "Always Create Pick Line" = Yes
+        LocationWithBinMandatoryInvtPick."Always Create Pick Line" := true;
+        LocationWithBinMandatoryInvtPick.Modify();
+
+        // [GIVEN] Component items have enough inventory on location with 'Bin Mandatory' = Yes
+        Qty := LibraryRandom.RandIntInRange(5, 10);
+        CreateAndPostInvtAdjustmentWithUnitCost(CompItem1."No.", LocationWithBinMandatoryInvtPick.Code, Bin1.Code, Qty * 10, LibraryRandom.RandDec(10, 2));
+        CreateAndPostInvtAdjustmentWithUnitCost(CompItem2."No.", LocationWithBinMandatoryInvtPick.Code, Bin1.Code, Qty * 10, LibraryRandom.RandDec(10, 2));
+
+        // [GIVEN] A job with a planning line for the assembly item with Qty. to Assemble set
+        CreateJobWithJobTask(JobTask);
+        Job.Get(JobTask."Job No.");
+
+        CreateJobPlanningLineWithAssemblyItem(JobPlanningLine, JobTask, ParentItem."No.", LocationWithBinMandatoryInvtPick.Code, Bin2.Code, Qty);
+
+        // [GIVEN] Assembly order is created
+        ATOLink.SetRange(Type, ATOLink.Type::Job);
+        ATOLink.SetRange("Job No.", JobTask."Job No.");
+        ATOLink.SetRange("Job Task No.", JobTask."Job Task No.");
+        ATOLink.SetRange("Document Line No.", JobPlanningLine."Line No.");
+        Assert.RecordIsNotEmpty(ATOLink);
+
+        JobPlanningLine.AsmToOrderExists(AssemblyHeader);
+        Assert.AreNotEqual('', AssemblyHeader."No.", 'Assembly order should be created');
+
+        Commit();
+
+        // [WHEN] Create Inventory Pick is run for the Job
+        // This should NOT throw "The Bin does not exist" error with the fix
+        LibraryWarehouse.CreateInvtPutPickMovement("Warehouse Request Source Document"::"Job Usage", Job."No.", false, true, false);
+
+        // [THEN] Warehouse activity lines are created for the assembly components
+        WarehouseActivityLine.SetRange("Activity Type", WarehouseActivityLine."Activity Type"::"Invt. Pick");
+        WarehouseActivityLine.SetRange("Source No.", Job."No.");
+        WarehouseActivityLine.SetRange("Assemble to Order", true);
+        Assert.RecordIsNotEmpty(WarehouseActivityLine);
+
+        // Cleanup
+        LocationWithBinMandatoryInvtPick."Always Create Pick Line" := false;
+        LocationWithBinMandatoryInvtPick.Modify();
+    end;
+
+    local procedure Initialize()
+    var
+        NoSeries: Record "No. Series";
+        InventorySetup: Record "Inventory Setup";
+        ManufacturingSetup: Record "Manufacturing Setup";
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+        WarehouseEmployee: Record "Warehouse Employee";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"Inv. Pick ATO On Job Planning");
+        LibrarySetupStorage.Restore();
+        LibraryJob.DeleteJobJournalTemplate();
+
+        if not IsInitialized then begin
+            LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"Inv. Pick ATO On Job Planning");
+
+            // Create location with Bin Mandatory and Job Consump. Whse. Handling = Inventory Pick
+            LibraryWarehouse.CreateLocationWMS(LocationWithBinMandatoryInvtPick, true, false, true, false, false);
+            LocationWithBinMandatoryInvtPick.Validate("Job Consump. Whse. Handling", LocationWithBinMandatoryInvtPick."Job Consump. Whse. Handling"::"Inventory Pick");
+            LocationWithBinMandatoryInvtPick.Modify(true);
+
+            LibraryWarehouse.CreateBin(Bin1, LocationWithBinMandatoryInvtPick.Code, LibraryUtility.GenerateRandomCode(Bin1.FieldNo(Code), Database::Bin), '', '');
+            LibraryWarehouse.CreateBin(Bin2, LocationWithBinMandatoryInvtPick.Code, LibraryUtility.GenerateRandomCode(Bin2.FieldNo(Code), Database::Bin), '', '');
+
+            // Setup no series
+            LibraryInventory.NoSeriesSetup(InventorySetup);
+            if InventorySetup."Inventory Pick Nos." = '' then
+                InventorySetup."Inventory Pick Nos." := LibraryUtility.GetGlobalNoSeriesCode();
+            if InventorySetup."Posted Invt. Pick Nos." = '' then
+                InventorySetup."Posted Invt. Pick Nos." := LibraryUtility.GetGlobalNoSeriesCode();
+            InventorySetup.Modify(true);
+
+            // Setup manufacturing
+            ManufacturingSetup.Get();
+            Evaluate(ManufacturingSetup."Default Safety Lead Time", '<0D>');
+            ManufacturingSetup.Modify(true);
+
+            LibraryERMCountryData.CreateVATData();
+            LibraryERMCountryData.CreateGeneralPostingSetupData();
+            LibraryERMCountryData.UpdateGeneralPostingSetup();
+            LibraryERMCountryData.UpdatePurchasesPayablesSetup();
+
+            NoSeries.Get(LibraryJob.GetJobTestNoSeries());
+            NoSeries."Manual Nos." := true;
+            NoSeries.Modify();
+
+            LibrarySetupStorage.Save(Database::"Inventory Setup");
+            LibrarySetupStorage.Save(Database::"Purchases & Payables Setup");
+
+            IsInitialized := true;
+            Commit();
+            LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"Inv. Pick ATO On Job Planning");
+        end;
+
+        CreateDefaultWarehouseEmployee(LocationWithBinMandatoryInvtPick);
+    end;
+
+    local procedure CreateDefaultWarehouseEmployee(var NewDefaultLocation: Record Location)
+    var
+        WarehouseEmployee: Record "Warehouse Employee";
+    begin
+        WarehouseEmployee.SetRange(Default, true);
+        if WarehouseEmployee.FindFirst() then begin
+            if WarehouseEmployee."Location Code" <> NewDefaultLocation.Code then begin
+                WarehouseEmployee.Delete(true);
+                LibraryWarehouse.CreateWarehouseEmployee(WarehouseEmployee, NewDefaultLocation.Code, true);
+            end;
+        end
+        else
+            LibraryWarehouse.CreateWarehouseEmployee(WarehouseEmployee, NewDefaultLocation.Code, true);
+    end;
+
+    local procedure CreateJobWithJobTask(var JobTask: Record "Job Task")
+    var
+        Job: Record Job;
+    begin
+        LibraryJob.CreateJob(Job, CreateCustomer(''));
+        Job.Validate("Apply Usage Link", true);
+        Job.Modify(true);
+        LibraryJob.CreateJobTask(Job, JobTask);
+    end;
+
+    local procedure CreateCustomer(CurrencyCode: Code[10]): Code[20]
+    var
+        Customer: Record Customer;
+    begin
+        LibrarySales.CreateCustomer(Customer);
+        Customer.Validate("Currency Code", CurrencyCode);
+        Customer.Modify(true);
+        exit(Customer."No.");
+    end;
+
+    local procedure CreateAssemblyItemWithBOM(var AssemblyItem: Record Item; var BomComponentItem1: Record Item; var BomComponentItem2: Record Item)
+    begin
+        LibraryInventory.CreateItem(AssemblyItem);
+        AssemblyItem.Validate("Replenishment System", AssemblyItem."Replenishment System"::Assembly);
+        AssemblyItem.Validate("Assembly Policy", Enum::"Assembly Policy"::"Assemble-to-Order");
+        AssemblyItem.Modify(true);
+
+        // Create Component Item and set as Assembly BOM
+        CreateAssemblyBomComponent(BomComponentItem1, AssemblyItem."No.");
+        CreateAssemblyBomComponent(BomComponentItem2, AssemblyItem."No.");
+        Commit();
+    end;
+
+    local procedure CreateAssemblyBomComponent(var Item: Record Item; ParentItemNo: Code[20])
+    var
+        BomComponent: Record "BOM Component";
+        BomRecordRef: RecordRef;
+    begin
+        LibraryInventory.CreateItem(Item);
+        Item.Validate("Unit Cost", LibraryRandom.RandDec(10, 2));
+        Item.Modify(true);
+
+        BomComponent.Init();
+        BomComponent.Validate(BomComponent."Parent Item No.", ParentItemNo);
+        BomRecordRef.GetTable(BomComponent);
+        BomComponent.Validate(BomComponent."Line No.", LibraryUtility.GetNewLineNo(BomRecordRef, BomComponent.FieldNo(BomComponent."Line No.")));
+        BomComponent.Validate(BomComponent.Type, BomComponent.Type::Item);
+        BomComponent.Validate(BomComponent."No.", Item."No.");
+        BomComponent.Validate(BomComponent."Quantity per", LibraryRandom.RandInt(3));
+        BomComponent.Insert(true);
+    end;
+
+    local procedure CreateJobPlanningLineWithAssemblyItem(var JobPlanningLine: Record "Job Planning Line"; JobTask: Record "Job Task"; AssemblyItemNo: Code[20]; LocationCode: Code[10]; BinCode: Code[20]; Quantity: Decimal)
+    begin
+        LibraryJob.CreateJobPlanningLine("Job Planning Line Line Type"::Budget, JobPlanningLine.Type::Item, JobTask, JobPlanningLine);
+        JobPlanningLine.Validate("No.", AssemblyItemNo);
+        JobPlanningLine.Validate("Location Code", LocationCode);
+        if BinCode <> '' then
+            JobPlanningLine.Validate("Bin Code", BinCode);
+        JobPlanningLine.Validate(Quantity, Quantity);
+        // Setting quantity also sets Qty. to Assemble for ATO items
+        JobPlanningLine.Modify(true);
+    end;
+
+    local procedure CreateAndPostInvtAdjustmentWithUnitCost(ItemNo: Code[20]; LocationCode: Code[10]; BinCode: Code[20]; Qty: Decimal; UnitCost: Decimal)
+    var
+        ItemJournalLine: Record "Item Journal Line";
+    begin
+        LibraryInventory.CreateItemJournalLineInItemTemplate(ItemJournalLine, ItemNo, '', '', Qty);
+        ItemJournalLine.Validate("Location Code", LocationCode);
+        ItemJournalLine.Validate("Bin Code", BinCode);
+        ItemJournalLine.Validate("Unit Cost", UnitCost);
+        ItemJournalLine.Modify(true);
+        LibraryInventory.PostItemJournalLine(ItemJournalLine."Journal Template Name", ItemJournalLine."Journal Batch Name");
+    end;
+
+    [MessageHandler]
+    [Scope('OnPrem')]
+    procedure MessageHandler(Message: Text[1024])
+    begin
+        // Empty handler to suppress message display
+    end;
+}

diff --git a/App/Layers/W1/Tests/VAT/NonDedVATJobCurrency.Codeunit.al b/App/Layers/W1/Tests/VAT/NonDedVATJobCurrency.Codeunit.al
new file mode 100644
index 00000000..85ae2069
--- /dev/null
+++ b/App/Layers/W1/Tests/VAT/NonDedVATJobCurrency.Codeunit.al
@@ -0,0 +1,215 @@
+codeunit 134291 "Non-Ded. VAT Job Currency"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Non Deductible VAT] [Project] [Currency]
+    end;
+
+    var
+        LibraryERM: Codeunit "Library - ERM";
+        LibraryJob: Codeunit "Library - Job";
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryNonDeductibleVAT: Codeunit "Library - NonDeductible VAT";
+        LibrarySetupStorage: Codeunit "Library - Setup Storage";
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryRandom: Codeunit "Library - Random";
+        Assert: Codeunit Assert;
+        IsInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure NonDedVATAmountConvertedToJobCurrencyWhenGenJnlLineInLCY()
+    var
+        Job: Record Job;
+        JobTask: Record "Job Task";
+        VATPostingSetup: Record "VAT Posting Setup";
+        GenJournalLine: Record "Gen. Journal Line";
+        JobLedgerEntry: Record "Job Ledger Entry";
+        Customer: Record Customer;
+        JobCurrencyCode: Code[10];
+        JobExchangeRate: Decimal;
+        ExpectedNonDedVATAmountLCY: Decimal;
+        ExpectedUnitCostLCY: Decimal;
+        ExpectedTotalCostLCY: Decimal;
+        CurrencyFactor: Decimal;
+    begin
+        // [SCENARIO] Non-Deductible VAT amount is correctly converted to LCY for Project Ledger Entry
+        // when posting a general journal line in LCY to a project that uses a foreign currency.
+        // Previously, the Non-Deductible VAT amount was added without considering the project currency,
+        // causing incorrect amounts when the project has a different currency than the journal line.
+
+        // [GIVEN] Non-Deductible VAT is enabled and set to use for Job Cost
+        Initialize();
+        LibraryNonDeductibleVAT.SetUseForJobCost();
+
+        // [GIVEN] VAT Posting Setup with "VAT %" = 20, "Non-Deductible VAT %" = 50
+        LibraryNonDeductibleVAT.CreateNonDeductibleNormalVATPostingSetup(VATPostingSetup);
+
+        // [GIVEN] Job Currency code (EUR) with exchange rate = 10 (meaning 1 LCY = 0.1 EUR or 1 EUR = 10 LCY)
+        JobExchangeRate := 10;
+        JobCurrencyCode := LibraryERM.CreateCurrencyWithExchangeRate(WorkDate(), JobExchangeRate, JobExchangeRate);
+
+        // [GIVEN] Job with Currency Code = EUR
+        LibrarySales.CreateCustomer(Customer);
+        LibraryJob.CreateJob(Job, Customer."No.");
+        Job.Validate("Currency Code", JobCurrencyCode);
+        Job.Modify(true);
+        LibraryJob.CreateJobTask(Job, JobTask);
+
+        // [GIVEN] General journal line in LCY (no currency code) with Non-Deductible VAT, pointing to the Job
+        CreateGenJnlLineWithJobInLCY(GenJournalLine, VATPostingSetup, JobTask);
+
+        // [WHEN] Post the general journal line
+        LibraryERM.PostGeneralJnlLine(GenJournalLine);
+
+        // [THEN] Job Ledger Entry has "Unit Cost (LCY)" that includes the Non-Deductible VAT amount
+        // converted using the currency factor
+        JobLedgerEntry.SetRange("Job No.", Job."No.");
+        JobLedgerEntry.SetRange("Document No.", GenJournalLine."Document No.");
+        JobLedgerEntry.FindFirst();
+
+        // When GenJnlLine is in LCY (Currency Code = '') and Job is in FCY:
+        // CurrencyFactor = GetGenJnlLineToJobCurrencyFactor() returns Job Currency Factor (since GenJnl Currency Factor = 0)
+        // NonDedVATAmountLCY = Non-Deductible VAT Amount * CurrencyFactor
+        CurrencyFactor := GenJournalLine.GetGenJnlLineToJobCurrencyFactor();
+        ExpectedNonDedVATAmountLCY := Round(GenJournalLine."Non-Deductible VAT Amount" * CurrencyFactor);
+        ExpectedUnitCostLCY := Round((GenJournalLine."VAT Base Amount (LCY)" + ExpectedNonDedVATAmountLCY) / GenJournalLine."Job Quantity");
+        ExpectedTotalCostLCY := GenJournalLine."VAT Base Amount (LCY)" + ExpectedNonDedVATAmountLCY;
+
+        Assert.AreEqual(
+            ExpectedUnitCostLCY,
+            JobLedgerEntry."Unit Cost (LCY)",
+            'Unit Cost (LCY) should include correctly converted Non-Deductible VAT amount');
+        Assert.AreEqual(
+            ExpectedTotalCostLCY,
+            JobLedgerEntry."Total Cost (LCY)",
+            'Total Cost (LCY) should include correctly converted Non-Deductible VAT amount');
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure NonDedVATAmountConvertedWhenGenJnlAndJobHaveDifferentFCY()
+    var
+        Job: Record Job;
+        JobTask: Record "Job Task";
+        VATPostingSetup: Record "VAT Posting Setup";
+        GenJournalLine: Record "Gen. Journal Line";
+        JobLedgerEntry: Record "Job Ledger Entry";
+        Customer: Record Customer;
+        GenJnlCurrencyCode: Code[10];
+        JobCurrencyCode: Code[10];
+        GenJnlExchangeRate: Decimal;
+        JobExchangeRate: Decimal;
+        ExpectedNonDedVATAmountLCY: Decimal;
+        ExpectedUnitCostLCY: Decimal;
+        ExpectedTotalCostLCY: Decimal;
+        CurrencyFactor: Decimal;
+    begin
+        // [SCENARIO] Non-Deductible VAT amount is correctly converted to LCY for Project Ledger Entry
+        // when posting a general journal line in one foreign currency (e.g., DKK) to a project that
+        // uses another foreign currency (e.g., EUR).
+
+        // [GIVEN] Non-Deductible VAT is enabled and set to use for Job Cost
+        Initialize();
+        LibraryNonDeductibleVAT.SetUseForJobCost();
+
+        // [GIVEN] VAT Posting Setup with "VAT %" = 20, "Non-Deductible VAT %" = 50
+        LibraryNonDeductibleVAT.CreateNonDeductibleNormalVATPostingSetup(VATPostingSetup);
+
+        // [GIVEN] GenJnl Currency code (DKK) with exchange rate = 5
+        GenJnlExchangeRate := 5;
+        GenJnlCurrencyCode := LibraryERM.CreateCurrencyWithExchangeRate(WorkDate(), GenJnlExchangeRate, GenJnlExchangeRate);
+
+        // [GIVEN] Job Currency code (EUR) with exchange rate = 10
+        JobExchangeRate := 10;
+        JobCurrencyCode := LibraryERM.CreateCurrencyWithExchangeRate(WorkDate(), JobExchangeRate, JobExchangeRate);
+
+        // [GIVEN] Job with Currency Code = EUR
+        LibrarySales.CreateCustomer(Customer);
+        LibraryJob.CreateJob(Job, Customer."No.");
+        Job.Validate("Currency Code", JobCurrencyCode);
+        Job.Modify(true);
+        LibraryJob.CreateJobTask(Job, JobTask);
+
+        // [GIVEN] General journal line in DKK with Non-Deductible VAT, pointing to the Job
+        CreateGenJnlLineWithJobInFCY(GenJournalLine, VATPostingSetup, JobTask, GenJnlCurrencyCode);
+
+        // [WHEN] Post the general journal line
+        LibraryERM.PostGeneralJnlLine(GenJournalLine);
+
+        // [THEN] Job Ledger Entry has "Unit Cost (LCY)" that includes the Non-Deductible VAT amount
+        // correctly converted using the combined currency factor
+        JobLedgerEntry.SetRange("Job No.", Job."No.");
+        JobLedgerEntry.SetRange("Document No.", GenJournalLine."Document No.");
+        JobLedgerEntry.FindFirst();
+
+        // When GenJnlLine is in FCY1 and Job is in FCY2:
+        // CurrencyFactor = Job Currency Factor / GenJnl Currency Factor
+        // NonDedVATAmountLCY = Non-Deductible VAT Amount * CurrencyFactor
+        CurrencyFactor := GenJournalLine.GetGenJnlLineToJobCurrencyFactor();
+        ExpectedNonDedVATAmountLCY := Round(GenJournalLine."Non-Deductible VAT Amount" * CurrencyFactor);
+        ExpectedUnitCostLCY := Round((GenJournalLine."VAT Base Amount (LCY)" + ExpectedNonDedVATAmountLCY) / GenJournalLine."Job Quantity");
+        ExpectedTotalCostLCY := GenJournalLine."VAT Base Amount (LCY)" + ExpectedNonDedVATAmountLCY;
+
+        Assert.AreEqual(
