index 00000000..35c4580b
--- /dev/null
+++ b/App/Layers/W1/Tests/SCM/SCMReqWkshtItemTracking.Codeunit.al
@@ -0,0 +1,293 @@
+codeunit 137068 "SCM Req. Wksht Item Tracking"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Planning] [Requisition Worksheet] [Item Tracking] [SCM]
+        isInitialized := false;
+    end;
+
+    var
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryPlanning: Codeunit "Library - Planning";
+        LibraryUtility: Codeunit "Library - Utility";
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryPurchase: Codeunit "Library - Purchase";
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+        LibraryItemTracking: Codeunit "Library - Item Tracking";
+        LibraryVariableStorage: Codeunit "Library - Variable Storage";
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        isInitialized: Boolean;
+        ItemTrackingMode: Option "Assign Lot No.","Select Entries";
+
+    [Test]
+    [HandlerFunctions('ItemTrackingLinesPageHandler')]
+    [Scope('OnPrem')]
+    procedure ReplanReqWkshWithItemTrackingDoesNotCreateDuplicateSurplusEntries()
+    var
+        Item: Record Item;
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        PurchaseHeader: Record "Purchase Header";
+        PurchaseLine: Record "Purchase Line";
+        ReservationEntry: Record "Reservation Entry";
+        RequisitionWkshName: Record "Requisition Wksh. Name";
+        RequisitionLine: Record "Requisition Line";
+        SalesQty: Decimal;
+        IncreasedQty: Decimal;
+        InitialReservationCount: Integer;
+        InitialSurplusQty: Decimal;
+    begin
+        // [SCENARIO] When recalculating an item in a requisition worksheet with no planning results, 
+        // surplus reservation entries should not be incorrectly added to the reservation table.
+        // The issue was that prospect entries were not changed to surplus after carry out, causing
+        // additional surplus entries when replanning.
+        Initialize();
+
+        // [GIVEN] An Item with Lot-for-Lot reordering policy, Purchase replenishment, and lot tracking
+        SalesQty := LibraryRandom.RandIntInRange(50, 100);
+        IncreasedQty := SalesQty + LibraryRandom.RandIntInRange(30, 50);
+        CreateLotForLotItemWithLotTracking(Item);
+
+        // [GIVEN] A Sales Order for the item
+        CreateSalesOrderWithItem(SalesHeader, SalesLine, Item."No.", SalesQty);
+
+        // [GIVEN] Plan the item in requisition worksheet to meet the demand
+        CalculatePlanForRequisitionWorksheet(RequisitionWkshName, Item, WorkDate(), CalcDate('<+1M>', WorkDate()));
+
+        // [GIVEN] Modify the requisition line: increase quantity, set planning flexibility to None, and assign lot tracking
+        SelectRequisitionLine(RequisitionLine, Item."No.");
+        RequisitionLine.Validate(Quantity, IncreasedQty);
+        RequisitionLine.Validate("Planning Flexibility", RequisitionLine."Planning Flexibility"::None);
+        RequisitionLine.Validate("Vendor No.", LibraryPurchase.CreateVendorNo());
+        RequisitionLine.Modify(true);
+
+        // Assign lot tracking to the requisition line
+        LibraryVariableStorage.Enqueue(ItemTrackingMode::"Assign Lot No.");
+        LibraryVariableStorage.Enqueue(IncreasedQty);
+        RequisitionLine.OpenItemTrackingLines();
+
+        // [GIVEN] Carry out action message to create Purchase Order
+        AcceptAndCarryOutActionMessage(RequisitionLine);
+
+        // [GIVEN] Verify Purchase Order was created with correct quantity
+        FindPurchaseLine(PurchaseLine, Item."No.");
+        PurchaseLine.TestField(Quantity, IncreasedQty);
+        PurchaseHeader.Get(PurchaseHeader."Document Type"::Order, PurchaseLine."Document No.");
+
+        // [GIVEN] Record the initial reservation entry state for the purchase line
+        ReservationEntry.SetRange("Source Type", Database::"Purchase Line");
+        ReservationEntry.SetRange("Source Subtype", PurchaseLine."Document Type");
+        ReservationEntry.SetRange("Source ID", PurchaseLine."Document No.");
+        ReservationEntry.SetRange("Source Ref. No.", PurchaseLine."Line No.");
+        ReservationEntry.SetRange("Item No.", Item."No.");
+        InitialReservationCount := ReservationEntry.Count();
+        ReservationEntry.CalcSums("Quantity (Base)");
+        InitialSurplusQty := ReservationEntry."Quantity (Base)";
+
+        // [WHEN] Recalculate the plan in requisition worksheet (no results expected due to Planning Flexibility = None)
+        Clear(RequisitionWkshName);
+        LibraryPlanning.CalculatePlanForReqWksh(
+            Item, RequisitionWkshName."Worksheet Template Name", RequisitionWkshName.Name, WorkDate(), CalcDate('<+1M>', WorkDate()));
+
+        // [THEN] No additional reservation entries are created for the purchase line
+        ReservationEntry.SetRange("Source Type", Database::"Purchase Line");
+        ReservationEntry.SetRange("Source Subtype", PurchaseLine."Document Type");
+        ReservationEntry.SetRange("Source ID", PurchaseLine."Document No.");
+        ReservationEntry.SetRange("Source Ref. No.", PurchaseLine."Line No.");
+        ReservationEntry.SetRange("Item No.", Item."No.");
+
+        Assert.AreEqual(
+            InitialReservationCount,
+            ReservationEntry.Count(),
+            'Reservation entry count should not change after replanning.');
+
+        ReservationEntry.CalcSums("Quantity (Base)");
+        Assert.AreEqual(
+            InitialSurplusQty,
+            ReservationEntry."Quantity (Base)",
+            'Reservation entry quantity should not change after replanning.');
+
+        // [THEN] All reservation entries for the purchase line should be Surplus (not Prospect)
+        ReservationEntry.SetRange("Reservation Status", ReservationEntry."Reservation Status"::Prospect);
+        Assert.RecordIsEmpty(ReservationEntry);
+    end;
+
+    [Test]
+    [HandlerFunctions('ItemTrackingLinesPageHandler')]
+    [Scope('OnPrem')]
+    procedure CarryOutReqWkshChangesProspectReservationToSurplus()
+    var
+        Item: Record Item;
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        PurchaseLine: Record "Purchase Line";
+        ReservationEntry: Record "Reservation Entry";
+        RequisitionWkshName: Record "Requisition Wksh. Name";
+        RequisitionLine: Record "Requisition Line";
+        SalesQty: Decimal;
+        IncreasedQty: Decimal;
+    begin
+        // [SCENARIO] When carrying out action message from requisition worksheet to purchase order,
+        // the reservation status should be Surplus, not Prospect for the surplus quantity.
+        Initialize();
+
+        // [GIVEN] An Item with Lot-for-Lot reordering policy, Purchase replenishment, and lot tracking
+        SalesQty := LibraryRandom.RandIntInRange(50, 100);
+        IncreasedQty := SalesQty + LibraryRandom.RandIntInRange(30, 50);
+        CreateLotForLotItemWithLotTracking(Item);
+
+        // [GIVEN] A Sales Order for the item
+        CreateSalesOrderWithItem(SalesHeader, SalesLine, Item."No.", SalesQty);
+
+        // [GIVEN] Plan the item in requisition worksheet
+        CalculatePlanForRequisitionWorksheet(RequisitionWkshName, Item, WorkDate(), CalcDate('<+1M>', WorkDate()));
+
+        // [GIVEN] Increase quantity beyond demand and assign lot tracking
+        SelectRequisitionLine(RequisitionLine, Item."No.");
+        RequisitionLine.Validate(Quantity, IncreasedQty);
+        RequisitionLine.Validate("Planning Flexibility", RequisitionLine."Planning Flexibility"::None);
+        RequisitionLine.Validate("Vendor No.", LibraryPurchase.CreateVendorNo());
+        RequisitionLine.Modify(true);
+
+        LibraryVariableStorage.Enqueue(ItemTrackingMode::"Assign Lot No.");
+        LibraryVariableStorage.Enqueue(IncreasedQty);
+        RequisitionLine.OpenItemTrackingLines();
+
+        // [WHEN] Carry out action message
+        AcceptAndCarryOutActionMessage(RequisitionLine);
+
+        // [THEN] Purchase Order is created
+        FindPurchaseLine(PurchaseLine, Item."No.");
+        PurchaseLine.TestField(Quantity, IncreasedQty);
+
+        // [THEN] All reservation entries for the purchase line should be Surplus (not Prospect)
+        ReservationEntry.SetRange("Source Type", Database::"Purchase Line");
+        ReservationEntry.SetRange("Source Subtype", PurchaseLine."Document Type");
+        ReservationEntry.SetRange("Source ID", PurchaseLine."Document No.");
+        ReservationEntry.SetRange("Source Ref. No.", PurchaseLine."Line No.");
+        ReservationEntry.SetRange("Item No.", Item."No.");
+        ReservationEntry.SetRange("Reservation Status", ReservationEntry."Reservation Status"::Prospect);
+
+        Assert.RecordIsEmpty(ReservationEntry);
+    end;
+
+    local procedure Initialize()
+    var
+        ReservationEntry: Record "Reservation Entry";
+        RequisitionLine: Record "Requisition Line";
+        RequisitionWkshName: Record "Requisition Wksh. Name";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"SCM Req. Wksht Item Tracking");
+        ReservationEntry.DeleteAll();
+        RequisitionLine.DeleteAll();
+        RequisitionWkshName.DeleteAll();
+        LibraryVariableStorage.Clear();
+
+        if isInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"SCM Req. Wksht Item Tracking");
+
+        LibraryERMCountryData.UpdateGeneralLedgerSetup();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        LibraryERMCountryData.UpdateSalesReceivablesSetup();
+        LibraryERMCountryData.CreateVATData();
+        NoSeriesSetup();
+
+        isInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"SCM Req. Wksht Item Tracking");
+    end;
+
+    local procedure NoSeriesSetup()
+    var
+        PurchasesPayablesSetup: Record "Purchases & Payables Setup";
+        SalesReceivablesSetup: Record "Sales & Receivables Setup";
+    begin
+        PurchasesPayablesSetup.Get();
+        PurchasesPayablesSetup.Validate("Order Nos.", LibraryUtility.GetGlobalNoSeriesCode());
+        PurchasesPayablesSetup.Modify(true);
+
+        SalesReceivablesSetup.Get();
+        SalesReceivablesSetup.Validate("Order Nos.", LibraryUtility.GetGlobalNoSeriesCode());
+        SalesReceivablesSetup.Modify(true);
+    end;
+
+    local procedure CreateLotForLotItemWithLotTracking(var Item: Record Item)
+    var
+        ItemTrackingCode: Record "Item Tracking Code";
+    begin
+        LibraryItemTracking.CreateItemTrackingCode(ItemTrackingCode, false, true);
+        LibraryInventory.CreateItem(Item);
+        Item.Validate("Item Tracking Code", ItemTrackingCode.Code);
+        Item.Validate("Replenishment System", Item."Replenishment System"::Purchase);
+        Item.Validate("Reordering Policy", Item."Reordering Policy"::"Lot-for-Lot");
+        Item.Validate("Vendor No.", LibraryPurchase.CreateVendorNo());
+        Item.Modify(true);
+    end;
+
+    local procedure CreateSalesOrderWithItem(var SalesHeader: Record "Sales Header"; var SalesLine: Record "Sales Line"; ItemNo: Code[20]; Quantity: Decimal)
+    begin
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Order, '');
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, ItemNo, Quantity);
+    end;
+
+    local procedure CalculatePlanForRequisitionWorksheet(var RequisitionWkshName: Record "Requisition Wksh. Name"; var Item: Record Item; StartDate: Date; EndDate: Date)
+    var
+        ReqWkshTemplate: Record "Req. Wksh. Template";
+    begin
+        ReqWkshTemplate.SetRange(Type, ReqWkshTemplate.Type::"Req.");
+        ReqWkshTemplate.SetRange(Recurring, false);
+        ReqWkshTemplate.FindFirst();
+        LibraryPlanning.CreateRequisitionWkshName(RequisitionWkshName, ReqWkshTemplate.Name);
+
+        LibraryPlanning.CalculatePlanForReqWksh(
+            Item, RequisitionWkshName."Worksheet Template Name", RequisitionWkshName.Name, StartDate, EndDate);
+    end;
+
+    local procedure SelectRequisitionLine(var RequisitionLine: Record "Requisition Line"; ItemNo: Code[20])
+    begin
+        RequisitionLine.SetRange(Type, RequisitionLine.Type::Item);
+        RequisitionLine.SetRange("No.", ItemNo);
+        RequisitionLine.FindFirst();
+    end;
+
+    local procedure AcceptAndCarryOutActionMessage(var RequisitionLine: Record "Requisition Line")
+    begin
+        RequisitionLine.Validate("Accept Action Message", true);
+        RequisitionLine.Modify(true);
+        LibraryPlanning.CarryOutReqWksh(RequisitionLine, WorkDate(), WorkDate(), WorkDate(), WorkDate(), '');
+    end;
+
+    local procedure FindPurchaseLine(var PurchaseLine: Record "Purchase Line"; ItemNo: Code[20])
+    begin
+        PurchaseLine.SetRange("Document Type", PurchaseLine."Document Type"::Order);
+        PurchaseLine.SetRange(Type, PurchaseLine.Type::Item);
+        PurchaseLine.SetRange("No.", ItemNo);
+        PurchaseLine.FindFirst();
+    end;
+
+    [PageHandler]
+    procedure ItemTrackingLinesPageHandler(var ItemTrackingLines: TestPage "Item Tracking Lines")
+    var
+        TrackingMode: Option;
+        Qty: Decimal;
+    begin
+        TrackingMode := LibraryVariableStorage.DequeueInteger();
+        case TrackingMode of
+            ItemTrackingMode::"Assign Lot No.":
+                begin
+                    Qty := LibraryVariableStorage.DequeueDecimal();
+                    ItemTrackingLines."Lot No.".SetValue(LibraryUtility.GenerateGUID());
+                    ItemTrackingLines."Quantity (Base)".SetValue(Qty);
+                end;
+            ItemTrackingMode::"Select Entries":
+                ItemTrackingLines."Select Entries".Invoke();
+        end;
+        ItemTrackingLines.OK().Invoke();
+    end;
+}

diff --git a/App/Layers/W1/Tests/SCM-Service/ServiceStandardCodesReserve.Codeunit.al b/App/Layers/W1/Tests/SCM-Service/ServiceStandardCodesReserve.Codeunit.al
