+namespace Microsoft.Service.Test;
+
+using Microsoft.Inventory.Item;
+using Microsoft.Inventory.Journal;
+using Microsoft.Sales.Customer;
+using Microsoft.Service.Document;
+using Microsoft.Service.Item;
+
+codeunit 136198 "Service Standard Codes Reserve"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Standard Service Code] [Reservation] [Service]
+        isInitialized := false;
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryService: Codeunit "Library - Service";
+        LibrarySales: Codeunit "Library - Sales";
+        ServiceItemGroupCode2: Code[10];
+        StandardServiceCode2: Code[10];
+        isInitialized: Boolean;
+
+    [Test]
+    [HandlerFunctions('ModalFormHandlerServItemGroup')]
+    [Scope('OnPrem')]
+    procedure GetStdServiceCodeWithItemReserveAlwaysCreatesReservation()
+    var
+        Item: Record Item;
+        ServiceHeader: Record "Service Header";
+        ServiceItemLine: Record "Service Item Line";
+        ServiceLine: Record "Service Line";
+        ServiceItemGroup: Record "Service Item Group";
+        StandardServiceCode: Record "Standard Service Code";
+        StandardServiceLine: Record "Standard Service Line";
+        StandardServiceItemGrCode: Record "Standard Service Item Gr. Code";
+        Quantity: Decimal;
+    begin
+        // [SCENARIO] When using Get Std. Service Codes on a Service Order with an Item that has Reserve = Always,
+        // the service line should automatically have Reserved Quantity.
+        // [GIVEN] An Item with Reserve = Always and available inventory
+        Initialize();
+        Quantity := LibraryRandom.RandIntInRange(2, 10);
+
+        CreateItemWithReserve(Item, Item.Reserve::Always);
+        PostPositiveAdjustment(Item."No.", Quantity);
+
+        // [GIVEN] A Standard Service Code with a line for that item with the same quantity
+        LibraryService.CreateStandardServiceCode(StandardServiceCode);
+        CreateStdServiceLineItemWithQuantity(StandardServiceLine, StandardServiceCode.Code, Item."No.", Quantity);
+
+        // [GIVEN] A Service Order with a Service Item Line
+        LibraryService.CreateServiceItemGroup(ServiceItemGroup);
+        ServiceItemGroupCode2 := ServiceItemGroup.Code;
+        CreateServiceOrder(ServiceHeader, ServiceItemLine);
+        StandardServiceCode2 := StandardServiceCode.Code;
+        ServiceItemLine.Validate("Service Item Group Code", ServiceItemGroup.Code);
+        ServiceItemLine.Modify(true);
+
+        // [WHEN] Insert Service Lines from Standard Service Code
+        StandardServiceItemGrCode.InsertServiceLines(ServiceItemLine);
+
+        // [THEN] The Service Line for the Item should have Reserved Quantity equal to the Quantity
+        ServiceLine.SetRange("Document Type", ServiceHeader."Document Type");
+        ServiceLine.SetRange("Document No.", ServiceHeader."No.");
+        ServiceLine.SetRange(Type, ServiceLine.Type::Item);
+        ServiceLine.SetRange("No.", Item."No.");
+        ServiceLine.FindFirst();
+        ServiceLine.CalcFields("Reserved Quantity");
+        Assert.AreEqual(Quantity, ServiceLine."Reserved Quantity", 'Reserved Quantity should equal Quantity for Reserve = Always item');
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(CODEUNIT::"Service Standard Codes Reserve");
+        if isInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(CODEUNIT::"Service Standard Codes Reserve");
+
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateAccountsInServiceContractAccountGroups();
+        LibraryERMCountryData.UpdateAccountInServiceCosts();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        LibraryService.SetupServiceMgtNoSeries();
+        Commit();
+        isInitialized := true;
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(CODEUNIT::"Service Standard Codes Reserve");
+    end;
+
+    local procedure CreateItemWithReserve(var Item: Record Item; Reserve: Enum "Reserve Method")
+    begin
+        LibraryInventory.CreateItem(Item);
+        Item.Validate("Unit Price", LibraryRandom.RandInt(100));
+        Item.Validate(Reserve, Reserve);
+        Item.Modify(true);
+    end;
+
+    local procedure PostPositiveAdjustment(ItemNo: Code[20]; Quantity: Decimal)
+    var
+        ItemJournalLine: Record "Item Journal Line";
+        ItemJournalTemplate: Record "Item Journal Template";
+        ItemJournalBatch: Record "Item Journal Batch";
+    begin
+        ItemJournalTemplate.SetRange(Recurring, false);
+        LibraryInventory.FindItemJournalTemplate(ItemJournalTemplate);
+        LibraryInventory.CreateItemJournalBatch(ItemJournalBatch, ItemJournalTemplate.Name);
+        LibraryInventory.CreateItemJournalLine(
+            ItemJournalLine, ItemJournalTemplate.Name, ItemJournalBatch.Name,
+            ItemJournalLine."Entry Type"::"Positive Adjmt.", ItemNo, Quantity);
+        LibraryInventory.PostItemJournalLine(ItemJournalTemplate.Name, ItemJournalBatch.Name);
+    end;
+
+    local procedure CreateStdServiceLineItemWithQuantity(var StandardServiceLine: Record "Standard Service Line"; StandardServiceCode: Code[10]; ItemNo: Code[20]; Quantity: Decimal)
+    begin
+        LibraryService.CreateStandardServiceLine(StandardServiceLine, StandardServiceCode);
+        StandardServiceLine.Validate(Type, StandardServiceLine.Type::Item);
+        StandardServiceLine.Validate("No.", ItemNo);
+        StandardServiceLine.Validate(Quantity, Quantity);
+        StandardServiceLine.Modify(true);
+    end;
+
+    local procedure CreateServiceOrder(var ServiceHeader: Record "Service Header"; var ServiceItemLine: Record "Service Item Line")
+    var
+        Customer: Record Customer;
+    begin
+        LibrarySales.CreateCustomer(Customer);
+        LibraryService.CreateServiceHeader(ServiceHeader, ServiceHeader."Document Type"::Order, Customer."No.");
+        LibraryService.CreateServiceItemLine(ServiceItemLine, ServiceHeader, '');
+    end;
+
+    [ModalPageHandler]
+    procedure ModalFormHandlerServItemGroup(var StandardServItemGrCodes: Page "Standard Serv. Item Gr. Codes"; var Response: Action)
+    var
+        StandardServiceItemGrCode: Record "Standard Service Item Gr. Code";
+    begin
+        LibraryService.CreateStandardServiceItemGr(StandardServiceItemGrCode, ServiceItemGroupCode2, StandardServiceCode2);
+        StandardServItemGrCodes.SetRecord(StandardServiceItemGrCode);
+        Response := ACTION::LookupOK;
+    end;
+}

