@@ -1222,5 +1222,51 @@ codeunit 137928 "SCM Assembly UT"
         Assert.ExpectedMessage(DatesChangedConfirmHandlerQuestion, Question);
         Reply := true;
     end;
+
+    [Test]
+    [HandlerFunctions('BlanketAssemblyOrderPageHandler')]
+    [Scope('OnPrem')]
+    procedure ShowDocumentOpensBlanketAssemblyOrderForBlanketOrder()
+    var
+        AssemblyHeader: Record "Assembly Header";
+        AssemblyLine: Record "Assembly Line";
+    begin
+        // [FEATURE] [Assembly] [Blanket Order] [UI]
+        // [SCENARIO] When calling Show Document from Assembly Lines page for a Blanket Assembly Order line,
+        // the Blanket Assembly Order page should be opened, not the Assembly Order page.
+
+        // [GIVEN] A Blanket Assembly Order with an assembly line
+        CreateBlanketAssemblyOrderWithLine(AssemblyHeader, AssemblyLine);
+
+        // [WHEN] ShowAssemblyDocument is called on the assembly line
+        // [THEN] The Blanket Assembly Order page is opened (verified in BlanketAssemblyOrderPageHandler)
+        AssemblyLine.ShowAssemblyDocument();
+    end;
+
+    local procedure CreateBlanketAssemblyOrderWithLine(var AssemblyHeader: Record "Assembly Header"; var AssemblyLine: Record "Assembly Line")
+    begin
+        AssemblyHeader.Init();
+        AssemblyHeader."Document Type" := AssemblyHeader."Document Type"::"Blanket Order";
+        AssemblyHeader."No." := LibraryUtility.GenerateGUID();
+        AssemblyHeader.Insert();
