@@ -0,0 +1,171 @@
+codeunit 137170 "SCM Whse. Put-Away Break Filter"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Warehouse] [SCM] [Put-away] [Breakbulk Filter]
+        isInitialized := false;
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryWarehouse: Codeunit "Library - Warehouse";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryPurchase: Codeunit "Library - Purchase";
+        LibraryRandom: Codeunit "Library - Random";
+        isInitialized: Boolean;
+
+    [Test]
+    [HandlerFunctions('ConfirmHandlerYes')]
+    [Scope('OnPrem')]
+    procedure RegisterPutAwayWithBreakbulkFilterRegistersAllLines()
+    var
+        Location: Record Location;
+        WarehouseEmployee: Record "Warehouse Employee";
+        Item: Record Item;
+        ItemUnitOfMeasure: Record "Item Unit of Measure";
+        PurchaseHeader: Record "Purchase Header";
+        PurchaseLine: Record "Purchase Line";
+        WarehouseActivityHeader: Record "Warehouse Activity Header";
+        WarehouseActivityLine: Record "Warehouse Activity Line";
+        RegisteredWhseActivityLine: Record "Registered Whse. Activity Line";
+        WarehousePutAway: TestPage "Warehouse Put-away";
+        QtyPerUOM: Decimal;
+        PurchQty: Decimal;
+        TotalRegisteredBaseQty: Decimal;
+    begin
+        // [FEATURE] [Put-Away] [Breakbulk Filter]
+        // [SCENARIO] When registering a put-away with Breakbulk Filter set to Yes, all put-away lines should be registered, not just the visible (non-breakbulk) lines.
+        Initialize();
+        QtyPerUOM := LibraryRandom.RandIntInRange(5, 10);
+        PurchQty := LibraryRandom.RandIntInRange(10, 20);
+
+        // [GIVEN] Full WMS location "L" with Allow Breakbulk = TRUE.
+        LibraryWarehouse.CreateFullWMSLocation(Location, 1);
+        Location.Validate("Allow Breakbulk", true);
+        Location.Modify(true);
+        LibraryWarehouse.CreateWarehouseEmployee(WarehouseEmployee, Location.Code, false);
+
+        // [GIVEN] Item with Base Unit of Measure = "PCS" and alternate Unit of Measure = "BOX". "BOX" contains "X" units of "PCS".
+        // [GIVEN] Put-away Unit of Measure Code in the item is "PCS" (base UOM).
+        LibraryInventory.CreateItem(Item);
+        CreateItemUnitOfMeasure(ItemUnitOfMeasure, Item."No.", QtyPerUOM);
+        UpdateItemUOM(Item, ItemUnitOfMeasure.Code, '', Item."Base Unit of Measure");
+
+        // [GIVEN] Purchase Order for "Y" units of "BOX".
+        LibraryPurchase.CreatePurchHeader(PurchaseHeader, PurchaseHeader."Document Type"::Order, '');
+        LibraryPurchase.CreatePurchaseLine(PurchaseLine, PurchaseHeader, PurchaseLine.Type::Item, Item."No.", PurchQty);
+        PurchaseLine.Validate("Location Code", Location.Code);
+        PurchaseLine.Modify(true);
+        LibraryPurchase.ReleasePurchaseDocument(PurchaseHeader);
+
+        // [GIVEN] Posted warehouse receipt for full quantity - this creates a put-away with breakbulk lines.
+        CreateAndPostWarehouseReceiptFromPurchaseOrder(PurchaseHeader);
+
+        // [GIVEN] The put-away has breakbulk lines (4 lines: 2 for original UOM conversion, 2 for base UOM put-away).
+        FindWarehouseActivityLine(
+          WarehouseActivityLine, WarehouseActivityLine."Source Document"::"Purchase Order", PurchaseHeader."No.",
+          WarehouseActivityLine."Activity Type"::"Put-away");
+        WarehouseActivityHeader.Get(WarehouseActivityLine."Activity Type", WarehouseActivityLine."No.");
+
+        // [GIVEN] Breakbulk Filter is set to Yes on the put-away header (filtering out breakbulk lines from view).
+        WarehouseActivityHeader.Validate("Breakbulk Filter", true);
+        WarehouseActivityHeader.Modify(true);
+
+        // [WHEN] Register the put-away from the page (this calls RegisterPutAwayYesNo on the subform which is the fixed code).
+        WarehousePutAway.OpenEdit();
+        WarehousePutAway.FILTER.SetFilter("No.", WarehouseActivityHeader."No.");
+        WarehousePutAway.WhseActivityLines.First();
+        WarehousePutAway."&Register Put-away".Invoke();
+        WarehousePutAway.Close();
+
+        // [THEN] The put-away is fully registered - all lines including breakbulk lines should be registered.
+        Assert.IsFalse(WarehouseActivityHeader.Find(), 'Put-away should be fully registered and deleted.');
+
+        // [THEN] Verify registered put-away lines - the total registered quantity should match the total original quantity.
+        RegisteredWhseActivityLine.SetRange("Source Document", RegisteredWhseActivityLine."Source Document"::"Purchase Order");
+        RegisteredWhseActivityLine.SetRange("Source No.", PurchaseHeader."No.");
+        RegisteredWhseActivityLine.SetRange("Activity Type", RegisteredWhseActivityLine."Activity Type"::"Put-away");
+        RegisteredWhseActivityLine.SetRange("Action Type", RegisteredWhseActivityLine."Action Type"::Place);
+        RegisteredWhseActivityLine.CalcSums("Qty. (Base)");
+        TotalRegisteredBaseQty := RegisteredWhseActivityLine."Qty. (Base)";
+
+        // The total registered base quantity should equal the purchase quantity times the UOM conversion.
+        Assert.AreEqual(PurchQty * QtyPerUOM, TotalRegisteredBaseQty, 'All put-away lines should be registered when using Breakbulk Filter.');
+    end;
+
+    local procedure Initialize()
+    var
+        WarehouseEmployee: Record "Warehouse Employee";
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(CODEUNIT::"SCM Whse. Put-Away Break Filter");
+
+        if isInitialized then
+            exit;
+
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(CODEUNIT::"SCM Whse. Put-Away Break Filter");
+
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        NoSeriesSetup();
+
+        WarehouseEmployee.DeleteAll(true);
+
+        isInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(CODEUNIT::"SCM Whse. Put-Away Break Filter");
+    end;
+
+    local procedure NoSeriesSetup()
+    var
+        WarehouseSetup: Record "Warehouse Setup";
+    begin
+        LibraryWarehouse.NoSeriesSetup(WarehouseSetup);
+    end;
+
+    local procedure CreateItemUnitOfMeasure(var ItemUnitOfMeasure: Record "Item Unit of Measure"; ItemNo: Code[20]; QtyPerUnitOfMeasure: Decimal)
+    begin
+        LibraryInventory.CreateItemUnitOfMeasureCode(ItemUnitOfMeasure, ItemNo, QtyPerUnitOfMeasure);
+    end;
+
+    local procedure UpdateItemUOM(var Item: Record Item; PurchUnitOfMeasure: Code[10]; SalesUnitOfMeasure: Code[10]; PutAwayUnitOfMeasureCode: Code[10])
+    begin
+        Item.Validate("Purch. Unit of Measure", PurchUnitOfMeasure);
+        if SalesUnitOfMeasure <> '' then
+            Item.Validate("Sales Unit of Measure", SalesUnitOfMeasure);
+        Item.Validate("Put-away Unit of Measure Code", PutAwayUnitOfMeasureCode);
+        Item.Modify(true);
+    end;
+
+    local procedure CreateAndPostWarehouseReceiptFromPurchaseOrder(PurchaseHeader: Record "Purchase Header")
+    var
+        WarehouseReceiptLine: Record "Warehouse Receipt Line";
+        WarehouseReceiptHeader: Record "Warehouse Receipt Header";
+    begin
+        LibraryWarehouse.CreateWhseReceiptFromPO(PurchaseHeader);
+        WarehouseReceiptLine.SetRange("Source Document", WarehouseReceiptLine."Source Document"::"Purchase Order");
+        WarehouseReceiptLine.SetRange("Source No.", PurchaseHeader."No.");
+        WarehouseReceiptLine.FindFirst();
+        WarehouseReceiptHeader.Get(WarehouseReceiptLine."No.");
+        LibraryWarehouse.PostWhseReceipt(WarehouseReceiptHeader);
+    end;
+
+    local procedure FindWarehouseActivityLine(var WarehouseActivityLine: Record "Warehouse Activity Line"; SourceDocument: Enum "Warehouse Activity Source Document"; SourceNo: Code[20];
+                                                                                                                               ActivityType: Enum "Warehouse Activity Type")
+    begin
+        WarehouseActivityLine.SetRange("Source Document", SourceDocument);
+        WarehouseActivityLine.SetRange("Source No.", SourceNo);
+        WarehouseActivityLine.SetRange("Activity Type", ActivityType);
+        WarehouseActivityLine.FindFirst();
+    end;
+
+    [ConfirmHandler]
+    procedure ConfirmHandlerYes(Question: Text[1024]; var Reply: Boolean)
+    begin
+        Reply := true;
+    end;
+}

