+        ProdOrderLine: Record "Prod. Order Line";
+        ProdOrderComponent: Record "Prod. Order Component";
+        ProdBOMQtyPer: Decimal;
+    begin
+        // [SCENARIO] Prod. Order Component "Quantity per" preserves partial quantity when component's Item UOM has Qty. Rounding Precision = 1
+        // [GIVEN] Component Item with Replenishment System = Purchase, Rounding Precision = 0.01
+        // [GIVEN] Component Item's Base UOM has Qty. Rounding Precision = 1
+        // [GIVEN] Production Item with Replenishment System = Prod. Order, Rounding Precision = 1
+        // [GIVEN] Production BOM with Component Item having Quantity Per = 0.09 (partial quantity)
+        Initialize();
+
+        ProdBOMQtyPer := 0.09;
+
+        // [GIVEN] Create Component Item with Replenishment System = Purchase
+        LibraryInventory.CreateItem(CompItem);
+        CompItem.Validate("Replenishment System", CompItem."Replenishment System"::Purchase);
+        CompItem.Validate("Rounding Precision", 0.01);
+        CompItem.Modify(true);
+
+        // [GIVEN] Set Qty. Rounding Precision = 1 on Component Item's Base UOM
+        CompItemUnitOfMeasure.Get(CompItem."No.", CompItem."Base Unit of Measure");
+        CompItemUnitOfMeasure.Validate("Qty. Rounding Precision", 1);
+        CompItemUnitOfMeasure.Modify(true);
+
+        // [GIVEN] Create Production Item with Replenishment System = Prod. Order
+        LibraryInventory.CreateItem(ProdItem);
+        ProdItem.Validate("Replenishment System", ProdItem."Replenishment System"::"Prod. Order");
+        ProdItem.Validate("Rounding Precision", 1);
+        ProdItem.Modify(true);
+
+        // [GIVEN] Create and certify Production BOM with Component having Quantity Per = 0.09
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, ProdItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, CompItem."No.", ProdBOMQtyPer);
+        ProductionBOMLine.Validate("Unit of Measure Code", CompItem."Base Unit of Measure");
+        ProductionBOMLine.Modify(true);
+        LibraryManufacturing.UpdateProductionBOMStatus(ProductionBOMHeader, ProductionBOMHeader.Status::Certified);
+
+        // [GIVEN] Assign Production BOM to Production Item
+        ProdItem.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        ProdItem.Modify(true);
+
+        // [WHEN] Create and refresh Released Production Order for 1 quantity
+        LibraryManufacturing.CreateProductionOrder(ProductionOrder, ProductionOrder.Status::Released, ProductionOrder."Source Type"::Item, ProdItem."No.", 1);
+        LibraryManufacturing.RefreshProdOrder(ProductionOrder, false, true, true, true, false);
+
+        // [THEN] Prod. Order Component "Quantity per" = 0.09 (not rounded to 0)
+        FindProductionOrderLine(ProdOrderLine, ProdItem."No.");
+        FindProdOrderComponentByItem(ProdOrderComponent, ProdOrderLine, CompItem."No.");
+        Assert.AreEqual(ProdBOMQtyPer, ProdOrderComponent."Quantity per", 'Quantity per should preserve partial quantity when Qty. Rounding Precision = 1');
+
+        // [THEN] Prod. Order Component "Expected Quantity" = 0.09 (not rounded to 0)
+        Assert.AreEqual(ProdBOMQtyPer, ProdOrderComponent."Expected Quantity", 'Expected Quantity should preserve partial quantity when Qty. Rounding Precision = 1');
+    end;
