+        // [GIVEN] A production item with a component item (using Pick + Backward flushing method to be eligible for pick worksheet)
+        LibraryInventory.CreateItem(ParentItem);
+        LibraryInventory.CreateItem(CompItem);
+        CompItem.Validate("Flushing Method", "Flushing Method"::"Pick + Backward");
+        CompItem.Modify(true);
+        LibraryManufacturing.CreateCertifiedProductionBOM(ProductionBOMHeader, CompItem."No.", 1);
+        ParentItem."Production BOM No." := ProductionBOMHeader."No.";
+        ParentItem."Replenishment System" := ParentItem."Replenishment System"::"Prod. Order";
+        ParentItem.Modify(true);
+
+        // [GIVEN] Post component inventory to a bin - total quantity 3 PCS (2 for first order + 1 for second order)
+        TotalCompQty := 3;
+        Bin.SetRange("Location Code", Location.Code);
+        Bin.FindFirst();
+        CreateAndPostItemJournalLine(CompItem."No.", "Item Ledger Entry Type"::"Positive Adjmt.", TotalCompQty, Location.Code, Bin.Code, '');
+
+        // [GIVEN] Two Released Production Orders for the parent item
+        // First Production Order: Quantity = 2
+        CreateAndRefreshProductionOrder(ProductionOrder1, "Production Order Status"::Released, "Prod. Order Source Type"::Item, ParentItem."No.", 2, Location.Code);
+
+        // Second Production Order: Quantity = 1
+        CreateAndRefreshProductionOrder(ProductionOrder2, "Production Order Status"::Released, "Prod. Order Source Type"::Item, ParentItem."No.", 1, Location.Code);
+
+        // [GIVEN] Reserve components on both production orders against inventory
+        AutoReserveProdOrderComponents(ProductionOrder1);
+        AutoReserveProdOrderComponents(ProductionOrder2);
+
+        // [GIVEN] Get Warehouse Documents on Pick Worksheet for Production Orders
+        LibraryWarehouse.SelectWhseWorksheetTemplate(WhseWorksheetTemplate, WhseWorksheetTemplate.Type::Pick);
+        LibraryWarehouse.SelectWhseWorksheetName(WhseWorksheetName, WhseWorksheetTemplate.Name, Location.Code);
+        WhsePickRequest.SetRange(Status, WhsePickRequest.Status::Released);
+        WhsePickRequest.SetRange("Completely Picked", false);
+        WhsePickRequest.SetRange("Location Code", Location.Code);
+        WhsePickRequest.SetRange("Document Type", WhsePickRequest."Document Type"::Production);
+        LibraryWarehouse.GetOutboundSourceDocuments(WhsePickRequest, WhseWorksheetName, Location.Code);
+
+        // [GIVEN] Verify that pick worksheet lines are created
+        WhseWorksheetLine.SetRange("Worksheet Template Name", WhseWorksheetName."Worksheet Template Name");
+        WhseWorksheetLine.SetRange(Name, WhseWorksheetName.Name);
+        WhseWorksheetLine.SetRange("Location Code", Location.Code);
+        Assert.RecordIsNotEmpty(WhseWorksheetLine);
+
+        // [WHEN] Create Pick from Pick Worksheet
+        // This should NOT raise an availability error even though components are reserved
+        LibraryWarehouse.CreatePickFromPickWorksheet(
+            WhseWorksheetLine, 0, WhseWorksheetName."Worksheet Template Name", WhseWorksheetName.Name,
+            Location.Code, '', 0, 0, "Whse. Activity Sorting Method"::None, false, false, false, false, false, false, false);
+
+        // [THEN] Warehouse Pick lines are created successfully (no availability error was thrown)
+        WarehouseActivityLine.SetRange("Activity Type", WarehouseActivityLine."Activity Type"::Pick);
+        WarehouseActivityLine.SetRange("Location Code", Location.Code);
+        WarehouseActivityLine.SetRange("Item No.", CompItem."No.");
+        Assert.RecordIsNotEmpty(WarehouseActivityLine);
+
+        // [THEN] Verify total quantity on pick lines matches the total component quantity
+        WarehouseActivityLine.SetRange("Action Type", WarehouseActivityLine."Action Type"::Take);
+        WarehouseActivityLine.CalcSums(Quantity);
+        Assert.AreEqual(TotalCompQty, WarehouseActivityLine.Quantity, 'Total pick quantity should match the total component quantity.');
+    end;
+
+    local procedure AutoReserveProdOrderComponents(ProductionOrder: Record "Production Order")
+    var
+        ProdOrderLine: Record "Prod. Order Line";
+        ProdOrderComponent: Record "Prod. Order Component";
+    begin
+        ProdOrderLine.SetRange(Status, ProductionOrder.Status);
+        ProdOrderLine.SetRange("Prod. Order No.", ProductionOrder."No.");
+        if ProdOrderLine.FindSet() then
+            repeat
+                ProdOrderComponent.SetRange(Status, ProdOrderLine.Status);
+                ProdOrderComponent.SetRange("Prod. Order No.", ProdOrderLine."Prod. Order No.");
+                ProdOrderComponent.SetRange("Prod. Order Line No.", ProdOrderLine."Line No.");
+                if ProdOrderComponent.FindSet() then
+                    repeat
+                        ProdOrderComponent.AutoReserve();
+                    until ProdOrderComponent.Next() = 0;
+            until ProdOrderLine.Next() = 0;
+    end;
+
