diff --git a/App/Layers/W1/Tests/SCM/MfgItemIntegrationTests.Codeunit.al b/App/Layers/W1/Tests/SCM/MfgItemIntegrationTests.Codeunit.al
new file mode 100644
index 00000000..e7ef2216
--- /dev/null
+++ b/App/Layers/W1/Tests/SCM/MfgItemIntegrationTests.Codeunit.al
@@ -0,0 +1,149 @@
+codeunit 134829 "Mfg. Item Integration Tests"
+{
+    Subtype = Test;
+    TestPermissions = NonRestrictive;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Item] [Item Variant] [Rename]
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryUtility: Codeunit "Library - Utility";
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        isInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure RenameItemWithVariantAndValueEntries()
+    var
+        Item: Record Item;
+        ItemVariant: Record "Item Variant";
+        ValueEntry: Record "Value Entry";
+        OldItemNo: Code[20];
+        NewItemNo: Code[20];
+    begin
+        // [SCENARIO] Item can be renamed when it has Item Variants and Value Entries with Variant Codes
+        // Bug fix: OnBeforeRenameItemVariant event subscriber should check RunTrigger parameter
+        // Before fix: Error "You cannot rename Item No. in a Item Variant, because it is used in Value Entry"
+        // After fix: Item rename succeeds because cascading Item Variant renames have RunTrigger = false
+        Initialize();
+
+        // [GIVEN] An Item with a Variant Code
+        LibraryInventory.CreateItem(Item);
+        OldItemNo := Item."No.";
+        LibraryInventory.CreateItemVariant(ItemVariant, Item."No.");
+
+        // [GIVEN] Posted inventory adjustment to create Item Ledger Entries and Value Entries for Item with Variant
+        PostPositiveAdjustmentWithVariant(Item, ItemVariant.Code, LibraryRandom.RandDecInRange(10, 100, 2));
+
+        // [GIVEN] Value Entries exist for the Item with the Variant Code
+        ValueEntry.SetRange("Item No.", Item."No.");
+        ValueEntry.SetRange("Variant Code", ItemVariant.Code);
+        Assert.RecordIsNotEmpty(ValueEntry);
+
+        // [WHEN] Rename the Item to a new Item No.
+        NewItemNo := LibraryUtility.GenerateGUID();
+        Item.Rename(NewItemNo);
+
+        // [THEN] The Item is successfully renamed
+        Assert.IsFalse(Item.Get(OldItemNo), 'Old Item No. should not exist');
+        Assert.IsTrue(Item.Get(NewItemNo), 'New Item No. should exist');
+
+        // [THEN] The Item Variant is also renamed to the new Item No.
+        Assert.IsTrue(ItemVariant.Get(NewItemNo, ItemVariant.Code), 'Item Variant should have new Item No.');
+
+        // [THEN] Value Entries are updated to the new Item No.
+        ValueEntry.Reset();
+        ValueEntry.SetRange("Item No.", NewItemNo);
+        ValueEntry.SetRange("Variant Code", ItemVariant.Code);
+        Assert.RecordIsNotEmpty(ValueEntry);
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure RenameItemWithVariantAndValueEntriesForBlankVariant()
+    var
+        Item: Record Item;
+        ItemVariant: Record "Item Variant";
+        ValueEntry: Record "Value Entry";
+        OldItemNo: Code[20];
+        NewItemNo: Code[20];
+    begin
+        // [SCENARIO] Item can be renamed when it has Item Variants with Value Entries for both blank and non-blank Variant Codes
+        // This reproduces the exact repro steps from the bug report:
+        // 1. Create item with variant codes
+        // 2. Post item journal with variant (creates Value Entries with Variant Code)
+        // 3. Post sales invoice without variant (creates Value Entries with blank Variant Code)
+        // 4. Post sales invoice with variant (creates Value Entries with Variant Code)
+        // 5. Attempt to rename item - should succeed after fix
+        Initialize();
+
+        // [GIVEN] An Item with a Variant Code
+        LibraryInventory.CreateItem(Item);
+        OldItemNo := Item."No.";
+        LibraryInventory.CreateItemVariant(ItemVariant, Item."No.");
+
+        // [GIVEN] Posted inventory adjustments for Item without variant (blank Variant Code)
+        PostPositiveAdjustmentWithVariant(Item, '', LibraryRandom.RandDecInRange(10, 100, 2));
+
+        // [GIVEN] Posted inventory adjustment for Item with Variant
+        PostPositiveAdjustmentWithVariant(Item, ItemVariant.Code, LibraryRandom.RandDecInRange(10, 100, 2));
+
+        // [GIVEN] Value Entries exist with blank Variant Code
+        ValueEntry.SetRange("Item No.", Item."No.");
+        ValueEntry.SetRange("Variant Code", '');
+        Assert.RecordIsNotEmpty(ValueEntry);
+
+        // [GIVEN] Value Entries exist with the Variant Code
+        ValueEntry.SetRange("Variant Code", ItemVariant.Code);
+        Assert.RecordIsNotEmpty(ValueEntry);
+
+        // [WHEN] Rename the Item to a new Item No.
+        NewItemNo := LibraryUtility.GenerateGUID();
+        Item.Rename(NewItemNo);
+
+        // [THEN] The Item is successfully renamed
+        Assert.IsFalse(Item.Get(OldItemNo), 'Old Item No. should not exist');
+        Assert.IsTrue(Item.Get(NewItemNo), 'New Item No. should exist');
+
+        // [THEN] The Item Variant is also renamed to the new Item No.
+        Assert.IsTrue(ItemVariant.Get(NewItemNo, ItemVariant.Code), 'Item Variant should have new Item No.');
+    end;
+
+    local procedure Initialize()
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"Mfg. Item Integration Tests");
+        if isInitialized then
+            exit;
+
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"Mfg. Item Integration Tests");
+        isInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"Mfg. Item Integration Tests");
+    end;
+
+    local procedure PostPositiveAdjustmentWithVariant(Item: Record Item; VariantCode: Code[10]; Qty: Decimal)
+    var
+        ItemJournalTemplate: Record "Item Journal Template";
+        ItemJournalBatch: Record "Item Journal Batch";
+        ItemJournalLine: Record "Item Journal Line";
+    begin
+        LibraryInventory.CreateItemJournalTemplate(ItemJournalTemplate);
+        LibraryInventory.CreateItemJournalBatch(ItemJournalBatch, ItemJournalTemplate.Name);
+        LibraryInventory.CreateItemJournalLine(
+            ItemJournalLine,
+            ItemJournalTemplate.Name,
+            ItemJournalBatch.Name,
+            ItemJournalLine."Entry Type"::"Positive Adjmt.",
+            Item."No.",
+            Qty);
+        ItemJournalLine.Validate("Variant Code", VariantCode);
+        ItemJournalLine.Validate("Unit Amount", LibraryRandom.RandDecInRange(10, 100, 2));
+        ItemJournalLine.Modify(true);
+        LibraryInventory.PostItemJournalLine(ItemJournalTemplate.Name, ItemJournalBatch.Name);
+    end;
+}

