+codeunit 134936 "ERM Purchase Journal UT"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Purchase Journal] [UT]
+    end;
+
+    var
+        LibraryERM: Codeunit "Library - ERM";
+        LibraryPurchase: Codeunit "Library - Purchase";
+        Assert: Codeunit Assert;
+        IsInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure PurchaseJournalDocumentAmountAcceptsThreeDecimalPlaces()
+    var
+        GenJournalTemplate: Record "Gen. Journal Template";
+        GenJournalBatch: Record "Gen. Journal Batch";
+        GenJournalLine: Record "Gen. Journal Line";
+        Currency: Record Currency;
+        Vendor: Record Vendor;
+        PurchaseJournal: TestPage "Purchase Journal";
+        AmountWith3Decimals: Decimal;
+    begin
+        // [SCENARIO] Document Amount field in Purchase Journal should accept amounts with 3 decimal places for currencies like TND
+        // [GIVEN] A currency with 3 decimal places (like TND)
+        Initialize();
+        CreateCurrencyWith3DecimalPlaces(Currency);
+
+        // [GIVEN] A vendor with the currency
+        LibraryPurchase.CreateVendor(Vendor);
+        Vendor.Validate("Currency Code", Currency.Code);
+        Vendor.Modify(true);
+
+        // [GIVEN] A purchase journal template and batch
+        CreatePurchaseJournalTemplateBatch(GenJournalTemplate, GenJournalBatch);
+
+        // [GIVEN] An amount with 3 decimal places
+        AmountWith3Decimals := 1.234;
+
+        // [WHEN] Opening the Purchase Journal page and entering a Document Amount with 3 decimal places
+        PurchaseJournal.OpenEdit();
+        PurchaseJournal.CurrentJnlBatchName.SetValue(GenJournalBatch.Name);
+        PurchaseJournal."Document Type".SetValue(GenJournalLine."Document Type"::Invoice);
+        PurchaseJournal."Account Type".SetValue(GenJournalLine."Account Type"::Vendor);
+        PurchaseJournal."Account No.".SetValue(Vendor."No.");
+        // The vendor has the currency code set, which will be inherited by the journal line
+        PurchaseJournal.DocumentAmount.SetValue(AmountWith3Decimals);
+        PurchaseJournal.Close();
+
+        // [THEN] The journal line should have the correct amount with 3 decimal places
+        GenJournalLine.SetRange("Journal Template Name", GenJournalTemplate.Name);
+        GenJournalLine.SetRange("Journal Batch Name", GenJournalBatch.Name);
+        GenJournalLine.FindFirst();
+
+        // For Invoice document type, the amount is negative
+        Assert.AreEqual(-AmountWith3Decimals, GenJournalLine.Amount, 'Amount should be stored with 3 decimal places');
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        if IsInitialized then
+            exit;
+
+        LibraryERMCountryData.UpdateLocalData();
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+
+        IsInitialized := true;
+    end;
+
+    local procedure CreateCurrencyWith3DecimalPlaces(var Currency: Record Currency)
+    begin
+        LibraryERM.CreateCurrency(Currency);
+        Currency.Validate("Amount Decimal Places", '3:3');
+        Currency.Validate("Unit-Amount Decimal Places", '3:5');
+        Currency.Modify(true);
+
+        // Create exchange rate for the currency
+        LibraryERM.CreateExchangeRate(Currency.Code, WorkDate(), 1, 1);
+    end;
+
+    local procedure CreatePurchaseJournalTemplateBatch(var GenJournalTemplate: Record "Gen. Journal Template"; var GenJournalBatch: Record "Gen. Journal Batch")
+    begin
+        LibraryERM.CreateGenJournalTemplate(GenJournalTemplate);
+        GenJournalTemplate.Validate(Type, GenJournalTemplate.Type::Purchases);
+        GenJournalTemplate.Modify(true);
+
+        LibraryERM.CreateGenJournalBatch(GenJournalBatch, GenJournalTemplate.Name);
+    end;
+}

