+
+    [Test]
+    [HandlerFunctions('DueDateBeforeWorkDateMsgHandler')]
+    procedure AvailWarningConsidersDueDatesWhenCheckingFutureDemand()
+    var
+        ParentItem: Record Item;
+        ChildItem: Record Item;
+        AsmHeader1: Record "Assembly Header";
+        AsmHeader2: Record "Assembly Header";
+        AsmLine1: Record "Assembly Line";
+        DueDate1: Date;
+        DueDate2: Date;
+    begin
+        // [SCENARIO] Avail. Warning on Assembly Order Lines considers Due Dates when calculating availability, 
+        // and does not incorrectly show a warning when available inventory covers the current order's demand.
+
+        // [GIVEN] Create assembled item with one component (Qty Per = 2)
+        Initialize();
+        MockAsmItem(ParentItem, ChildItem, 2);
+
+        // [GIVEN] Add 2 units of component to inventory (enough for 1 assembly order)
+        AddItemToInventory(ChildItem, '', '', 2);
+
+        // [GIVEN] Create first Assembly Order for 1 qty with Due Date = Today
+        DueDate1 := WorkDate();
+        MockAsmOrder(AsmHeader1, ParentItem, 1, DueDate1, '');
+        AsmLine1.Get(AsmHeader1."Document Type", AsmHeader1."No.", 10000);
+        
+        // [GIVEN] Verify first order has no availability warning (2 in stock, 2 needed)
+        Assert.IsFalse(AsmLine1."Avail. Warning", 'First order line should have no warning initially');
+
+        // [GIVEN] Create second Assembly Order for 3 qty with Due Date 5 days later (creates future demand of 6 components)
+        DueDate2 := CalcDate('<+5D>', WorkDate());
+        MockAsmOrder(AsmHeader2, ParentItem, 3, DueDate2, '');
+
+        // [WHEN] Re-read the first Assembly Order line to recalculate availability warning
+        AsmLine1.Get(AsmHeader1."Document Type", AsmHeader1."No.", 10000);
+        AsmLine1.UpdateAvailWarning();
+
+        // [THEN] First order should still have no availability warning because 2 units in inventory 
+        // covers the 2 units needed for this order on its due date. The future demand from the second order 
+        // should not affect the availability warning for the first order.
+        Assert.IsFalse(
+            AsmLine1."Avail. Warning",
+            'Avail. Warning should be FALSE - inventory is sufficient for this order by its due date, regardless of future demand');
+
+        NotificationLifecycleMgt.RecallAllNotifications();
+    end;
 }

