+        // [SCENARIO] Job cost fields are updated when Amount (LCY) is changed on a Gen. Journal Line with Job Task set.
+        // [GIVEN] A Job G/L Journal Line with Job No., Job Task No., and Job Quantity filled.
+        Initialize();
+        LibraryJob.CreateJob(Job);
+        LibraryJob.CreateJobTask(Job, JobTask);
+        LibraryJob.CreateJobGLJournalLine(GenJournalLine."Job Line Type"::Billable, JobTask, GenJournalLine);
+
+        // Store initial job cost values which are automatically calculated from Amount
+        InitialJobUnitCost := GenJournalLine."Job Unit Cost (LCY)";
+        InitialJobTotalCost := GenJournalLine."Job Total Cost (LCY)";
+
+        // [WHEN] The Amount (LCY) field is changed to a different value
+        NewAmountLCY := GenJournalLine."Amount (LCY)" + LibraryRandom.RandDec(100, 2);
+        GenJournalLine.Validate("Amount (LCY)", NewAmountLCY);
+
+        // [THEN] The Job cost fields should be updated to reflect the new Amount (LCY)
+        Assert.AreNotEqual(InitialJobUnitCost, GenJournalLine."Job Unit Cost (LCY)", 'Job Unit Cost (LCY) should be updated when Amount (LCY) changes');
+        Assert.AreNotEqual(InitialJobTotalCost, GenJournalLine."Job Total Cost (LCY)", 'Job Total Cost (LCY) should be updated when Amount (LCY) changes');
+        Assert.AreEqual(NewAmountLCY / GenJournalLine."Job Quantity", GenJournalLine."Job Unit Cost (LCY)", 'Job Unit Cost (LCY) should equal new Amount (LCY) divided by Job Quantity');
+        Assert.AreEqual(NewAmountLCY, GenJournalLine."Job Total Cost (LCY)", 'Job Total Cost (LCY) should equal new Amount (LCY)');
+    end;
+
     [Test]
     [Scope('OnPrem')]
     procedure UpdateLineAmountOnJobJournalLine()

