diff --git a/App/Layers/W1/Tests/SCM-Manufacturing/SCMProdOrderQtyRoundingTest.Codeunit.al b/App/Layers/W1/Tests/SCM-Manufacturing/SCMProdOrderQtyRoundingTest.Codeunit.al
new file mode 100644
index 00000000..491e4dbf
--- /dev/null
+++ b/App/Layers/W1/Tests/SCM-Manufacturing/SCMProdOrderQtyRoundingTest.Codeunit.al
@@ -0,0 +1,155 @@
+// ------------------------------------------------------------------------------------------------
+// Copyright (c) Microsoft Corporation. All rights reserved.
+// Licensed under the MIT License. See License.txt in the project root for license information.
+// ------------------------------------------------------------------------------------------------
+namespace Microsoft.Manufacturing.Test;
+
+using Microsoft.Foundation.UOM;
+using Microsoft.Inventory.Item;
+using Microsoft.Manufacturing.Document;
+using Microsoft.Manufacturing.ProductionBOM;
+using Microsoft.Sales.Document;
+using System.TestLibraries.Utilities;
+
+codeunit 137899 "SCM Prod Order Qty Rounding"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Manufacturing] [Production Order] [Rounding] [SCM]
+    end;
+
+    var
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryManufacturing: Codeunit "Library - Manufacturing";
+        LibrarySales: Codeunit "Library - Sales";
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        Initialized: Boolean;
+
+    [Test]
+    [HandlerFunctions('ProdOrderCreatedMessageHandler')]
+    [Scope('OnPrem')]
+    procedure ProdOrderComponentQtyPerNotZeroWhenItemUOMHasQtyRndPrecision()
+    var
+        ComponentItem: Record Item;
+        FinishedGoodsItem: Record Item;
+        ItemUnitOfMeasure: Record "Item Unit of Measure";
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionBOMLine: Record "Production BOM Line";
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        ProductionOrder: Record "Production Order";
+        ProdOrderComponent: Record "Prod. Order Component";
+        CreateProdOrderFromSale: Codeunit "Create Prod. Order from Sale";
+        QuantityPer: Decimal;
+    begin
+        // [FEATURE] [Production Order] [Component] [Rounding]
+        // [SCENARIO] When a component Item UOM has Qty. Rounding Precision = 1 and FG consumes partial quantity,
+        // the Prod. Order Component should have correct Quantity per (not 0).
+        Initialize();
+
+        // [GIVEN] Component item with Replenishment System = Purchase and Rounding Precision = 0.01
+        // [GIVEN] Component item's Base UOM has "Qty. Rounding Precision" = 1
+        QuantityPer := 0.09;
+        CreateComponentItemWithUOMQtyRoundingPrecision(ComponentItem, 0.01, 1);
+
+        // [GIVEN] Finished goods item with Replenishment System = Prod. Order and Rounding Precision = 1
+        // [GIVEN] Production BOM that consumes Component with "Quantity Per" = 0.09
+        CreateFinishedGoodsItemWithBOM(FinishedGoodsItem, ComponentItem, QuantityPer);
+
+        // [GIVEN] Sales Order for FG Item with Quantity = 1
+        LibrarySales.CreateSalesDocumentWithItem(
+            SalesHeader, SalesLine, SalesHeader."Document Type"::Order, '', FinishedGoodsItem."No.", 1, '', 0D);
+
+        // [WHEN] Create Production Order from Sales Order
+        CreateProdOrderFromSale.CreateProductionOrder(
+            SalesLine, "Production Order Status"::Released, "Create Production Order Type"::ItemOrder);
+
+        // [THEN] Production Order Component has "Quantity per" = 0.09 (not 0)
+        FindProductionOrder(ProductionOrder, ProductionOrder.Status::Released, FinishedGoodsItem."No.");
+        FindProdOrderComponent(ProdOrderComponent, ProductionOrder.Status, ProductionOrder."No.", ComponentItem."No.");
+        Assert.AreEqual(QuantityPer, ProdOrderComponent."Quantity per",
+            'Quantity per on Prod. Order Component should not be rounded to 0');
+        Assert.AreEqual(QuantityPer, ProdOrderComponent."Expected Quantity",
+            'Expected Quantity on Prod. Order Component should not be rounded to 0');
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(CODEUNIT::"SCM Prod Order Qty Rounding");
+        if Initialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(CODEUNIT::"SCM Prod Order Qty Rounding");
+
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        LibraryERMCountryData.CreateVATData();
+        Commit();
+
+        Initialized := true;
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(CODEUNIT::"SCM Prod Order Qty Rounding");
+    end;
+
+    local procedure CreateComponentItemWithUOMQtyRoundingPrecision(var Item: Record Item; ItemRoundingPrecision: Decimal; UOMQtyRoundingPrecision: Decimal)
+    var
+        ItemUnitOfMeasure: Record "Item Unit of Measure";
+    begin
+        LibraryInventory.CreateItem(Item);
+        Item.Validate("Replenishment System", Item."Replenishment System"::Purchase);
+        Item.Validate("Rounding Precision", ItemRoundingPrecision);
+        Item.Modify(true);
+
+        // Set Qty. Rounding Precision on the Item's Base Unit of Measure
+        ItemUnitOfMeasure.Get(Item."No.", Item."Base Unit of Measure");
+        ItemUnitOfMeasure.Validate("Qty. Rounding Precision", UOMQtyRoundingPrecision);
+        ItemUnitOfMeasure.Modify(true);
+    end;
+
+    local procedure CreateFinishedGoodsItemWithBOM(var FinishedGoodsItem: Record Item; ComponentItem: Record Item; QuantityPer: Decimal)
+    var
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionBOMLine: Record "Production BOM Line";
+    begin
+        LibraryInventory.CreateItem(FinishedGoodsItem);
+        FinishedGoodsItem.Validate("Replenishment System", FinishedGoodsItem."Replenishment System"::"Prod. Order");
+        FinishedGoodsItem.Validate("Rounding Precision", 1);
+        FinishedGoodsItem.Modify(true);
+
+        // Create Production BOM with component
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, FinishedGoodsItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, ComponentItem."No.", QuantityPer);
+        ProductionBOMHeader.Validate(Status, ProductionBOMHeader.Status::Certified);
+        ProductionBOMHeader.Modify(true);
+
+        FinishedGoodsItem.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        FinishedGoodsItem.Modify(true);
+    end;
+
+    local procedure FindProductionOrder(var ProductionOrder: Record "Production Order"; OrderStatus: Enum "Production Order Status"; ItemNo: Code[20])
+    begin
+        ProductionOrder.SetRange(Status, OrderStatus);
+        ProductionOrder.SetRange("Source Type", ProductionOrder."Source Type"::Item);
+        ProductionOrder.SetRange("Source No.", ItemNo);
+        ProductionOrder.FindFirst();
+    end;
+
+    local procedure FindProdOrderComponent(var ProdOrderComponent: Record "Prod. Order Component"; Status: Enum "Production Order Status"; ProdOrderNo: Code[20]; ItemNo: Code[20])
+    begin
+        ProdOrderComponent.SetRange(Status, Status);
+        ProdOrderComponent.SetRange("Prod. Order No.", ProdOrderNo);
+        ProdOrderComponent.SetRange("Item No.", ItemNo);
+        ProdOrderComponent.FindFirst();
+    end;
+
+    [MessageHandler]
+    [Scope('OnPrem')]
+    procedure ProdOrderCreatedMessageHandler(Message: Text[1024])
+    begin
+        // Simple handler to suppress message display
+    end;
+}

