+codeunit 99134909 "Reminder Due Date Update"
+{
+    // [FEATURE] [Reminder] [Due Date]
+    // Tests for verifying that reminder due date updates correctly when customer ledger entry due date changes
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    var
+        LibraryERM: Codeunit "Library - ERM";
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryInventory: Codeunit "Library - Inventory";
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        IsInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure ReminderDueDateUpdatesWhenCustLedgerDueDateChangesToEarlier()
+    var
+        Customer: Record Customer;
+        ReminderHeader: Record "Reminder Header";
+        ReminderLevel: Record "Reminder Level";
+        ReminderFinChargeEntry: Record "Reminder/Fin. Charge Entry";
+        CustLedgerEntry: Record "Cust. Ledger Entry";
+        SalesHeader: Record "Sales Header";
+        ReminderIssue: Codeunit "Reminder-Issue";
+        NoSeries: Codeunit "No. Series";
+        IssuedReminderNo: Code[20];
+        ReminderNo: Code[20];
+        InvoiceNo: Code[20];
+        InitialDueDate: Date;
+        EarlierDueDate: Date;
+    begin
+        // [SCENARIO] When customer ledger entry due date is changed to an earlier date, the reminder entry due date should also update
+        // Bug: The reminder's due date was NOT updated when the document's due date was moved backward (only forward updates worked)
+        Initialize();
+
+        // [GIVEN] A customer with reminder terms
+        CreateCustomerWithReminderTerms(Customer, ReminderLevel);
+
+        // [GIVEN] A posted sales invoice that is overdue
+        CreateAndPostSalesInvoiceWithDueDate(SalesHeader, Customer."No.", WorkDate() - LibraryRandom.RandInt(30));
+        InvoiceNo := GetLastPostedSalesInvoiceNo(Customer."No.");
+
+        // [GIVEN] Find the customer ledger entry for the invoice
+        FindCustLedgerEntry(CustLedgerEntry, Customer."No.", CustLedgerEntry."Document Type"::Invoice, InvoiceNo);
+        InitialDueDate := CustLedgerEntry."Due Date";
+
+        // [GIVEN] A reminder is created and issued for the customer
+        ReminderNo := CreateReminderForCustomer(Customer."No.", CalcDate(ReminderLevel."Grace Period", InitialDueDate) + 1);
+        ReminderHeader.Get(ReminderNo);
+        IssuedReminderNo := NoSeries.PeekNextNo(ReminderHeader."Issuing No. Series");
+        ReminderIssue.Set(ReminderHeader, false, ReminderHeader."Document Date");
+        LibraryERM.RunReminderIssue(ReminderIssue);
+
+        // [GIVEN] Verify the Reminder/Fin. Charge Entry exists and has the expected due date
+        FindReminderFinChargeEntry(ReminderFinChargeEntry, CustLedgerEntry."Entry No.");
+        Assert.AreNotEqual(0D, ReminderFinChargeEntry."Due Date", 'Reminder entry should have a due date');
+
+        // [WHEN] The customer ledger entry due date is changed to an earlier date than the current reminder due date
+        EarlierDueDate := ReminderFinChargeEntry."Due Date" - LibraryRandom.RandIntInRange(5, 10);
+        CustLedgerEntry.Get(CustLedgerEntry."Entry No.");
+        CustLedgerEntry.Validate("Due Date", EarlierDueDate);
+        CustLedgerEntry.Modify(true);
+
+        // [THEN] The Reminder/Fin. Charge Entry due date should be updated to the new earlier date
+        ReminderFinChargeEntry.Get(ReminderFinChargeEntry."Entry No.");
+        Assert.AreEqual(
+            EarlierDueDate,
+            ReminderFinChargeEntry."Due Date",
+            'Reminder entry due date should be updated to the earlier date');
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure ReminderDueDateUpdatesWhenCustLedgerDueDateChangesToLater()
+    var
+        Customer: Record Customer;
+        ReminderHeader: Record "Reminder Header";
+        ReminderLevel: Record "Reminder Level";
+        ReminderFinChargeEntry: Record "Reminder/Fin. Charge Entry";
+        CustLedgerEntry: Record "Cust. Ledger Entry";
+        SalesHeader: Record "Sales Header";
+        ReminderIssue: Codeunit "Reminder-Issue";
+        NoSeries: Codeunit "No. Series";
+        IssuedReminderNo: Code[20];
+        ReminderNo: Code[20];
+        InvoiceNo: Code[20];
+        InitialDueDate: Date;
+        LaterDueDate: Date;
+    begin
+        // [SCENARIO] When customer ledger entry due date is changed to a later date, the reminder entry due date should also update
+        Initialize();
+
+        // [GIVEN] A customer with reminder terms
+        CreateCustomerWithReminderTerms(Customer, ReminderLevel);
+
+        // [GIVEN] A posted sales invoice that is overdue
+        CreateAndPostSalesInvoiceWithDueDate(SalesHeader, Customer."No.", WorkDate() - LibraryRandom.RandInt(30));
+        InvoiceNo := GetLastPostedSalesInvoiceNo(Customer."No.");
+
+        // [GIVEN] Find the customer ledger entry for the invoice
+        FindCustLedgerEntry(CustLedgerEntry, Customer."No.", CustLedgerEntry."Document Type"::Invoice, InvoiceNo);
+        InitialDueDate := CustLedgerEntry."Due Date";
+
+        // [GIVEN] A reminder is created and issued for the customer
+        ReminderNo := CreateReminderForCustomer(Customer."No.", CalcDate(ReminderLevel."Grace Period", InitialDueDate) + 1);
+        ReminderHeader.Get(ReminderNo);
+        IssuedReminderNo := NoSeries.PeekNextNo(ReminderHeader."Issuing No. Series");
+        ReminderIssue.Set(ReminderHeader, false, ReminderHeader."Document Date");
+        LibraryERM.RunReminderIssue(ReminderIssue);
+
+        // [GIVEN] Verify the Reminder/Fin. Charge Entry exists
+        FindReminderFinChargeEntry(ReminderFinChargeEntry, CustLedgerEntry."Entry No.");
+        Assert.AreNotEqual(0D, ReminderFinChargeEntry."Due Date", 'Reminder entry should have a due date');
+
+        // [WHEN] The customer ledger entry due date is changed to a later date
+        LaterDueDate := ReminderFinChargeEntry."Due Date" + LibraryRandom.RandIntInRange(5, 10);
+        CustLedgerEntry.Get(CustLedgerEntry."Entry No.");
+        CustLedgerEntry.Validate("Due Date", LaterDueDate);
+        CustLedgerEntry.Modify(true);
+
+        // [THEN] The Reminder/Fin. Charge Entry due date should be updated to the new later date
+        ReminderFinChargeEntry.Get(ReminderFinChargeEntry."Entry No.");
+        Assert.AreEqual(
+            LaterDueDate,
+            ReminderFinChargeEntry."Due Date",
+            'Reminder entry due date should be updated to the later date');
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"Reminder Due Date Update");
+
+        if IsInitialized then
+            exit;
+
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"Reminder Due Date Update");
+
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.CreateGeneralPostingSetupData();
+        LibraryERMCountryData.UpdateJournalTemplMandatory(false);
+
+        IsInitialized := true;
+        Commit();
+
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"Reminder Due Date Update");
+    end;
+
+    local procedure CreateCustomerWithReminderTerms(var Customer: Record Customer; var ReminderLevel: Record "Reminder Level")
+    var
+        ReminderTerms: Record "Reminder Terms";
+    begin
+        // Create reminder terms with one level
+        LibraryERM.CreateReminderTerms(ReminderTerms);
+        LibraryERM.CreateReminderLevel(ReminderLevel, ReminderTerms.Code);
+        Evaluate(ReminderLevel."Grace Period", '<' + Format(LibraryRandom.RandInt(5)) + 'D>');
+        Evaluate(ReminderLevel."Due Date Calculation", '<' + Format(LibraryRandom.RandInt(10)) + 'D>');
+        ReminderLevel.Modify(true);
+
+        // Create customer with reminder terms
+        LibrarySales.CreateCustomer(Customer);
+        Customer.Validate("Reminder Terms Code", ReminderTerms.Code);
+        Customer.Modify(true);
+    end;
+
+    local procedure CreateAndPostSalesInvoiceWithDueDate(var SalesHeader: Record "Sales Header"; CustomerNo: Code[20]; DueDate: Date)
+    var
+        SalesLine: Record "Sales Line";
+        Item: Record Item;
+    begin
+        LibraryInventory.CreateItemWithUnitPriceAndUnitCost(Item, LibraryRandom.RandDec(100, 2), LibraryRandom.RandDec(100, 2));
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Invoice, CustomerNo);
+        SalesHeader.Validate("Due Date", DueDate);
+        SalesHeader.Modify(true);
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, Item."No.", LibraryRandom.RandInt(10));
+        LibrarySales.PostSalesDocument(SalesHeader, true, true);
+    end;
+
+    local procedure GetLastPostedSalesInvoiceNo(CustomerNo: Code[20]): Code[20]
+    var
+        SalesInvoiceHeader: Record "Sales Invoice Header";
+    begin
+        SalesInvoiceHeader.SetRange("Sell-to Customer No.", CustomerNo);
+        SalesInvoiceHeader.FindLast();
+        exit(SalesInvoiceHeader."No.");
+    end;
+
+    local procedure FindCustLedgerEntry(var CustLedgerEntry: Record "Cust. Ledger Entry"; CustomerNo: Code[20]; DocumentType: Enum "Gen. Journal Document Type"; DocumentNo: Code[20])
+    begin
+        CustLedgerEntry.SetRange("Customer No.", CustomerNo);
+        CustLedgerEntry.SetRange("Document Type", DocumentType);
+        CustLedgerEntry.SetRange("Document No.", DocumentNo);
+        CustLedgerEntry.FindFirst();
+    end;
+
+    local procedure CreateReminderForCustomer(CustomerNo: Code[20]; DocumentDate: Date): Code[20]
+    var
+        Customer: Record Customer;
+        ReminderHeader: Record "Reminder Header";
+        CreateReminders: Report "Create Reminders";
+    begin
+        Clear(CreateReminders);
+        Customer.SetRange("No.", CustomerNo);
+        CreateReminders.SetTableView(Customer);
+        CreateReminders.InitializeRequest(DocumentDate, DocumentDate, false, false, false);
+        CreateReminders.UseRequestPage(false);
+        CreateReminders.Run();
+
+        ReminderHeader.SetRange("Customer No.", CustomerNo);
+        ReminderHeader.SetRange("Document Date", DocumentDate);
+        ReminderHeader.FindLast();
+        exit(ReminderHeader."No.");
+    end;
+
+    local procedure FindReminderFinChargeEntry(var ReminderFinChargeEntry: Record "Reminder/Fin. Charge Entry"; CustLedgerEntryNo: Integer)
+    begin
+        ReminderFinChargeEntry.SetCurrentKey("Customer Entry No.", Type);
+        ReminderFinChargeEntry.SetRange("Customer Entry No.", CustLedgerEntryNo);
+        ReminderFinChargeEntry.SetRange(Type, ReminderFinChargeEntry.Type::Reminder);
+        ReminderFinChargeEntry.FindLast();
+    end;
+}

