@@ -0,0 +1,115 @@
+codeunit 134936 "Purchase Journal Vendor Name"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Purchase Journal] [Vendor Name]
+    end;
+
+    var
+        LibraryPurchase: Codeunit "Library - Purchase";
+        LibraryERM: Codeunit "Library - ERM";
+        Assert: Codeunit Assert;
+        GenJnlManagement: Codeunit GenJnlManagement;
+        IsInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure VendorNameIsBlankWhenAccountTypeIsGLAccount()
+    var
+        GenJournalTemplate: Record "Gen. Journal Template";
+        GenJournalBatch: Record "Gen. Journal Batch";
+        GenJournalLine: Record "Gen. Journal Line";
+        GLAccount: Record "G/L Account";
+        PurchaseJournal: TestPage "Purchase Journal";
+    begin
+        // [FEATURE] [Purchase Journal] [Vendor Name]
+        // [SCENARIO] Vendor Name field should be blank when Account Type is G/L Account on Purchase Journal page
+        Initialize();
+
+        // [GIVEN] Clean journal setup
+        GenJournalTemplate.DeleteAll();
+        GenJournalBatch.DeleteAll();
+
+        // [GIVEN] A G/L Account with a name
+        LibraryERM.CreateGLAccount(GLAccount);
+        GLAccount.Name := 'Test GL Account Name';
+        GLAccount.Modify();
+
+        // [GIVEN] Set Purchase Journal to show more columns mode
+        GenJnlManagement.SetJournalSimplePageModePreference(false, PAGE::"Purchase Journal");
+
+        // [WHEN] User opens Purchase Journal and enters a line with Account Type = G/L Account
+        PurchaseJournal.OpenEdit();
+        PurchaseJournal."Account Type".SetValue(GenJournalLine."Account Type"::"G/L Account");
+        PurchaseJournal."Account No.".SetValue(GLAccount."No.");
+
+        // [THEN] The Description field shows the G/L Account name
+        Assert.AreEqual(GLAccount.Name, PurchaseJournal.Description.Value(), 'Description should be populated with G/L Account name');
+
+        // [THEN] The Vendor Name field should be blank since this is a G/L Account, not a Vendor
+        Assert.AreEqual('', PurchaseJournal."<Vendor Name>".Value(), 'Vendor Name should be blank when Account Type is G/L Account');
+
+        PurchaseJournal.Close();
+
+        // Reset to default mode
+        GenJnlManagement.SetJournalSimplePageModePreference(true, PAGE::"Purchase Journal");
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure VendorNameIsPopulatedWhenAccountTypeIsVendor()
+    var
+        GenJournalTemplate: Record "Gen. Journal Template";
+        GenJournalBatch: Record "Gen. Journal Batch";
+        GenJournalLine: Record "Gen. Journal Line";
+        Vendor: Record Vendor;
+        PurchaseJournal: TestPage "Purchase Journal";
+    begin
+        // [FEATURE] [Purchase Journal] [Vendor Name]
+        // [SCENARIO] Vendor Name field should show vendor name when Account Type is Vendor on Purchase Journal page
+        Initialize();
