diff --git a/test/ERMSalesBatchPostCurrencyTest.Codeunit.al b/test/ERMSalesBatchPostCurrencyTest.Codeunit.al
new file mode 100644
index 00000000..cb6fdedb
--- /dev/null
+++ b/test/ERMSalesBatchPostCurrencyTest.Codeunit.al
@@ -0,0 +1,189 @@
+codeunit 136234 "ERM Sales Batch Post Curr.Test"
+{
+    // [FEATURE] [Batch Post] [Sales] [Currency]
+    // Test verifies that batch posting sales invoice with currency code and replace posting date
+    // preserves line amounts and does not trigger line recreation.
+
+    Subtype = Test;
+    TestPermissions = NonRestrictive;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryERM: Codeunit "Library - ERM";
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryVariableStorage: Codeunit "Library - Variable Storage";
+        LibrarySetupStorage: Codeunit "Library - Setup Storage";
+        isInitialized: Boolean;
+
+    [Test]
+    [HandlerFunctions('RequestPageHandlerBatchPostSalesInvoices,MessageHandler')]
+    [Scope('OnPrem')]
+    procedure BatchPostSalesInvoiceWithCurrencyAndReplacePostingDatePreservesLineAmounts()
+    var
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        SalesInvoiceHeader: Record "Sales Invoice Header";
+        SalesInvoiceLine: Record "Sales Invoice Line";
+        Item: Record Item;
+        Customer: Record Customer;
+        CurrencyCode: Code[10];
+        OriginalUnitPrice: Decimal;
+        OriginalLineAmount: Decimal;
+        OriginalQuantity: Decimal;
+        NewPostingDate: Date;
+        LibraryJobQueue: Codeunit "Library - Job Queue";
+    begin
+        // [SCENARIO] Batch Posting of Sales Invoice with Currency Code and Replace Posting Date option
+        // should preserve line amounts without triggering line recreation.
+        // This tests the fix for issue where validating Currency Code during batch posting
+        // caused RecreateSalesLines to be called because xRec was not properly initialized.
+        Initialize();
+        LibrarySales.SetPostWithJobQueue(true);
+        BindSubscription(LibraryJobQueue);
+        LibraryJobQueue.SetDoNotHandleCodeunitJobQueueEnqueueEvent(true);
+
+        // [GIVEN] A currency with exchange rates for both original and new posting dates
+        CurrencyCode := CreateCurrencyWithMultipleDateExchangeRates();
+
+        // [GIVEN] A sales invoice with currency code and specific line amounts
+        LibrarySales.CreateCustomer(Customer);
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Invoice, Customer."No.");
+        SalesHeader.SetHideValidationDialog(true);
+        SalesHeader.Validate("Currency Code", CurrencyCode);
+        SalesHeader.SetHideValidationDialog(false);
+        SalesHeader.Modify(true);
+
+        LibraryInventory.CreateItem(Item);
+        OriginalQuantity := LibraryRandom.RandIntInRange(5, 10);
+        OriginalUnitPrice := LibraryRandom.RandDecInRange(100, 500, 2);
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, Item."No.", OriginalQuantity);
+        SalesLine.Validate("Unit Price", OriginalUnitPrice);
+        SalesLine.Modify(true);
+
+        OriginalLineAmount := SalesLine."Line Amount";
+
+        // [GIVEN] A new posting date different from the original
+        NewPostingDate := CalcDate('<1M>', SalesHeader."Posting Date");
+
+        // [WHEN] Batch post the sales invoice with Replace Posting Date option
+        RunBatchPostSalesInvoice(SalesHeader."No.", NewPostingDate);
+        LibraryJobQueue.FindAndRunJobQueueEntryByRecordId(SalesHeader.RecordId);
+
+        // [THEN] The posted sales invoice exists with the new posting date
+        SalesInvoiceHeader.SetRange("Pre-Assigned No.", SalesHeader."No.");
+        SalesInvoiceHeader.FindFirst();
+        Assert.AreEqual(NewPostingDate, SalesInvoiceHeader."Posting Date", 'Posting date should be replaced with new date.');
+
+        // [THEN] The posted sales invoice line preserves the original amounts
+        SalesInvoiceLine.SetRange("Document No.", SalesInvoiceHeader."No.");
+        SalesInvoiceLine.FindFirst();
+        Assert.AreEqual(OriginalQuantity, SalesInvoiceLine.Quantity, 'Line quantity should be preserved.');
+        Assert.AreEqual(OriginalUnitPrice, SalesInvoiceLine."Unit Price", 'Line unit price should be preserved and not recalculated.');
+        Assert.AreEqual(OriginalLineAmount, SalesInvoiceLine."Line Amount", 'Line amount should be preserved and not recalculated.');
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"ERM Sales Batch Post Curr.Test");
+        LibraryVariableStorage.Clear();
+        LibrarySetupStorage.Restore();
+
+        if isInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"ERM Sales Batch Post Curr.Test");
+
+        LibraryERMCountryData.UpdateSalesReceivablesSetup();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        isInitialized := true;
+        LibrarySetupStorage.SaveGeneralLedgerSetup();
+        LibrarySetupStorage.SaveSalesSetup();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"ERM Sales Batch Post Curr.Test");
+    end;
+
+    local procedure CreateCurrencyWithMultipleDateExchangeRates(): Code[10]
+    var
+        Currency: Record Currency;
+        CurrencyExchangeRate: Record "Currency Exchange Rate";
+        GLAccount: Record "G/L Account";
+        ExchRateAmt: Decimal;
+        FutureDate: Date;
+    begin
+        // Create currency with exchange rates for workdate and a future date
+        LibraryERM.CreateCurrency(Currency);
+
+        // Create residual gains/losses accounts
+        LibraryERM.CreateGLAccount(GLAccount);
+        Currency.Validate("Residual Gains Account", GLAccount."No.");
+        LibraryERM.CreateGLAccount(GLAccount);
+        Currency.Validate("Residual Losses Account", GLAccount."No.");
+        LibraryERM.CreateGLAccount(GLAccount);
+        Currency.Validate("Realized Gains Acc.", GLAccount."No.");
+        LibraryERM.CreateGLAccount(GLAccount);
+        Currency.Validate("Realized Losses Acc.", GLAccount."No.");
+        Currency.Modify(true);
+
+        ExchRateAmt := LibraryRandom.RandDecInRange(1, 2, 2);
+
+        // Create exchange rate for current work date
+        LibraryERM.CreateExchangeRate(Currency.Code, WorkDate(), ExchRateAmt, ExchRateAmt);
+
+        // Create exchange rate for future date (1 month ahead) - slightly different rate
+        FutureDate := CalcDate('<1M>', WorkDate());
+        LibraryERM.CreateExchangeRate(Currency.Code, FutureDate, ExchRateAmt * 1.05, ExchRateAmt * 1.05);
+
+        exit(Currency.Code);
+    end;
+
+    local procedure RunBatchPostSalesInvoice(DocumentNo: Text; PostingDate: Date)
+    var
+        SalesHeader: Record "Sales Header";
+    begin
+        UpdateCalcInvDiscSalesReceivablesSetup(false);
+        LibraryVariableStorage.Enqueue(DocumentNo);
+        LibraryVariableStorage.Enqueue(PostingDate);
+
+        Commit();
+        Report.RunModal(Report::"Batch Post Sales Invoices", true, true, SalesHeader);
+    end;
+
+    local procedure UpdateCalcInvDiscSalesReceivablesSetup(CalcInvDisc: Boolean)
+    var
+        SalesReceivablesSetup: Record "Sales & Receivables Setup";
+    begin
+        SalesReceivablesSetup.Get();
+        SalesReceivablesSetup.Validate("Calc. Inv. Discount", CalcInvDisc);
+        SalesReceivablesSetup.Modify(true);
+    end;
+
+    [RequestPageHandler]
+    [Scope('OnPrem')]
+    procedure RequestPageHandlerBatchPostSalesInvoices(var BatchPostSalesInvoices: TestRequestPage "Batch Post Sales Invoices")
+    var
+        SalesHeader: Record "Sales Header";
+        DocumentNoFilter: Variant;
+        PostingDate: Variant;
+    begin
+        LibraryVariableStorage.Dequeue(DocumentNoFilter);
+        LibraryVariableStorage.Dequeue(PostingDate);
+
+        BatchPostSalesInvoices."Sales Header".SetFilter("No.", DocumentNoFilter);
+        BatchPostSalesInvoices."Sales Header".SetFilter("Document Type", Format(SalesHeader."Document Type"::Invoice));
+
+        BatchPostSalesInvoices.PostingDate.SetValue(PostingDate);
+        BatchPostSalesInvoices.ReplaceDocumentDate.SetValue(true);
+        BatchPostSalesInvoices.ReplacePostingDate.SetValue(true);
+        BatchPostSalesInvoices.OK().Invoke();
+    end;
+
+    [MessageHandler]
+    [Scope('OnPrem')]
+    procedure MessageHandler(Message: Text[1024])
+    begin
+        // Handle any messages during batch posting
+    end;
+}

diff --git a/App/Layers/W1/Tests/SCM/SCMInvtPickRounding.Codeunit.al b/App/Layers/W1/Tests/SCM/SCMInvtPickRounding.Codeunit.al
new file mode 100644
index 00000000..1a277acc
--- /dev/null
+++ b/App/Layers/W1/Tests/SCM/SCMInvtPickRounding.Codeunit.al
@@ -0,0 +1,237 @@
+codeunit 137832 "SCM Invt. Pick Rounding"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Warehouse] [Inventory Pick] [FEFO] [Rounding]
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryUtility: Codeunit "Library - Utility";
+        LibraryRandom: Codeunit "Library - Random";
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure InvtPickFEFOMultipleLotsBinsNoRoundingError()
+    var
+        Item: Record Item;
+        ItemTrackingCode: Record "Item Tracking Code";
+        Location: Record Location;
+        Bin: array[3] of Record Bin;
+        BinContent: array[3] of Record "Bin Content";
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        WarehouseRequest: Record "Warehouse Request";
+        WarehouseActivityLine: Record "Warehouse Activity Line";
+        ItemUnitOfMeasure: Record "Item Unit of Measure";
+        QtyPerUOM: Decimal;
+        SalesQty: Decimal;
+        TotalPickQty: Decimal;
+        i: Integer;
+    begin
+        // [SCENARIO] Creating inventory pick with FEFO from multiple lots/bins with fractional UOM should not have rounding errors
+        // [GIVEN] Location with Require Pick = Yes and Pick According to FEFO = Yes
+        CreateInventoryPickLocationWithFEFO(Location);
+
+        // [GIVEN] Item with lot tracking requiring expiration date
+        CreateItemTrackingCodeWithExpiration(ItemTrackingCode);
+        CreateItemWithLotTracking(Item, ItemTrackingCode.Code);
+
+        // [GIVEN] Non-base UOM with fractional Qty per UOM (2.888)
+        QtyPerUOM := 2.888;
+        CreateItemUnitOfMeasure(ItemUnitOfMeasure, Item."No.", QtyPerUOM, 0.00001);
+
+        // [GIVEN] Multiple bins at location
+        for i := 1 to 3 do begin
+            CreateBin(Bin[i], Location.Code);
+            CreateBinContent(BinContent[i], Location.Code, Bin[i].Code, Item."No.");
+        end;
+
+        // [GIVEN] Inventory distributed across bins with different lots and expiration dates
+        // These quantities are designed to cause rounding issues when picked according to FEFO
+        // Bin 1: LOT01 (later exp), LOT03 (earlier exp), LOT06 (earlier exp)
+        CreateInventoryForLot(BinContent[1], 'LOT01', 434.97616, CalcDate('<2M>', WorkDate()));
+        CreateInventoryForLot(BinContent[1], 'LOT03', 17.3126, CalcDate('<-1M>', WorkDate()));
+        CreateInventoryForLot(BinContent[1], 'LOT06', 17.0373, CalcDate('<-1M>', WorkDate()));
+
+        // Bin 2: LOT01 (earlier exp), LOT02 (later exp), LOT03 (earlier exp), LOT04 (earliest exp)
+        CreateInventoryForLot(BinContent[2], 'LOT01', 4.13394, CalcDate('<-1M>', WorkDate()));
+        CreateInventoryForLot(BinContent[2], 'LOT02', 4.34355, CalcDate('<2M>', WorkDate()));
+        CreateInventoryForLot(BinContent[2], 'LOT03', 151.33333, CalcDate('<-1M>', WorkDate()));
+        CreateInventoryForLot(BinContent[2], 'LOT04', 40.01221, CalcDate('<-3M>', WorkDate()));
+
+        // Bin 3: LOT02 (earliest exp), LOT03 (earlier exp), LOT05 (middle exp)
+        CreateInventoryForLot(BinContent[3], 'LOT02', 1.78787, CalcDate('<-4M>', WorkDate()));
+        CreateInventoryForLot(BinContent[3], 'LOT03', 42.73313, CalcDate('<-1M>', WorkDate()));
+        CreateInventoryForLot(BinContent[3], 'LOT05', 4.013, CalcDate('<-2M>', WorkDate()));
+
+        // [GIVEN] Sales order for quantity that will span multiple lots when picked by FEFO
+        SalesQty := 248;
+        CreateSalesOrderWithUOM(SalesHeader, SalesLine, Item."No.", Location.Code, SalesQty, ItemUnitOfMeasure.Code, QtyPerUOM);
+
+        // Create warehouse request for the sales order
+        CreateWarehouseRequest(WarehouseRequest, SalesLine);
+
+        // [WHEN] Create inventory pick
+        CreateInventoryPickFromWarehouseRequest(WarehouseRequest);
+
+        // [THEN] Total pick quantity equals sales order quantity (no rounding error)
+        WarehouseActivityLine.Reset();
+        WarehouseActivityLine.SetRange("Activity Type", WarehouseActivityLine."Activity Type"::"Invt. Pick");
+        WarehouseActivityLine.SetRange("Item No.", Item."No.");
+        WarehouseActivityLine.CalcSums(Quantity);
+        TotalPickQty := WarehouseActivityLine.Quantity;
+
+        Assert.AreEqual(SalesQty, TotalPickQty,
+            'Total pick quantity should equal sales order quantity without rounding errors');
+    end;
+
+    local procedure CreateInventoryPickLocationWithFEFO(var Location: Record Location)
+    begin
+        Location.Init();
+        Location.Code := LibraryUtility.GenerateGUID();
+        Location."Bin Mandatory" := true;
+        Location."Require Pick" := true;
+        Location."Pick According to FEFO" := true;
+        Location.Insert();
+    end;
+
+    local procedure CreateItemTrackingCodeWithExpiration(var ItemTrackingCode: Record "Item Tracking Code")
+    begin
+        ItemTrackingCode.Init();
+        ItemTrackingCode.Code := LibraryUtility.GenerateGUID();
+        ItemTrackingCode."Lot Specific Tracking" := true;
+        ItemTrackingCode."Lot Warehouse Tracking" := true;
+        ItemTrackingCode."Man. Expir. Date Entry Reqd." := true;
+        ItemTrackingCode."Use Expiration Dates" := true;
+        ItemTrackingCode.Insert();
+    end;
+
+    local procedure CreateItemWithLotTracking(var Item: Record Item; ItemTrackingCodeCode: Code[10])
+    begin
+        Item.Init();
+        Item."No." := LibraryUtility.GenerateGUID();
+        Item."Item Tracking Code" := ItemTrackingCodeCode;
+        Item.Insert();
+    end;
+
+    local procedure CreateItemUnitOfMeasure(var ItemUnitOfMeasure: Record "Item Unit of Measure"; ItemNo: Code[20]; QtyPerUOM: Decimal; QtyRoundingPrecision: Decimal)
+    var
+        UnitOfMeasure: Record "Unit of Measure";
+    begin
+        UnitOfMeasure.Init();
+        UnitOfMeasure.Code := LibraryUtility.GenerateGUID();
+        UnitOfMeasure.Insert();
+
+        ItemUnitOfMeasure.Init();
+        ItemUnitOfMeasure."Item No." := ItemNo;
+        ItemUnitOfMeasure.Code := UnitOfMeasure.Code;
+        ItemUnitOfMeasure."Qty. per Unit of Measure" := QtyPerUOM;
+        ItemUnitOfMeasure."Qty. Rounding Precision" := QtyRoundingPrecision;
+        ItemUnitOfMeasure.Insert();
+    end;
+
+    local procedure CreateBin(var Bin: Record Bin; LocationCode: Code[10])
+    begin
+        Bin.Init();
+        Bin."Location Code" := LocationCode;
+        Bin.Code := LibraryUtility.GenerateGUID();
+        Bin.Insert();
+    end;
+
+    local procedure CreateBinContent(var BinContent: Record "Bin Content"; LocationCode: Code[10]; BinCode: Code[20]; ItemNo: Code[20])
+    begin
+        BinContent.Init();
+        BinContent."Location Code" := LocationCode;
+        BinContent."Bin Code" := BinCode;
+        BinContent."Item No." := ItemNo;
+        BinContent.Insert();
+    end;
+
+    local procedure CreateInventoryForLot(BinContent: Record "Bin Content"; LotNo: Code[20]; Quantity: Decimal; ExpirationDate: Date)
+    var
+        WarehouseEntry: Record "Warehouse Entry";
+        WarehouseEntry2: Record "Warehouse Entry";
+        ItemLedgerEntry: Record "Item Ledger Entry";
+        ItemLedgerEntry2: Record "Item Ledger Entry";
+    begin
+        if WarehouseEntry2.FindLast() then;
+        WarehouseEntry.Init();
+        WarehouseEntry."Entry No." := WarehouseEntry2."Entry No." + 1;
+        WarehouseEntry."Location Code" := BinContent."Location Code";
+        WarehouseEntry."Bin Code" := BinContent."Bin Code";
+        WarehouseEntry."Item No." := BinContent."Item No.";
+        WarehouseEntry."Lot No." := LotNo;
+        WarehouseEntry.Quantity := Quantity;
+        WarehouseEntry."Qty. (Base)" := Quantity;
+        WarehouseEntry."Expiration Date" := ExpirationDate;
+        WarehouseEntry.Insert();
+
+        if ItemLedgerEntry2.FindLast() then;
+        ItemLedgerEntry.Init();
+        ItemLedgerEntry."Entry No." := ItemLedgerEntry2."Entry No." + 1;
+        ItemLedgerEntry."Item No." := BinContent."Item No.";
+        ItemLedgerEntry."Location Code" := BinContent."Location Code";
+        ItemLedgerEntry."Lot No." := LotNo;
+        ItemLedgerEntry.Quantity := Quantity;
+        ItemLedgerEntry.Positive := ItemLedgerEntry.Quantity > 0;
+        ItemLedgerEntry."Expiration Date" := ExpirationDate;
+        ItemLedgerEntry.Open := true;
+        ItemLedgerEntry."Remaining Quantity" := ItemLedgerEntry.Quantity;
+        ItemLedgerEntry.Insert();
+    end;
+
+    local procedure CreateSalesOrderWithUOM(var SalesHeader: Record "Sales Header"; var SalesLine: Record "Sales Line"; ItemNo: Code[20]; LocationCode: Code[10]; Quantity: Decimal; UOMCode: Code[10]; QtyPerUOM: Decimal)
+    begin
+        SalesHeader.Init();
+        SalesHeader."Document Type" := SalesHeader."Document Type"::Order;
+        SalesHeader."No." := LibraryUtility.GenerateGUID();
+        SalesHeader.Insert();
+
+        SalesLine.Init();
+        SalesLine."Document Type" := SalesHeader."Document Type";
+        SalesLine."Document No." := SalesHeader."No.";
+        SalesLine."Line No." := 10000;
+        SalesLine.Type := SalesLine.Type::Item;
+        SalesLine."No." := ItemNo;
+        SalesLine."Location Code" := LocationCode;
+        SalesLine."Unit of Measure Code" := UOMCode;
+        SalesLine."Qty. per Unit of Measure" := QtyPerUOM;
+        SalesLine."Qty. Rounding Precision" := 0.00001;
+        SalesLine.Quantity := Quantity;
+        SalesLine."Outstanding Quantity" := Quantity;
+        SalesLine."Qty. to Ship" := Quantity;
+        SalesLine."Quantity (Base)" := Round(Quantity * QtyPerUOM, 0.00001);
+        SalesLine."Outstanding Qty. (Base)" := SalesLine."Quantity (Base)";
+        SalesLine."Qty. to Ship (Base)" := SalesLine."Quantity (Base)";
+        SalesLine.Insert();
+    end;
+
+    local procedure CreateWarehouseRequest(var WarehouseRequest: Record "Warehouse Request"; SalesLine: Record "Sales Line")
+    begin
+        WarehouseRequest.Init();
+        WarehouseRequest.Type := WarehouseRequest.Type::Outbound;
+        WarehouseRequest."Location Code" := SalesLine."Location Code";
+        WarehouseRequest."Source Type" := DATABASE::"Sales Line";
+        WarehouseRequest."Source Subtype" := SalesLine."Document Type".AsInteger();
+        WarehouseRequest."Source No." := SalesLine."Document No.";
+        WarehouseRequest."Source Document" := WarehouseRequest."Source Document"::"Sales Order";
+        WarehouseRequest.Insert();
+    end;
+
+    local procedure CreateInventoryPickFromWarehouseRequest(WarehouseRequest: Record "Warehouse Request")
+    var
+        WarehouseActivityHeader: Record "Warehouse Activity Header";
+        CreateInventoryPickMovement: Codeunit "Create Inventory Pick/Movement";
+    begin
+        WarehouseActivityHeader.Type := WarehouseActivityHeader.Type::"Invt. Pick";
+        WarehouseActivityHeader."Location Code" := WarehouseRequest."Location Code";
+
+        CreateInventoryPickMovement.SetWhseRequest(WarehouseRequest, true);
+        CreateInventoryPickMovement.CheckSourceDoc(WarehouseRequest);
+        CreateInventoryPickMovement.AutoCreatePickOrMove(WarehouseActivityHeader);
+    end;
+}

diff --git a/App/Layers/W1/Tests/SCM/SCMKittingCostSharesTree.Codeunit.al b/App/Layers/W1/Tests/SCM/SCMKittingCostSharesTree.Codeunit.al
