+        ParentItem.Validate("Replenishment System", ParentItem."Replenishment System"::"Prod. Order");
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, ParentItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(ProductionBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, ChildItem."No.", QuantityPer);
+        LibraryManufacturing.UpdateProductionBOMStatus(ProductionBOMHeader, ProductionBOMHeader.Status::Certified);
+        ParentItem.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        ParentItem.Modify(true);
+
+        // [WHEN] Calculate BOM tree for the parent item (child has empty BOM)
+        ParentItemFilter.SetRange("No.", ParentItem."No.");
+        CalculateBOMTree.GenerateTreeForItems(ParentItemFilter, BOMBufferWithEmptyBOM, TreeType::Cost);
+
+        // [THEN] Find the child item in the BOM buffer and get its Rolled-up Capacity Cost
+        BOMBufferWithEmptyBOM.SetRange(Type, BOMBufferWithEmptyBOM.Type::Item);
+        BOMBufferWithEmptyBOM.SetRange("No.", ChildItem."No.");
+        BOMBufferWithEmptyBOM.FindFirst();
+        RolledUpCapCostWithEmptyBOM := BOMBufferWithEmptyBOM."Rolled-up Capacity Cost";
+
+        // [GIVEN] Now remove the empty Production BOM from the child item (no BOM at all)
+        ChildItem.Validate("Production BOM No.", '');
+        ChildItem.Modify(true);
+
+        // [WHEN] Calculate BOM tree again
+        ParentItemFilter.SetRange("No.", ParentItem."No.");
+        CalculateBOMTree2.GenerateTreeForItems(ParentItemFilter, BOMBufferWithNoBOM, TreeType::Cost);
+
+        // [THEN] Find the child item in the BOM buffer and get its Rolled-up Capacity Cost
+        BOMBufferWithNoBOM.SetRange(Type, BOMBufferWithNoBOM.Type::Item);
+        BOMBufferWithNoBOM.SetRange("No.", ChildItem."No.");
+        BOMBufferWithNoBOM.FindFirst();
+        RolledUpCapCostWithNoBOM := BOMBufferWithNoBOM."Rolled-up Capacity Cost";
+
+        // [THEN] The Rolled-up Capacity Cost should be the same in both scenarios
+        Assert.AreEqual(
+            RolledUpCapCostWithEmptyBOM,
+            RolledUpCapCostWithNoBOM,
+            'Rolled-up Capacity Cost should be the same for empty BOM and no BOM');
+    end;
