+        ItemVariant: Record "Item Variant";
+        InventorySetup: Record "Inventory Setup";
+        TransferHeader: Record "Transfer Header";
+        TransferLine: Record "Transfer Line";
+        LocationFrom: Record Location;
+        LocationTo: Record Location;
+        LocationInTransit: Record Location;
+    begin
+        // [FEATURE] [Transfer Order] [Variant Mandatory]
+        // [SCENARIO] When "Variant Mandatory if Exists" is enabled and item has variants,
+        // releasing a transfer order with variant code should succeed
+
+        Initialize();
+
+        // [GIVEN] Inventory Setup with "Variant Mandatory if Exists" = true
+        InventorySetup.Get();
+        InventorySetup.Validate("Variant Mandatory if Exists", true);
+        InventorySetup.Modify(true);
+
+        // [GIVEN] An item with variants
+        LibraryInventory.CreateItem(Item);
+        LibraryInventory.CreateItemVariant(ItemVariant, Item."No.");
+
+        // [GIVEN] Transfer locations
+        LibraryWarehouse.CreateTransferLocations(LocationFrom, LocationTo, LocationInTransit);
+
+        // [GIVEN] A transfer order with a line that has a variant code
+        LibraryInventory.CreateTransferHeader(TransferHeader, LocationFrom.Code, LocationTo.Code, LocationInTransit.Code);
+        LibraryInventory.CreateTransferLine(TransferHeader, TransferLine, Item."No.", LibraryRandom.RandInt(10));
+        TransferLine.Validate("Variant Code", ItemVariant.Code);
+        TransferLine.Modify(true);
+
+        // [WHEN] The transfer order is released
+        LibraryWarehouse.ReleaseTransferOrder(TransferHeader);
+
+        // [THEN] The transfer order is released successfully
+        TransferHeader.Get(TransferHeader."No.");
+        Assert.AreEqual(TransferHeader.Status::Released, TransferHeader.Status, 'Transfer order should be released');
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure ReleaseTransferOrderSucceedsWhenVariantMandatoryDisabled()
+    var
+        Item: Record Item;
+        ItemVariant: Record "Item Variant";
+        InventorySetup: Record "Inventory Setup";
+        TransferHeader: Record "Transfer Header";
+        TransferLine: Record "Transfer Line";
+        LocationFrom: Record Location;
+        LocationTo: Record Location;
+        LocationInTransit: Record Location;
+    begin
+        // [FEATURE] [Transfer Order] [Variant Mandatory]
+        // [SCENARIO] When "Variant Mandatory if Exists" is disabled,
+        // releasing a transfer order without variant code should succeed even if item has variants
+
+        Initialize();
+
+        // [GIVEN] Inventory Setup with "Variant Mandatory if Exists" = false
+        InventorySetup.Get();
+        InventorySetup.Validate("Variant Mandatory if Exists", false);
+        InventorySetup.Modify(true);
+
+        // [GIVEN] An item with variants
+        LibraryInventory.CreateItem(Item);
+        LibraryInventory.CreateItemVariant(ItemVariant, Item."No.");
+
+        // [GIVEN] Transfer locations
+        LibraryWarehouse.CreateTransferLocations(LocationFrom, LocationTo, LocationInTransit);
+
+        // [GIVEN] A transfer order with a line that does not have a variant code
+        LibraryInventory.CreateTransferHeader(TransferHeader, LocationFrom.Code, LocationTo.Code, LocationInTransit.Code);
+        LibraryInventory.CreateTransferLine(TransferHeader, TransferLine, Item."No.", LibraryRandom.RandInt(10));
+
+        // [WHEN] The transfer order is released
+        LibraryWarehouse.ReleaseTransferOrder(TransferHeader);
+
+        // [THEN] The transfer order is released successfully
+        TransferHeader.Get(TransferHeader."No.");
+        Assert.AreEqual(TransferHeader.Status::Released, TransferHeader.Status, 'Transfer order should be released');
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"SCM Transfer Variant Mandatory");
+        LibrarySetupStorage.Restore();
+
+        if IsInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"SCM Transfer Variant Mandatory");
+
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        LibraryERMCountryData.UpdateInventoryPostingSetup();
+
+        LibrarySetupStorage.Save(Database::"Inventory Setup");
+
+        IsInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"SCM Transfer Variant Mandatory");
+    end;
+}

