+codeunit 136399 "Job Reservation Non Inv Item"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Reservation] [Job] [Non-Inventory Item]
+        IsInitialized := false;
+    end;
+
+    var
+        DummyJobsSetup: Record "Jobs Setup";
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryJob: Codeunit "Library - Job";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryPurchase: Codeunit "Library - Purchase";
+        LibraryRandom: Codeunit "Library - Random";
+        IsInitialized: Boolean;
+        NonInvReserveTypeErr: Label 'Non-inventory and service items cannot be reserved.';
+
+    [Test]
+    [HandlerFunctions('ReservationPageHandlerAutoReserve')]
+    [Scope('OnPrem')]
+    procedure ReserveServiceItemFromPurchaseToJobPlanningLineErrors()
+    var
+        Item: Record Item;
+        JobPlanningLine: Record "Job Planning Line";
+        PurchaseLine: Record "Purchase Line";
+    begin
+        // [SCENARIO] User cannot reserve a Service type item from purchase order to job planning line
+        // [GIVEN] A Service type item
+        Initialize();
+        LibraryInventory.CreateServiceTypeItem(Item);
+
+        // [GIVEN] A purchase order with the service item
+        CreatePurchaseDocumentWithItem(PurchaseLine, Item."No.");
+
+        // [GIVEN] A job planning line for the same item with Usage Link and Reserve = Optional
+        CreateJobAndPlanningLineWithItem(JobPlanningLine, Item."No.", PurchaseLine."Expected Receipt Date");
+
+        // [WHEN] Attempting to auto-reserve the purchase line to the job planning line
+        asserterror PurchaseLine.ShowReservation();
+
+        // [THEN] An error is thrown indicating non-inventory and service items cannot be reserved
+        Assert.ExpectedError(NonInvReserveTypeErr);
+    end;
+
+    [Test]
+    [HandlerFunctions('ReservationPageHandlerAutoReserve')]
+    [Scope('OnPrem')]
+    procedure ReserveNonInventoryItemFromPurchaseToJobPlanningLineErrors()
+    var
+        Item: Record Item;
+        JobPlanningLine: Record "Job Planning Line";
+        PurchaseLine: Record "Purchase Line";
+    begin
+        // [SCENARIO] User cannot reserve a Non-Inventory type item from purchase order to job planning line
+        // [GIVEN] A Non-Inventory type item
+        Initialize();
+        LibraryInventory.CreateNonInventoryTypeItem(Item);
+
+        // [GIVEN] A purchase order with the non-inventory item
+        CreatePurchaseDocumentWithItem(PurchaseLine, Item."No.");
+
+        // [GIVEN] A job planning line for the same item with Usage Link and Reserve = Optional
+        CreateJobAndPlanningLineWithItem(JobPlanningLine, Item."No.", PurchaseLine."Expected Receipt Date");
+
+        // [WHEN] Attempting to auto-reserve the purchase line to the job planning line
+        asserterror PurchaseLine.ShowReservation();
+
+        // [THEN] An error is thrown indicating non-inventory and service items cannot be reserved
+        Assert.ExpectedError(NonInvReserveTypeErr);
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(CODEUNIT::"Job Reservation Non Inv Item");
+
+        if IsInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(CODEUNIT::"Job Reservation Non Inv Item");
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+
+        DummyJobsSetup."Allow Sched/Contract Lines Def" := false;
+        DummyJobsSetup."Apply Usage Link by Default" := false;
+        DummyJobsSetup.Modify();
+
+        IsInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(CODEUNIT::"Job Reservation Non Inv Item");
+    end;
+
+    local procedure CreatePurchaseDocumentWithItem(var PurchaseLine: Record "Purchase Line"; ItemNo: Code[20])
+    var
+        PurchaseHeader: Record "Purchase Header";
+        Vendor: Record Vendor;
+    begin
+        LibraryPurchase.CreateVendor(Vendor);
+        LibraryPurchase.CreatePurchHeader(PurchaseHeader, PurchaseHeader."Document Type"::Order, Vendor."No.");
+        LibraryPurchase.CreatePurchaseLine(
+            PurchaseLine, PurchaseHeader, PurchaseLine.Type::Item, ItemNo, LibraryRandom.RandDecInRange(5, 10, 2));
+    end;
+
+    local procedure CreateJobAndPlanningLineWithItem(var JobPlanningLine: Record "Job Planning Line"; ItemNo: Code[20]; ExpectedReceiptDate: Date)
+    var
+        Job: Record Job;
+        JobTask: Record "Job Task";
+    begin
+        LibraryJob.CreateJob(Job);
+        LibraryJob.CreateJobTask(Job, JobTask);
+        LibraryJob.CreateJobPlanningLine(JobPlanningLine."Line Type"::Budget, LibraryJob.ItemType(), JobTask, JobPlanningLine);
+        JobPlanningLine.Validate("No.", ItemNo);
+        // Planning Date must be after Expected Receipt Date for reservation to be possible
+        JobPlanningLine.Validate("Planning Date", CalcDate('<' + Format(LibraryRandom.RandIntInRange(6, 10)) + 'M>', ExpectedReceiptDate));
+        JobPlanningLine.Validate("Usage Link", true);
+        JobPlanningLine.Validate(Quantity, LibraryRandom.RandDecInRange(1, 5, 2));
+        JobPlanningLine.Validate(Reserve, JobPlanningLine.Reserve::Optional);
+        JobPlanningLine.Modify(true);
+    end;
+
+    [ModalPageHandler]
+    [Scope('OnPrem')]
+    procedure ReservationPageHandlerAutoReserve(var Reservation: TestPage Reservation)
+    begin
+        Reservation."Auto Reserve".Invoke();
+        Reservation.OK().Invoke();
+    end;
+}

diff --git a/App/Layers/W1/Tests/SCM/SCMReservationTrackingQuantityUT.Codeunit.al b/App/Layers/W1/Tests/SCM/SCMReservationTrackingQuantityUT.Codeunit.al
new file mode 100644
index 00000000..9dc63cf4
--- /dev/null
+++ b/App/Layers/W1/Tests/SCM/SCMReservationTrackingQuantityUT.Codeunit.al
@@ -0,0 +1,197 @@
+codeunit 137822 "SCM Reserv. Tracking Qty UT"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Reservation] [Order Tracking] [SCM]
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryUtility: Codeunit "Library - Utility";
+        isInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure CalcReservationQuantitySumsTrackingEntries()
+    var
+        ReservationEntry: array[3] of Record "Reservation Entry";
+        SalesLine: Record "Sales Line";
+        QtyPerUoM: Decimal;
+        QtyBase1: Decimal;
+        QtyBase2: Decimal;
+        QtyBase3: Decimal;
+        TotalQtyBase: Decimal;
+        ExpectedTotalQty: Decimal;
+        ActualTotalQty: Decimal;
+    begin
+        // [FEATURE] [Reservation Entry] [Order Tracking]
+        // [SCENARIO] CalcReservationQuantity should include Tracking status entries when calculating quantity to avoid rounding errors
+        // This test reproduces issue where split tracking lines (each ending in x.xxxx7) would cause rounding errors
+        // when only Reservation status was considered, resulting in 12.00001 instead of 12
+        Initialize();
+
+        // [GIVEN] A UOM with 24 qty per UOM (e.g., CASE = 24 PCS)
+        QtyPerUoM := 24;
+
+        // [GIVEN] 3 quantities that when divided by 24 cause rounding issues:
+        // 13 / 24 = 0.541666...7, 137 / 24 = 5.708333...7, 138 / 24 = 5.75
+        // Total: 288 / 24 = 12 (exact)
+        // But if calculated individually and summed: 0.54167 + 5.70833 + 5.75 = 12.00000 (rounded correctly only when summed before division)
+        QtyBase1 := 13;
+        QtyBase2 := 137;
+        QtyBase3 := 138;
+        TotalQtyBase := QtyBase1 + QtyBase2 + QtyBase3; // 288
+        ExpectedTotalQty := TotalQtyBase / QtyPerUoM; // 12
+
+        // [GIVEN] A mock sales line as source
+        MockSalesLine(SalesLine);
+
+        // [GIVEN] First reservation entry with Tracking status and QtyBase1
+        CreateMockReservationEntry(
+            ReservationEntry[1], SalesLine, "Reservation Status"::Tracking, QtyPerUoM, -QtyBase1);
+
+        // [GIVEN] Second reservation entry with Tracking status and QtyBase2
+        CreateMockReservationEntry(
+            ReservationEntry[2], SalesLine, "Reservation Status"::Tracking, QtyPerUoM, -QtyBase2);
+
+        // [WHEN] Creating the third entry with Tracking status
+        // The CalcReservationQuantity procedure is called when validating "Quantity (Base)"
+        CreateMockReservationEntry(
+            ReservationEntry[3], SalesLine, "Reservation Status"::Tracking, QtyPerUoM, -QtyBase3);
+
+        // [THEN] The sum of Quantity across all entries should equal the expected total (12, not 12.00001)
+        ActualTotalQty := Abs(ReservationEntry[1].Quantity + ReservationEntry[2].Quantity + ReservationEntry[3].Quantity);
+        Assert.AreEqual(ExpectedTotalQty, ActualTotalQty,
+            'Sum of Quantity field should be 12 when considering all Tracking entries for rounding calculation');
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure CalcReservationQuantityIncludesTrackingNotJustReservation()
+    var
+        ReservationEntry1: Record "Reservation Entry";
+        ReservationEntry2: Record "Reservation Entry";
+        ReservationEntry3: Record "Reservation Entry";
+        SalesLine: Record "Sales Line";
+        QtyPerUoM: Decimal;
+        TotalQuantity: Decimal;
+    begin
+        // [FEATURE] [Reservation Entry] [Order Tracking]
+        // [SCENARIO] When validating Quantity (Base), CalcReservationQuantity must include Tracking status entries
+        // to properly calculate the Quantity field with correct rounding
+        Initialize();
+
+        // [GIVEN] A UOM with 24 qty per UOM
+        QtyPerUoM := 24;
+
+        // [GIVEN] A mock sales line
+        MockSalesLine(SalesLine);
+
+        // [GIVEN] First entry with Tracking status (not Reservation)
+        CreateMockReservationEntry(
+            ReservationEntry1, SalesLine, "Reservation Status"::Tracking, QtyPerUoM, -96); // 96/24 = 4
+
+        // [GIVEN] Second entry with Tracking status (not Reservation)
+        CreateMockReservationEntry(
+            ReservationEntry2, SalesLine, "Reservation Status"::Tracking, QtyPerUoM, -96); // 96/24 = 4
+
+        // [WHEN] Third entry is created with Tracking status
+        CreateMockReservationEntry(
+            ReservationEntry3, SalesLine, "Reservation Status"::Tracking, QtyPerUoM, -96); // 96/24 = 4
+
+        // [THEN] The total should be 12 (each entry = 4, total = 12)
+        TotalQuantity := Abs(ReservationEntry1.Quantity + ReservationEntry2.Quantity + ReservationEntry3.Quantity);
+        Assert.AreEqual(12, TotalQuantity,
+            'Total quantity should be 12 when all three Tracking entries are correctly considered');
+    end;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure CalcReservationQuantityWithMixedReservationAndTracking()
+    var
+        ReservationEntry1: Record "Reservation Entry";
+        ReservationEntry2: Record "Reservation Entry";
+        ReservationEntry3: Record "Reservation Entry";
+        SalesLine: Record "Sales Line";
+        QtyPerUoM: Decimal;
+        TotalQuantity: Decimal;
+    begin
+        // [FEATURE] [Reservation Entry] [Order Tracking]
+        // [SCENARIO] CalcReservationQuantity should include both Reservation and Tracking status entries
+        Initialize();
+
+        // [GIVEN] A UOM with 24 qty per UOM
+        QtyPerUoM := 24;
+
+        // [GIVEN] A mock sales line
+        MockSalesLine(SalesLine);
+
+        // [GIVEN] First entry with Reservation status
+        CreateMockReservationEntry(
+            ReservationEntry1, SalesLine, "Reservation Status"::Reservation, QtyPerUoM, -96);
+
+        // [GIVEN] Second entry with Tracking status
+        CreateMockReservationEntry(
+            ReservationEntry2, SalesLine, "Reservation Status"::Tracking, QtyPerUoM, -96);
+
+        // [WHEN] Third entry is created with Tracking status
+        CreateMockReservationEntry(
+            ReservationEntry3, SalesLine, "Reservation Status"::Tracking, QtyPerUoM, -96);
+
+        // [THEN] Total should be 12 (both Reservation and Tracking entries are included)
+        TotalQuantity := Abs(ReservationEntry1.Quantity + ReservationEntry2.Quantity + ReservationEntry3.Quantity);
+        Assert.AreEqual(12, TotalQuantity,
+            'Total quantity should be 12 when both Reservation and Tracking entries are considered');
+    end;
+
+    local procedure Initialize()
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"SCM Reserv. Tracking Qty UT");
+        if isInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"SCM Reserv. Tracking Qty UT");
+        isInitialized := true;
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"SCM Reserv. Tracking Qty UT");
+    end;
+
+    local procedure MockSalesLine(var SalesLine: Record "Sales Line")
+    var
+        SalesHeader: Record "Sales Header";
+        RecRef: RecordRef;
+    begin
+        SalesHeader.Init();
+        SalesHeader."Document Type" := SalesHeader."Document Type"::Order;
+        SalesHeader."No." := LibraryUtility.GenerateGUID();
+        SalesHeader.Insert();
+
+        SalesLine.Init();
+        SalesLine."Document Type" := SalesHeader."Document Type";
+        SalesLine."Document No." := SalesHeader."No.";
+        RecRef.GetTable(SalesLine);
+        SalesLine."Line No." := LibraryUtility.GetNewLineNo(RecRef, SalesLine.FieldNo("Line No."));
+        SalesLine.Insert();
+    end;
+
+    local procedure CreateMockReservationEntry(var ReservationEntry: Record "Reservation Entry"; SalesLine: Record "Sales Line"; ReservationStatus: Enum "Reservation Status"; QtyPerUoM: Decimal; QtyBase: Decimal)
+    begin
+        ReservationEntry.Init();
+        ReservationEntry."Entry No." := LibraryUtility.GetNewRecNo(ReservationEntry, ReservationEntry.FieldNo("Entry No."));
+        ReservationEntry."Reservation Status" := ReservationStatus;
+        ReservationEntry."Source Type" := Database::"Sales Line";
+        ReservationEntry."Source Subtype" := SalesLine."Document Type".AsInteger();
+        ReservationEntry."Source ID" := SalesLine."Document No.";
+        ReservationEntry."Source Ref. No." := SalesLine."Line No.";
+        ReservationEntry."Source Batch Name" := '';
+        ReservationEntry."Source Prod. Order Line" := 0;
+        ReservationEntry.Positive := QtyBase > 0;
+        ReservationEntry."Qty. per Unit of Measure" := QtyPerUoM;
+        ReservationEntry.Insert();
+        // Validate Quantity (Base) triggers CalcReservationQuantity
+        ReservationEntry.Validate("Quantity (Base)", QtyBase);
+        ReservationEntry.Modify();
+    end;
+}

