+        // [WHEN] Calculate expected costs for single-line production order
+        ProdOrderLine.SetRange(Status, SingleLineProdOrder.Status);
+        ProdOrderLine.SetRange("Prod. Order No.", SingleLineProdOrder."No.");
+        ProdOrderLine.FindFirst();
+        MfgCostCalculationMgt.CalcShareOfTotalCapCost(ProdOrderLine, ShareOfTotalCapCost);
+        MfgCostCalculationMgt.CalcProdOrderLineExpCost(
+            ProdOrderLine, ShareOfTotalCapCost,
+            SingleLineExpMatCost, SingleLineExpCapDirCost, SingleLineExpSubDirCost,
+            SingleLineExpCapOvhdCost, SingleLineExpMfgOvhdCost);
+
+        // [WHEN] Calculate expected costs for multi-line production order
+        Clear(MfgCostCalculationMgt);
+        ProdOrderLine.SetRange(Status, MultiLineProdOrder.Status);
+        ProdOrderLine.SetRange("Prod. Order No.", MultiLineProdOrder."No.");
+        if ProdOrderLine.FindSet() then
+            repeat
+                MfgCostCalculationMgt.CalcShareOfTotalCapCost(ProdOrderLine, ShareOfTotalCapCost);
+                MfgCostCalculationMgt.CalcProdOrderLineExpCost(
+                    ProdOrderLine, ShareOfTotalCapCost,
+                    MultiLineExpMatCost, MultiLineExpCapDirCost, MultiLineExpSubDirCost,
+                    MultiLineExpCapOvhdCost, MultiLineExpMfgOvhdCost);
+            until ProdOrderLine.Next() = 0;
+
+        // [THEN] Manufacturing overhead should be the same for both orders
+        // Expected: Material cost = 2000 (100 * 20), Mfg Overhead = 200 (10% of 2000)
+        Assert.AreEqual(
+            SingleLineExpMfgOvhdCost, MultiLineExpMfgOvhdCost,
+            'Manufacturing overhead cost should be equal for single line vs multiple lines with same total quantity');
+
+        // [THEN] Material costs should also be equal
+        Assert.AreEqual(
+            SingleLineExpMatCost, MultiLineExpMatCost,
+            'Material cost should be equal for single line vs multiple lines with same total quantity');
+    end;
+
     [Test]
     [Scope('OnPrem')]
     procedure CalculateMachineCenterCalendarReport()

