diff --git a/App/Layers/W1/Tests/SCM/SCMWhsePickPlaceLineUpdate.Codeunit.al b/App/Layers/W1/Tests/SCM/SCMWhsePickPlaceLineUpdate.Codeunit.al
new file mode 100644
index 00000000..abb36a59
--- /dev/null
+++ b/App/Layers/W1/Tests/SCM/SCMWhsePickPlaceLineUpdate.Codeunit.al
@@ -0,0 +1,224 @@
+codeunit 137999 "SCM Whse. Pick Place Line Upd."
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Warehouse] [Pick] [Production] [SCM]
+        isInitialized := false;
+    end;
+
+    var
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryWarehouse: Codeunit "Library - Warehouse";
+        LibraryManufacturing: Codeunit "Library - Manufacturing";
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryUtility: Codeunit "Library - Utility";
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        isInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure ChangeQtyOnLastTakeLineUpdatesCorrectPlaceLine()
+    var
+        Location: Record Location;
+        ParentItem: Record Item;
+        ComponentItem: Record Item;
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionBOMLine: Record "Production BOM Line";
+        ProductionOrder: Record "Production Order";
+        WarehouseActivityLine: Record "Warehouse Activity Line";
+        WarehouseActivityHeader: Record "Warehouse Activity Header";
+        Bin: array[5] of Record Bin;
+        QuantityPerBin: Decimal;
+        TotalQuantity: Decimal;
+        NewQuantity: Decimal;
+        LastTakeLineNo: Integer;
+        LastPlaceLineNo: Integer;
+        i: Integer;
+    begin
+        // [SCENARIO] When manually changing quantity of the last "Take Line" in Warehouse Pick, the last "Place Line" should be updated, not the first one.
+        // [GIVEN] Location with Require Pick and Prod. Consumption Whse. Handling = Warehouse Pick (mandatory)
+        Initialize();
+        QuantityPerBin := 900;
+        TotalQuantity := QuantityPerBin * 5;
+        NewQuantity := 400;
+
+        CreateLocationForProductionPick(Location);
+
+        // [GIVEN] Parent Item with Production BOM containing Component Item
+        LibraryInventory.CreateItem(ParentItem);
+        CreateComponentItemWithAllowOverpick(ComponentItem);
+
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, ParentItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, ComponentItem."No.", 1);
+        ProductionBOMHeader.Validate(Status, ProductionBOMHeader.Status::Certified);
+        ProductionBOMHeader.Modify(true);
+
+        ParentItem.Validate("Replenishment System", ParentItem."Replenishment System"::"Prod. Order");
+        ParentItem.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        ParentItem.Modify(true);
+
+        // [GIVEN] Inventory of 900 units in each of 5 bins (total 4500)
+        for i := 1 to 5 do begin
+            LibraryWarehouse.CreateBin(Bin[i], Location.Code, 'S-01-0' + Format(i), '', '');
+            CreatePositiveAdjustmentWithBin(ComponentItem."No.", Location.Code, Bin[i].Code, QuantityPerBin);
+        end;
+
+        // [GIVEN] Released Production Order for 4200 units
+        LibraryManufacturing.CreateProductionOrder(
+            ProductionOrder, ProductionOrder.Status::Released,
+            ProductionOrder."Source Type"::Item, ParentItem."No.", 4200);
+        ProductionOrder.Validate("Location Code", Location.Code);
+        ProductionOrder.Modify(true);
+        LibraryManufacturing.RefreshProdOrder(ProductionOrder, false, true, true, true, false);
+
+        // [GIVEN] Warehouse Pick created from Production Order (should have multiple Take/Place line pairs)
+        LibraryWarehouse.CreateWhsePickFromProduction(ProductionOrder);
+
+        // Find the warehouse activity header
+        WarehouseActivityLine.SetRange("Source Type", DATABASE::"Prod. Order Component");
+        WarehouseActivityLine.SetRange("Source Subtype", ProductionOrder.Status);
+        WarehouseActivityLine.SetRange("Source No.", ProductionOrder."No.");
+        WarehouseActivityLine.FindFirst();
+        WarehouseActivityHeader.Get(WarehouseActivityHeader.Type::Pick, WarehouseActivityLine."No.");
+
+        // [GIVEN] Find the last Take line and its corresponding Place line
+        FindLastTakeAndPlaceLine(
+            WarehouseActivityHeader."No.", ComponentItem."No.", Location.Code,
+            LastTakeLineNo, LastPlaceLineNo);
+
+        // Verify that the last Place line has line number greater than last Take line
+        Assert.IsTrue(LastPlaceLineNo > LastTakeLineNo, 'Place line should have higher line number than Take line');
+
+        // Get the original quantity on the last Place line
+        WarehouseActivityLine.Reset();
+        WarehouseActivityLine.SetRange("Activity Type", WarehouseActivityLine."Activity Type"::Pick);
+        WarehouseActivityLine.SetRange("No.", WarehouseActivityHeader."No.");
+        WarehouseActivityLine.SetRange("Line No.", LastPlaceLineNo);
+        WarehouseActivityLine.FindFirst();
+        Assert.AreEqual(QuantityPerBin, WarehouseActivityLine.Quantity, 'Initial Place line quantity should match bin quantity');
+
+        // [WHEN] Change the quantity on the last Take line from 900 to 400
+        WarehouseActivityLine.Reset();
+        WarehouseActivityLine.SetRange("Activity Type", WarehouseActivityLine."Activity Type"::Pick);
+        WarehouseActivityLine.SetRange("No.", WarehouseActivityHeader."No.");
+        WarehouseActivityLine.SetRange("Line No.", LastTakeLineNo);
+        WarehouseActivityLine.FindFirst();
+        WarehouseActivityLine.Validate(Quantity, NewQuantity);
+        WarehouseActivityLine.Modify(true);
+
+        // [THEN] The last Place line quantity is updated to 400 (not the first Place line)
+        WarehouseActivityLine.Reset();
+        WarehouseActivityLine.SetRange("Activity Type", WarehouseActivityLine."Activity Type"::Pick);
+        WarehouseActivityLine.SetRange("No.", WarehouseActivityHeader."No.");
+        WarehouseActivityLine.SetRange("Line No.", LastPlaceLineNo);
+        WarehouseActivityLine.FindFirst();
+        Assert.AreEqual(
+            NewQuantity, WarehouseActivityLine.Quantity,
+            'The last Place line should be updated to the new quantity');
+    end;
+
+    local procedure Initialize()
+    var
+        WarehouseActivityLine: Record "Warehouse Activity Line";
+        WarehouseSetup: Record "Warehouse Setup";
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(CODEUNIT::"SCM Whse. Pick Place Line Upd.");
+        WarehouseActivityLine.DeleteAll();
+
+        if isInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(CODEUNIT::"SCM Whse. Pick Place Line Upd.");
+
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        LibraryERMCountryData.CreateVATData();
+        LibraryWarehouse.NoSeriesSetup(WarehouseSetup);
+
+        isInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(CODEUNIT::"SCM Whse. Pick Place Line Upd.");
+    end;
+
+    local procedure CreateLocationForProductionPick(var Location: Record Location)
+    var
+        WarehouseEmployee: Record "Warehouse Employee";
+    begin
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(Location);
+        Location.Validate("Bin Mandatory", true);
+        Location.Validate("Require Shipment", true);
+        Location.Validate("Require Pick", true);
+        Location.Validate("Prod. Consump. Whse. Handling", "Prod. Consump. Whse. Handling"::"Warehouse Pick (mandatory)");
+        Location.Modify(true);
+
+        // Create production bins
+        Location.Validate("To-Production Bin Code", CreateBinCode(Location.Code));
+        Location.Validate("From-Production Bin Code", CreateBinCode(Location.Code));
+        Location.Modify(true);
+
+        LibraryWarehouse.CreateWarehouseEmployee(WarehouseEmployee, Location.Code, true);
+    end;
+
+    local procedure CreateBinCode(LocationCode: Code[10]): Code[20]
+    var
+        Bin: Record Bin;
+    begin
+        LibraryWarehouse.CreateBin(Bin, LocationCode, LibraryUtility.GenerateGUID(), '', '');
+        exit(Bin.Code);
+    end;
+
+    local procedure CreateComponentItemWithAllowOverpick(var Item: Record Item)
+    begin
+        LibraryInventory.CreateItem(Item);
+        Item.Validate("Replenishment System", Item."Replenishment System"::Purchase);
+        Item.Validate("Flushing Method", Item."Flushing Method"::Manual);
+        Item.Validate("Allow Whse. Overpick", true);
+        Item.Modify(true);
+    end;
+
+    local procedure CreatePositiveAdjustmentWithBin(ItemNo: Code[20]; LocationCode: Code[10]; BinCode: Code[20]; Quantity: Decimal)
+    var
+        ItemJournalLine: Record "Item Journal Line";
+        ItemJournalTemplate: Record "Item Journal Template";
+        ItemJournalBatch: Record "Item Journal Batch";
+    begin
+        LibraryInventory.SelectItemJournalTemplateName(ItemJournalTemplate, ItemJournalTemplate.Type::Item);
+        LibraryInventory.SelectItemJournalBatchName(ItemJournalBatch, ItemJournalTemplate.Type, ItemJournalTemplate.Name);
+        LibraryInventory.CreateItemJournalLine(
+            ItemJournalLine, ItemJournalTemplate.Name, ItemJournalBatch.Name,
+            ItemJournalLine."Entry Type"::"Positive Adjmt.", ItemNo, Quantity);
+        ItemJournalLine.Validate("Location Code", LocationCode);
+        ItemJournalLine.Validate("Bin Code", BinCode);
+        ItemJournalLine.Modify(true);
+        LibraryInventory.PostItemJournalLine(ItemJournalTemplate.Name, ItemJournalBatch.Name);
+    end;
+
+    local procedure FindLastTakeAndPlaceLine(WhseActivityNo: Code[20]; ItemNo: Code[20]; LocationCode: Code[10]; var LastTakeLineNo: Integer; var LastPlaceLineNo: Integer)
+    var
+        WarehouseActivityLine: Record "Warehouse Activity Line";
+    begin
+        // Find the last Take line
+        WarehouseActivityLine.SetRange("Activity Type", WarehouseActivityLine."Activity Type"::Pick);
+        WarehouseActivityLine.SetRange("No.", WhseActivityNo);
+        WarehouseActivityLine.SetRange("Item No.", ItemNo);
+        WarehouseActivityLine.SetRange("Location Code", LocationCode);
+        WarehouseActivityLine.SetRange("Action Type", WarehouseActivityLine."Action Type"::Take);
+        WarehouseActivityLine.FindLast();
+        LastTakeLineNo := WarehouseActivityLine."Line No.";
+
+        // Find the corresponding Place line (should be immediately after the Take line)
+        WarehouseActivityLine.Reset();
+        WarehouseActivityLine.SetRange("Activity Type", WarehouseActivityLine."Activity Type"::Pick);
+        WarehouseActivityLine.SetRange("No.", WhseActivityNo);
+        WarehouseActivityLine.SetRange("Item No.", ItemNo);
+        WarehouseActivityLine.SetRange("Location Code", LocationCode);
+        WarehouseActivityLine.SetRange("Action Type", WarehouseActivityLine."Action Type"::Place);
+        WarehouseActivityLine.SetFilter("Line No.", '>%1', LastTakeLineNo);
+        WarehouseActivityLine.FindFirst();
+        LastPlaceLineNo := WarehouseActivityLine."Line No.";
+    end;
+}

