+    [Test]
+    [Scope('OnPrem')]
+    procedure SameItemDiffPositionCommentsTransferredCorrectlyViaPlanningWorksheet()
+    var
+        ProdItem: Record Item;
+        CompItem: Record Item;
+        UnitOfMeasure: Record "Unit of Measure";
+        ItemUnitOfMeasure: Record "Item Unit of Measure";
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionBOMLine1: Record "Production BOM Line";
+        ProductionBOMLine2: Record "Production BOM Line";
+        ProductionBOMCommentLine1: Record "Production BOM Comment Line";
+        ProductionBOMCommentLine2: Record "Production BOM Comment Line";
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        RequisitionLine: Record "Requisition Line";
+        ProductionOrder: Record "Production Order";
+        ProdOrderComponent: Record "Prod. Order Component";
+        ProdOrderCompCmtLine: Record "Prod. Order Comp. Cmt Line";
+        Comment1: Text[80];
+        Comment2: Text[80];
+        Position1: Code[10];
+        Position2: Code[10];
+    begin
+        // [SCENARIO] When same item is listed twice in Production BOM with different Position values and different comments,
+        // creating a Firm Planned Prod. Order via Planning Worksheet should transfer the correct comment to each component line.
+        // Bug: Without the fix, both component lines would get the same comment (from the last matching BOM line).
+        Initialize();
+
+        // [GIVEN] Create Unit of Measure Code
+        LibraryInventory.CreateUnitOfMeasureCode(UnitOfMeasure);
+
+        // [GIVEN] Create Component Item with Purchase replenishment
+        CreateItemWithReorderPolicy(CompItem, UnitOfMeasure, ItemUnitOfMeasure, CompItem."Replenishment System"::Purchase, CompItem."Reordering Policy"::" ");
+
+        // [GIVEN] Create Production Item with Order reordering policy
+        CreateItemWithReorderPolicy(ProdItem, UnitOfMeasure, ItemUnitOfMeasure, ProdItem."Replenishment System"::"Prod. Order", ProdItem."Reordering Policy"::Order);
+
+        // [GIVEN] Create Production BOM Header
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, ProdItem."Base Unit of Measure");
+
+        // [GIVEN] Create first Production BOM Line for Component Item with Position "POS1"
+        Position1 := 'POS1';
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeader,
+            ProductionBOMLine1,
+            '',
+            ProductionBOMLine1.Type::Item,
+            CompItem."No.",
+            1);
+        ProductionBOMLine1.Validate(Position, Position1);
+        ProductionBOMLine1.Modify(true);
+
+        // [GIVEN] Create second Production BOM Line for SAME Component Item with different Position "POS2"
+        Position2 := 'POS2';
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeader,
+            ProductionBOMLine2,
+            '',
+            ProductionBOMLine2.Type::Item,
+            CompItem."No.",
+            1);
+        ProductionBOMLine2.Validate(Position, Position2);
+        ProductionBOMLine2.Modify(true);
+
+        // [GIVEN] Create comment "Test1" for first Production BOM Line
+        Comment1 := 'Test1';
+        CreateProductionBOMCommentLineWithText(ProductionBOMLine1, Comment1, ProductionBOMCommentLine1);
+
+        // [GIVEN] Create comment "Test2" for second Production BOM Line
+        Comment2 := 'Test2';
+        CreateProductionBOMCommentLineWithText(ProductionBOMLine2, Comment2, ProductionBOMCommentLine2);
+
+        // [GIVEN] Certify Production BOM
+        LibraryManufacturing.UpdateProductionBOMStatus(ProductionBOMHeader, ProductionBOMHeader.Status::Certified);
+
+        // [GIVEN] Assign Production BOM to Production Item
+        ProdItem.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        ProdItem.Modify(true);
+
+        // [GIVEN] Create Sales Order for Production Item to create demand
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Order, '');
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, ProdItem."No.", 1);
+        LibrarySales.ReleaseSalesDocument(SalesHeader);
+
+        // [GIVEN] Run Calculate Regenerative Plan
+        RunCalculateRegenerativePlan(ProdItem."No.", '');
+
+        // [GIVEN] Accept Action Message on Requisition Line
+        AcceptActionMessageOnReqLine(RequisitionLine, ProdItem."No.");
+
+        // [WHEN] Carry Out Action Plan to create Firm Planned Production Order
+        CarryOutActionPlanForFirmPlannedProdOrder(RequisitionLine);
+
+        // [THEN] Find the created Firm Planned Production Order
+        ProductionOrder.SetRange("Source Type", ProductionOrder."Source Type"::Item);
+        ProductionOrder.SetRange("Source No.", ProdItem."No.");
+        ProductionOrder.SetRange(Status, ProductionOrder.Status::"Firm Planned");
+        ProductionOrder.FindFirst();
+
+        // [THEN] Find Component with Position "POS1" and verify it has comment "Test1"
+        ProdOrderComponent.SetRange(Status, ProductionOrder.Status);
+        ProdOrderComponent.SetRange("Prod. Order No.", ProductionOrder."No.");
+        ProdOrderComponent.SetRange("Item No.", CompItem."No.");
+        ProdOrderComponent.SetRange(Position, Position1);
+        ProdOrderComponent.FindFirst();
+
+        ProdOrderCompCmtLine.SetRange(Status, ProdOrderComponent.Status);
+        ProdOrderCompCmtLine.SetRange("Prod. Order No.", ProdOrderComponent."Prod. Order No.");
+        ProdOrderCompCmtLine.SetRange("Prod. Order Line No.", ProdOrderComponent."Prod. Order Line No.");
