+codeunit 139614 "Shpfy Copy Document Test"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    var
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryRandom: Codeunit "Library - Random";
+        Assert: Codeunit Assert;
+        IsInitialized: Boolean;
+
+    local procedure Initialize()
+    begin
+        if IsInitialized then
+            exit;
+        LibraryRandom.Init();
+        IsInitialized := true;
+    end;
+
+    [Test]
+    procedure CopyPostedInvoiceClearsShopifyOrderId()
+    var
+        Customer: Record Customer;
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        SalesInvoiceHeader: Record "Sales Invoice Header";
+        ToSalesHeader: Record "Sales Header";
+        CopySalesDoc: Report "Copy Sales Document";
+        ShopifyOrderId: BigInteger;
+        ShopifyOrderNo: Code[50];
+        ShopifyRefundId: BigInteger;
+        PostedDocNo: Code[20];
+    begin
+        // [SCENARIO] When copying a posted sales invoice with Shopify Order Id, the Shopify fields should be cleared in the new document
+        Initialize();
+
+        // [GIVEN] A customer
+        LibrarySales.CreateCustomer(Customer);
+
+        // [GIVEN] A sales invoice with Shopify Order Id, Order No, and Refund Id
+        LibrarySales.CreateSalesInvoice(SalesHeader);
+        ShopifyOrderId := LibraryRandom.RandIntInRange(1000, 9999);
+        ShopifyOrderNo := CopyStr(LibraryRandom.RandText(10), 1, MaxStrLen(ShopifyOrderNo));
+        ShopifyRefundId := LibraryRandom.RandIntInRange(1000, 9999);
+        SalesHeader."Shpfy Order Id" := ShopifyOrderId;
+        SalesHeader."Shpfy Order No." := ShopifyOrderNo;
+        SalesHeader."Shpfy Refund Id" := ShopifyRefundId;
+        SalesHeader.Modify();
+
+        // [GIVEN] The sales invoice is posted
+        PostedDocNo := LibrarySales.PostSalesDocument(SalesHeader, false, true);
+        SalesInvoiceHeader.Get(PostedDocNo);
+
+        // [VERIFY] The posted invoice has the Shopify fields set
+        Assert.AreEqual(ShopifyOrderId, SalesInvoiceHeader."Shpfy Order Id", 'Posted invoice should have Shopify Order Id');
+        Assert.AreEqual(ShopifyOrderNo, SalesInvoiceHeader."Shpfy Order No.", 'Posted invoice should have Shopify Order No.');
+
+        // [GIVEN] A new sales invoice to copy into
+        ToSalesHeader.Init();
+        ToSalesHeader.Validate("Document Type", ToSalesHeader."Document Type"::Invoice);
+        ToSalesHeader.Insert(true);
+
+        // [WHEN] Copy the posted sales invoice with Include Header = true
+        Clear(CopySalesDoc);
+        CopySalesDoc.SetParameters("Sales Document Type From"::"Posted Invoice", PostedDocNo, 0, 0, true, false);
+        CopySalesDoc.SetSalesHeader(ToSalesHeader);
+        CopySalesDoc.UseRequestPage(false);
+        CopySalesDoc.RunModal();
+
+        // [THEN] The new sales invoice should have Shopify Order Id cleared (= 0)
+        ToSalesHeader.Get(ToSalesHeader."Document Type", ToSalesHeader."No.");
+        Assert.AreEqual(0, ToSalesHeader."Shpfy Order Id", 'Shopify Order Id should be cleared after copy');
+
+        // [THEN] The new sales invoice should have Shopify Order No. cleared (= '')
+        Assert.AreEqual('', ToSalesHeader."Shpfy Order No.", 'Shopify Order No. should be cleared after copy');
+
+        // [THEN] The new sales invoice should have Shopify Refund Id cleared (= 0)
+        Assert.AreEqual(0, ToSalesHeader."Shpfy Refund Id", 'Shopify Refund Id should be cleared after copy');
+    end;
+}

diff --git a/App/Layers/W1/Tests/Job/PurchDocFromJobTest.Codeunit.al b/App/Layers/W1/Tests/Job/PurchDocFromJobTest.Codeunit.al
new file mode 100644
index 00000000..c839499f
--- /dev/null
+++ b/App/Layers/W1/Tests/Job/PurchDocFromJobTest.Codeunit.al
@@ -0,0 +1,98 @@
+codeunit 136990 "Purch Doc. From Job Test"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Purchase] [Job] [Planning Lines]
+    end;
+
+    var
+        LibraryJob: Codeunit "Library - Job";
+        LibraryInventory: Codeunit "Library - Inventory";
+        Assert: Codeunit Assert;
+        LibraryRandom: Codeunit "Library - Random";
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure SelectionFilterValidWhenJobPlanningLinesInsertedOutOfOrder()
+    var
+        Job: Record Job;
+        JobTask: Record "Job Task";
+        JobPlanningLine: Record "Job Planning Line";
+        JobPlanningLine1: Record "Job Planning Line";
+        JobPlanningLine2: Record "Job Planning Line";
+        SelectionFilterMgt: Codeunit SelectionFilterManagement;
+        RecRef: RecordRef;
+        Item1No: Code[20];
+        Item2No: Code[20];
+        ContractEntryNoFilter: Text;
+        ContractEntryNo1: Integer;
+        ContractEntryNo2: Integer;
+    begin
+        // [SCENARIO 501234] When creating a purchase order from job planning lines, the Contract Entry No. filter
+        // must be valid even when lines are inserted out of Line No. order (simulating inserting a new line
+        // BEFORE existing lines in the UI). The fix ensures SetCurrentKey("Job Contract Entry No.") is called
+        // before building the selection filter, producing a valid ascending range like "15..16" instead of
+        // an invalid descending range like "16..15" which would match no records.
+
+        // [GIVEN] A Job with a Job Task
+        LibraryJob.CreateJob(Job);
+        LibraryJob.CreateJobTask(Job, JobTask);
+
+        // [GIVEN] Create first Job Planning Line with Line No. 20000 (gets Job Contract Entry No. e.g. 15)
+        Item1No := LibraryInventory.CreateItemNo();
+        CreateJobPlanningLineWithLineNo(JobPlanningLine1, JobTask, Item1No, 20000);
+        ContractEntryNo1 := JobPlanningLine1."Job Contract Entry No.";
+
+        // [GIVEN] Create second Job Planning Line with Line No. 10000 (lower Line No., but gets higher
+        // Job Contract Entry No. e.g. 16 because it was created later)
+        // This simulates inserting a new line BEFORE the existing line in the Job Planning Lines page
+        Item2No := LibraryInventory.CreateItemNo();
+        CreateJobPlanningLineWithLineNo(JobPlanningLine2, JobTask, Item2No, 10000);
+        ContractEntryNo2 := JobPlanningLine2."Job Contract Entry No.";
+
+        // Verify setup is correct: ContractEntryNo2 > ContractEntryNo1
+        Assert.IsTrue(ContractEntryNo2 > ContractEntryNo1,
+            'Setup error: Second line should have higher Job Contract Entry No.');
+
+        // [WHEN] Build selection filter using the approach from the fix:
+        // Sort by Job Contract Entry No. before iterating, so the filter is built in ascending order
+        JobPlanningLine.SetLoadFields("Job Contract Entry No.");
+        JobPlanningLine.SetRange("Job No.", JobTask."Job No.");
+        JobPlanningLine.SetRange("Job Task No.", JobTask."Job Task No.");
+        JobPlanningLine.SetCurrentKey("Job Contract Entry No.");
+        JobPlanningLine.FindSet();
+        RecRef.GetTable(JobPlanningLine);
+        ContractEntryNoFilter := SelectionFilterMgt.GetSelectionFilter(RecRef, JobPlanningLine.FieldNo("Job Contract Entry No."));
+
+        // [THEN] The filter should be in ascending order (e.g. "15..16")
+        Assert.AreEqual(
+            StrSubstNo('%1..%2', ContractEntryNo1, ContractEntryNo2),
+            ContractEntryNoFilter,
+            'Filter must be ascending (lower Contract Entry No. first) to be valid.');
+
+        // [THEN] The filter should find all Job Planning Lines
+        JobPlanningLine.Reset();
+        JobPlanningLine.SetRange("Job No.", JobTask."Job No.");
+        JobPlanningLine.SetRange("Job Task No.", JobTask."Job Task No.");
+        JobPlanningLine.SetFilter("Job Contract Entry No.", ContractEntryNoFilter);
+        Assert.AreEqual(2, JobPlanningLine.Count(),
+            'Both Job Planning Lines should be found with the valid filter.');
+    end;
+
+    local procedure CreateJobPlanningLineWithLineNo(var JobPlanningLine: Record "Job Planning Line"; JobTask: Record "Job Task"; ItemNo: Code[20]; LineNo: Integer)
+    begin
+        JobPlanningLine.Init();
+        JobPlanningLine.Validate("Job No.", JobTask."Job No.");
+        JobPlanningLine.Validate("Job Task No.", JobTask."Job Task No.");
+        JobPlanningLine."Line No." := LineNo;
+        JobPlanningLine.Insert(true);
+        JobPlanningLine.Validate("Line Type", JobPlanningLine."Line Type"::"Both Budget and Billable");
+        JobPlanningLine.Validate(Type, JobPlanningLine.Type::Item);
+        JobPlanningLine.Validate("No.", ItemNo);
+        JobPlanningLine.Validate(Quantity, LibraryRandom.RandDec(10, 2));
+        JobPlanningLine.Modify(true);
+    end;
+}

