+
+    [Test]
+    [Scope('OnPrem')]
+    procedure ShowReservationErrorOnTransferLineWhenItemReserveNever()
+    var
+        Item: Record Item;
+        FromLocation: Record Location;
+        ToLocation: Record Location;
+        InTransitLocation: Record Location;
+        TransferHeader: Record "Transfer Header";
+        TransferLine: Record "Transfer Line";
+        ItemJournalLine: Record "Item Journal Line";
+        ItemJournalBatch: Record "Item Journal Batch";
+        Qty: Decimal;
+    begin
+        // [FEATURE] [Transfer Order] [Reservation]
+        // [SCENARIO] ShowReservation throws an error when Item has Reserve = Never on Transfer Order Line.
+        // This is to ensure consistency with Sales Order behavior where Reserve = Never prevents reservation.
+        Initialize();
+
+        // [GIVEN] Create an Item with Reserve = Never.
+        LibraryInventory.CreateItem(Item);
+        Item.Validate(Reserve, Item.Reserve::Never);
+        Item.Modify(true);
+
+        // [GIVEN] Create locations.
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(FromLocation);
+        LibraryWarehouse.CreateLocation(ToLocation);
+        LibraryWarehouse.CreateInTransitLocation(InTransitLocation);
+
+        // [GIVEN] Post positive adjustment to have inventory at From Location.
+        Qty := LibraryRandom.RandDecInRange(10, 100, 2);
+        CreateAndPostItemJournalLine(ItemJournalLine, ItemJournalBatch, Item."No.", FromLocation.Code, Qty);
+
+        // [GIVEN] Create Transfer Order.
+        LibraryWarehouse.CreateTransferHeader(TransferHeader, FromLocation.Code, ToLocation.Code, InTransitLocation.Code);
+        LibraryWarehouse.CreateTransferLine(TransferHeader, TransferLine, Item."No.", Qty);
+
+        // [WHEN] Show Reservation is invoked on Transfer Line.
+        asserterror TransferLine.ShowReservation();
+
+        // [THEN] An error is thrown because Item.Reserve must have a value (Reserve = Never fails TestField).
+        Assert.ExpectedError('Reserve must have a value in Item');
+    end;
+
+    local procedure Initialize()
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"SCM Transfer Order Reserve");
+        LibraryVariableStorage.Clear();
+
+        if isInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"SCM Transfer Order Reserve");
+
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        LibraryERMCountryData.UpdateSalesReceivablesSetup();
+
+        isInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"SCM Transfer Order Reserve");
+    end;
+
+    local procedure CreateAndPostItemJournalLine(var ItemJournalLine: Record "Item Journal Line"; var ItemJournalBatch: Record "Item Journal Batch"; ItemNo: Code[20]; LocationCode: Code[10]; Quantity: Decimal)
+    var
+        ItemJournalTemplate: Record "Item Journal Template";
+    begin
+        LibraryInventory.SelectItemJournalTemplateName(ItemJournalTemplate, ItemJournalTemplate.Type::Item);
+        LibraryInventory.SelectItemJournalBatchName(ItemJournalBatch, ItemJournalTemplate.Type::Item, ItemJournalTemplate.Name);
+        LibraryInventory.ClearItemJournal(ItemJournalTemplate, ItemJournalBatch);
+        LibraryInventory.CreateItemJournalLine(
+            ItemJournalLine, ItemJournalBatch."Journal Template Name", ItemJournalBatch.Name,
+            ItemJournalLine."Entry Type"::"Positive Adjmt.", ItemNo, Quantity);
+        ItemJournalLine.Validate("Location Code", LocationCode);
+        ItemJournalLine.Modify(true);
+        LibraryInventory.PostItemJournalLine(ItemJournalBatch."Journal Template Name", ItemJournalBatch.Name);
+    end;
+
+}

