+codeunit 137999 "SCM Whse Pick Register Fix"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Warehouse] [Pick] [FEFO] [Reservation] [Item Tracking] [SCM]
+        isInitialized := false;
+    end;
+
+    var
+        LocationSilver: Record Location;
+        ItemJournalTemplate: Record "Item Journal Template";
+        ItemJournalBatch: Record "Item Journal Batch";
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryVariableStorage: Codeunit "Library - Variable Storage";
+        LibraryUtility: Codeunit "Library - Utility";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryItemTracking: Codeunit "Library - Item Tracking";
+        LibraryWarehouse: Codeunit "Library - Warehouse";
+        LibrarySales: Codeunit "Library - Sales";
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        isInitialized: Boolean;
+        TrackingAction: Option " ",AssignLotNo,SelectEntries,SetQuantity;
+
+    [Test]
+    [HandlerFunctions('ItemTrackingPageHandler,MessageHandler')]
+    [Scope('OnPrem')]
+    procedure RegisterPickWithNonSpecificReservationAndFEFO()
+    var
+        Item: Record Item;
+        Bin: Record Bin;
+        SalesHeader: array[2] of Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        WarehouseShipmentHeader: Record "Warehouse Shipment Header";
+        WarehouseActivityHeader: Record "Warehouse Activity Header";
+        WarehouseActivityLine: Record "Warehouse Activity Line";
+        LotNos: array[2] of Code[20];
+        Qty: Decimal;
+    begin
+        // [FEATURE] [FEFO] [Reservation] [Pick] [Item Tracking]
+        // [SCENARIO] Register warehouse pick for sales order with non-specific reservation on FEFO location
+        // when another sales order has already reserved items with the same lot.
+        // This reproduced the issue: "Lot No. LOT0001 is not available on inventory or it has already been reserved for another document."
+
+        // [GIVEN] Location set up for FEFO picking with Bin Mandatory, Require Pick, and Require Shipment
+        Initialize();
+        Qty := LibraryRandom.RandIntInRange(10, 20);
+
+        // [GIVEN] Lot-tracked item "I" with mandatory expiration date entry
+        CreateLotTrackedItemWithExpirationDate(Item);
+
+        // [GIVEN] Two lots "L1" and "L2" are in inventory on the FEFO location. Quantity of each lot = "Q".
+        // [GIVEN] Lot "L2" has an earlier expiration date than lot "L1" (to test FEFO).
+        LibraryWarehouse.FindBin(Bin, LocationSilver.Code, '', 1);
+        CreateAndPostTwoLotTrackedItemJournalLines(LotNos, Item."No.", LocationSilver.Code, Bin.Code, Qty);
+
+        // [GIVEN] Sales order "SO1" with item "I" and quantity = "Q". No item tracking on the sales line.
+        // [GIVEN] Auto-reserve "SO1" against the inventory (non-specific reservation without lot tracking).
+        LibrarySales.CreateSalesDocumentWithItem(
+            SalesHeader[1], SalesLine, SalesHeader[1]."Document Type"::Order, LibrarySales.CreateCustomerNo(),
+            Item."No.", Qty, LocationSilver.Code, LibraryRandom.RandDateFromInRange(WorkDate(), 10, 20));
+        LibrarySales.AutoReserveSalesLine(SalesLine);
+
+        // [GIVEN] Sales order "SO2" with item "I" and quantity = "Q". No item tracking on the sales line.
+        // [GIVEN] Auto-reserve "SO2" against the inventory (non-specific reservation without lot tracking).
+        LibrarySales.CreateSalesDocumentWithItem(
+            SalesHeader[2], SalesLine, SalesHeader[2]."Document Type"::Order, LibrarySales.CreateCustomerNo(),
+            Item."No.", Qty, LocationSilver.Code, LibraryRandom.RandDateFromInRange(WorkDate(), 10, 20));
+        LibrarySales.AutoReserveSalesLine(SalesLine);
+        LibrarySales.ReleaseSalesDocument(SalesHeader[2]);
+
+        // [GIVEN] Create warehouse shipment and pick from "SO2"
+        LibraryWarehouse.CreateWhseShipmentFromSO(SalesHeader[2]);
+        FindWarehouseShipmentHeader(WarehouseShipmentHeader, SalesHeader[2]."No.");
+        LibraryWarehouse.CreatePick(WarehouseShipmentHeader);
+
+        // [WHEN] Register the warehouse pick
+        WarehouseActivityHeader.SetRange(Type, WarehouseActivityHeader.Type::Pick);
+        WarehouseActivityHeader.SetRange("Location Code", LocationSilver.Code);
+        WarehouseActivityLine.SetRange("Source No.", SalesHeader[2]."No.");
+        WarehouseActivityLine.FindFirst();
+        WarehouseActivityHeader.Get(WarehouseActivityHeader.Type::Pick, WarehouseActivityLine."No.");
+        LibraryWarehouse.AutoFillQtyInventoryActivity(WarehouseActivityHeader);
+        LibraryWarehouse.RegisterWhseActivity(WarehouseActivityHeader);
+
+        // [THEN] The pick is registered without error
+        // [THEN] Verify registered pick entries exist
+        VerifyRegisteredWhseActivityLine(SalesHeader[2]."No.", Item."No.", LocationSilver.Code, Qty);
+
+        LibraryVariableStorage.AssertEmpty();
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+        WarehouseEmployee: Record "Warehouse Employee";
+    begin
+        LibraryTestInitialize.OnTestInitialize(CODEUNIT::"SCM Whse Pick Register Fix");
+
+        LibraryVariableStorage.Clear();
+
+        if isInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(CODEUNIT::"SCM Whse Pick Register Fix");
+
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.CreateGeneralPostingSetupData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+
+        CreateLocationSetup();
+        NoSeriesSetup();
+        ItemJournalSetup();
+
+        isInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(CODEUNIT::"SCM Whse Pick Register Fix");
+    end;
+
+    local procedure CreateLocationSetup()
+    var
+        WarehouseEmployee: Record "Warehouse Employee";
+    begin
+        WarehouseEmployee.DeleteAll(true);
+        // Create location with Bin Mandatory, Require Put-Away, Require Pick, Require Receive, Require Shipment, and Pick According To FEFO
+        CreateAndUpdateLocation(LocationSilver, true, true, true, true, true, true);
+        LibraryWarehouse.CreateWarehouseEmployee(WarehouseEmployee, LocationSilver.Code, true);
+        LibraryWarehouse.CreateNumberOfBins(LocationSilver.Code, '', '', LibraryRandom.RandInt(3) + 2, false);
+    end;
+
+    local procedure CreateAndUpdateLocation(var Location: Record Location; BinMandatory: Boolean; RequirePutAway: Boolean; RequirePick: Boolean; RequireReceive: Boolean; RequireShipment: Boolean; PickAccordingToFEFO: Boolean)
+    begin
+        LibraryWarehouse.CreateLocationWMS(Location, BinMandatory, RequirePutAway, RequirePick, RequireReceive, RequireShipment);
+        Location.Validate("Pick According to FEFO", PickAccordingToFEFO);
+        Location.Modify(true);
+    end;
+
+    local procedure NoSeriesSetup()
+    var
+        InventorySetup: Record "Inventory Setup";
+        WarehouseSetup: Record "Warehouse Setup";
+        SalesSetup: Record "Sales & Receivables Setup";
+    begin
+        LibraryInventory.NoSeriesSetup(InventorySetup);
+        LibraryWarehouse.NoSeriesSetup(WarehouseSetup);
+
+        SalesSetup.Get();
+        SalesSetup.Validate("Order Nos.", LibraryUtility.GetGlobalNoSeriesCode());
+        SalesSetup.Modify(true);
+    end;
+
+    local procedure ItemJournalSetup()
+    begin
+        LibraryInventory.SelectItemJournalTemplateName(ItemJournalTemplate, ItemJournalTemplate.Type::Item);
+        LibraryInventory.SelectItemJournalBatchName(ItemJournalBatch, ItemJournalTemplate.Type::Item, ItemJournalTemplate.Name);
+        LibraryInventory.ClearItemJournal(ItemJournalTemplate, ItemJournalBatch);
+    end;
+
+    local procedure CreateLotTrackedItemWithExpirationDate(var Item: Record Item)
+    var
+        ItemTrackingCode: Record "Item Tracking Code";
+        ExpirationCalculation: DateFormula;
+    begin
+        // Create Item Tracking Code with Lot Specific Tracking, Lot Warehouse Tracking, and Use Expiration Dates
+        CreateItemTrackingCode(ItemTrackingCode, true, false, true);
+        LibraryInventory.CreateTrackedItem(Item, LibraryUtility.GetGlobalNoSeriesCode(), '', ItemTrackingCode.Code);
+        // Set Expiration Calculation so that expiration date is automatically calculated based on posting date
+        Evaluate(ExpirationCalculation, StrSubstNo('<%1D>', LibraryRandom.RandIntInRange(30, 60)));
+        Item.Validate("Expiration Calculation", ExpirationCalculation);
+        Item.Modify(true);
+    end;
+
+    local procedure CreateItemTrackingCode(var ItemTrackingCode: Record "Item Tracking Code"; Lot: Boolean; Serial: Boolean; UseExpirationDates: Boolean)
+    begin
+        LibraryItemTracking.CreateItemTrackingCode(ItemTrackingCode, Serial, Lot);
+        ItemTrackingCode.Validate("Lot Warehouse Tracking", Lot);
+        ItemTrackingCode.Validate("SN Warehouse Tracking", Serial);
+        ItemTrackingCode.Validate("Use Expiration Dates", UseExpirationDates);
+        ItemTrackingCode.Modify(true);
+    end;
+
+    local procedure CreateAndPostTwoLotTrackedItemJournalLines(var AssignedLotNos: array[2] of Code[20]; ItemNo: Code[20]; LocationCode: Code[10]; BinCode: Code[20]; Qty: Decimal)
+    var
+        ItemJournalLine: Record "Item Journal Line";
+        i: Integer;
+    begin
+        // Create two lots with different expiration dates (L2 expires before L1 for FEFO testing)
+        for i := 1 to ArrayLen(AssignedLotNos) do begin
+            AssignedLotNos[i] := LibraryUtility.GenerateGUID();
+            CreateLotTrackedItemJournalLine(
+                ItemJournalLine, ItemNo, '', LocationCode, BinCode, WorkDate() - i, AssignedLotNos[i], Qty);
+        end;
+        LibraryInventory.PostItemJournalLine(ItemJournalLine."Journal Template Name", ItemJournalLine."Journal Batch Name");
+    end;
+
+    local procedure CreateLotTrackedItemJournalLine(var ItemJournalLine: Record "Item Journal Line"; ItemNo: Code[20]; VariantCode: Code[10]; LocationCode: Code[10]; BinCode: Code[20]; PostingDate: Date; LotNo: Code[50]; Qty: Decimal)
+    begin
+        LibraryInventory.CreateItemJournalLineInItemTemplate(ItemJournalLine, ItemNo, LocationCode, '', Qty);
+        ItemJournalLine.Validate("Variant Code", VariantCode);
+        ItemJournalLine.Validate("Bin Code", BinCode);
+        ItemJournalLine.Validate("Posting Date", PostingDate);
+        ItemJournalLine.Modify(true);
+
+        LibraryVariableStorage.Enqueue(TrackingAction::AssignLotNo);
+        LibraryVariableStorage.Enqueue(LotNo);
+        LibraryVariableStorage.Enqueue(Qty);
+        ItemJournalLine.OpenItemTrackingLines(false);
+    end;
+
+    local procedure FindWarehouseShipmentHeader(var WarehouseShipmentHeader: Record "Warehouse Shipment Header"; SourceNo: Code[20])
+    var
+        WarehouseShipmentLine: Record "Warehouse Shipment Line";
+    begin
+        WarehouseShipmentLine.SetRange("Source Document", WarehouseShipmentLine."Source Document"::"Sales Order");
+        WarehouseShipmentLine.SetRange("Source No.", SourceNo);
+        WarehouseShipmentLine.SetRange("Source Type", DATABASE::"Sales Line");
+        WarehouseShipmentLine.FindFirst();
+        WarehouseShipmentHeader.Get(WarehouseShipmentLine."No.");
+    end;
+
+    local procedure VerifyRegisteredWhseActivityLine(SourceNo: Code[20]; ItemNo: Code[20]; LocationCode: Code[10]; ExpectedQty: Decimal)
+    var
+        RegisteredWhseActivityLine: Record "Registered Whse. Activity Line";
+    begin
+        RegisteredWhseActivityLine.SetRange("Source Type", DATABASE::"Sales Line");
+        RegisteredWhseActivityLine.SetRange("Source No.", SourceNo);
+        RegisteredWhseActivityLine.SetRange("Item No.", ItemNo);
+        RegisteredWhseActivityLine.SetRange("Location Code", LocationCode);
+        RegisteredWhseActivityLine.SetRange("Activity Type", RegisteredWhseActivityLine."Activity Type"::Pick);
+        RegisteredWhseActivityLine.SetRange("Action Type", RegisteredWhseActivityLine."Action Type"::Take);
+        Assert.RecordIsNotEmpty(RegisteredWhseActivityLine);
+        RegisteredWhseActivityLine.CalcSums(Quantity);
+        Assert.AreEqual(ExpectedQty, RegisteredWhseActivityLine.Quantity, 'Expected quantity on registered pick line');
+    end;
+
+    [ModalPageHandler]
+    [Scope('OnPrem')]
+    procedure ItemTrackingPageHandler(var ItemTrackingLines: TestPage "Item Tracking Lines")
+    var
+        DequeueVariable: Variant;
+        LocalTrackingAction: Option " ",AssignLotNo,SelectEntries,SetQuantity;
+    begin
+        LibraryVariableStorage.Dequeue(DequeueVariable);
+        LocalTrackingAction := DequeueVariable;
+        case LocalTrackingAction of
+            LocalTrackingAction::AssignLotNo:
+                begin
+                    ItemTrackingLines."Lot No.".SetValue(LibraryVariableStorage.DequeueText());
+                    ItemTrackingLines."Quantity (Base)".SetValue(LibraryVariableStorage.DequeueDecimal());
+                end;
+        end;
+        ItemTrackingLines.OK().Invoke();
+    end;
+
+    [MessageHandler]
+    [Scope('OnPrem')]
+    procedure MessageHandler(Message: Text[1024])
+    begin
+        // Dummy Message Handler to handle pick creation message
+    end;
+}

