+codeunit 137943 "SCM Whse Shpt Preview Transfer"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Warehouse Shipment] [Transfer Order] [Posting Preview]
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryWarehouse: Codeunit "Library - Warehouse";
+        LibraryRandom: Codeunit "Library - Random";
+        isInitialized: Boolean;
+
+    [Test]
+    [HandlerFunctions('GLPostingPreviewPageHandler')]
+    [Scope('OnPrem')]
+    procedure WhseShptLineExistsAfterPostPreviewFromTransferOrder()
+    var
+        Item: Record Item;
+        Location: Record Location;
+        ToLocation: Record Location;
+        TransitLocation: Record Location;
+        TransferHeader: Record "Transfer Header";
+        TransferLine: Record "Transfer Line";
+        WarehouseShipmentHeader: Record "Warehouse Shipment Header";
+        WarehouseShipmentLine: Record "Warehouse Shipment Line";
+        WarehouseEmployee: Record "Warehouse Employee";
+        ItemJournalLine: Record "Item Journal Line";
+        WarehouseShipment: TestPage "Warehouse Shipment";
+        Quantity: Decimal;
+    begin
+        // [SCENARIO] Warehouse shipment line linked to a Transfer Order should not disappear after Preview posting
+        // Bug: The warehouse shipment line was being deleted during preview posting because PostUpdateWhseDocuments
+        // was being called even in preview mode.
+        Initialize();
+
+        // [GIVEN] Create an Item
+        LibraryInventory.CreateItem(Item);
+
+        // [GIVEN] Create locations - From location with Require Shipment, To location, and In-Transit location
+        CreateLocationWithRequireShipment(Location);
+        LibraryWarehouse.CreateLocation(ToLocation);
+        LibraryWarehouse.CreateInTransitLocation(TransitLocation);
+
+        // [GIVEN] Create Warehouse Employee for the From location
+        LibraryWarehouse.CreateWarehouseEmployee(WarehouseEmployee, Location.Code, false);
+
+        // [GIVEN] Create and post positive adjustment for the Item at the From location
+        Quantity := LibraryRandom.RandIntInRange(1, 10);
+        CreateAndPostItemJournalLine(ItemJournalLine, Item."No.", Quantity, Location.Code);
+
+        // [GIVEN] Create and release Transfer Order from the location with Require Shipment to the destination location
+        LibraryWarehouse.CreateTransferHeader(TransferHeader, Location.Code, ToLocation.Code, TransitLocation.Code);
+        LibraryWarehouse.CreateTransferLine(TransferHeader, TransferLine, Item."No.", Quantity);
+        LibraryWarehouse.ReleaseTransferOrder(TransferHeader);
+
+        // [GIVEN] Create Warehouse Shipment from the Transfer Order
+        LibraryWarehouse.CreateWhseShipmentFromTO(TransferHeader);
+        FindWarehouseShipmentLine(WarehouseShipmentLine, WarehouseShipmentLine."Source Document"::"Outbound Transfer", TransferHeader."No.");
+        WarehouseShipmentHeader.Get(WarehouseShipmentLine."No.");
+
+        // [GIVEN] Set Qty. to Ship on the Warehouse Shipment Line
+        WarehouseShipmentLine.Validate("Qty. to Ship", Quantity);
+        WarehouseShipmentLine.Modify(true);
+
+        Commit();
+
+        // [WHEN] Preview Posting is invoked from the Warehouse Shipment page
+        WarehouseShipment.OpenEdit();
+        WarehouseShipment.GoToRecord(WarehouseShipmentHeader);
+        WarehouseShipment.PreviewPosting.Invoke();
+
+        // [THEN] The Warehouse Shipment Line should still exist after preview posting
+        WarehouseShipmentLine.SetRange("Source Document", WarehouseShipmentLine."Source Document"::"Outbound Transfer");
+        WarehouseShipmentLine.SetRange("Source No.", TransferHeader."No.");
+        Assert.IsFalse(WarehouseShipmentLine.IsEmpty(), 'Warehouse Shipment Line should exist after preview posting');
+
+        // [THEN] The Warehouse Shipment Header should still exist
+        Assert.IsTrue(WarehouseShipmentHeader.Get(WarehouseShipmentLine."No."), 'Warehouse Shipment Header should exist after preview posting');
+
+        // [THEN] The Warehouse Shipment Line should have the same quantity as before preview
+        WarehouseShipmentLine.FindFirst();
+        Assert.AreEqual(Quantity, WarehouseShipmentLine.Quantity, 'Warehouse Shipment Line Quantity should be unchanged after preview');
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"SCM Whse Shpt Preview Transfer");
+
+        if isInitialized then
+            exit;
+
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"SCM Whse Shpt Preview Transfer");
+
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+
+        isInitialized := true;
+        Commit();
+
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"SCM Whse Shpt Preview Transfer");
+    end;
+
+    local procedure CreateLocationWithRequireShipment(var Location: Record Location)
+    begin
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(Location);
+        Location.Validate("Require Shipment", true);
+        Location.Modify(true);
+    end;
+
+    local procedure CreateAndPostItemJournalLine(var ItemJournalLine: Record "Item Journal Line"; ItemNo: Code[20]; Quantity: Decimal; LocationCode: Code[10])
+    var
+        ItemJournalTemplate: Record "Item Journal Template";
+        ItemJournalBatch: Record "Item Journal Batch";
+    begin
+        LibraryInventory.SelectItemJournalTemplateName(ItemJournalTemplate, ItemJournalTemplate.Type::Item);
+        LibraryInventory.SelectItemJournalBatchName(ItemJournalBatch, ItemJournalTemplate.Type::Item, ItemJournalTemplate.Name);
+        LibraryInventory.CreateItemJournalLine(
+            ItemJournalLine, ItemJournalTemplate.Name, ItemJournalBatch.Name,
+            ItemJournalLine."Entry Type"::"Positive Adjmt.", ItemNo, Quantity);
+        ItemJournalLine.Validate("Location Code", LocationCode);
+        ItemJournalLine.Modify(true);
+        LibraryInventory.PostItemJournalLine(ItemJournalTemplate.Name, ItemJournalBatch.Name);
+    end;
+
+    local procedure FindWarehouseShipmentLine(var WarehouseShipmentLine: Record "Warehouse Shipment Line"; SourceDocument: Enum "Warehouse Activity Source Document"; SourceNo: Code[20])
+    begin
+        WarehouseShipmentLine.SetRange("Source Document", SourceDocument);
+        WarehouseShipmentLine.SetRange("Source No.", SourceNo);
+        WarehouseShipmentLine.FindFirst();
+    end;
+
+    [PageHandler]
+    [Scope('OnPrem')]
+    procedure GLPostingPreviewPageHandler(var GLPostingPreview: TestPage "G/L Posting Preview")
+    begin
+        // Close the preview page - the test verifies that data is not modified after preview
+        GLPostingPreview.Close();
+    end;
+}

