+codeunit 137902 "SCM Consumption Multi Lot Rsv"
+{
+    // [FEATURE] [Consumption] [Reservation] [Item Tracking]
+    // Tests for posting consumption when component item is reserved across multiple Item Ledger Entries with same lot number.
+
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        IsInitialized := false;
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryItemTracking: Codeunit "Library - Item Tracking";
+        LibraryManufacturing: Codeunit "Library - Manufacturing";
+        LibraryUtility: Codeunit "Library - Utility";
+        LibraryRandom: Codeunit "Library - Random";
+        IsInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure PostConsumptionReservedToMultipleLotTrackedILEs()
+    var
+        ComponentItem: Record Item;
+        ParentItem: Record Item;
+        ProductionOrder: Record "Production Order";
+        ProdOrderComponent: Record "Prod. Order Component";
+        ItemJournalTemplate: Record "Item Journal Template";
+        ItemJournalBatch: Record "Item Journal Batch";
+        ItemJournalLine: Record "Item Journal Line";
+        ReservationEntry: Record "Reservation Entry";
+        ItemLedgerEntry: Record "Item Ledger Entry";
+        LotNo: Code[50];
+        Qty1: Decimal;
+        Qty2: Decimal;
+        Qty3: Decimal;
+        TotalQty: Decimal;
+    begin
+        // [SCENARIO] Post consumption for a lot-tracked item that is reserved across multiple Item Ledger Entries with the same lot number.
+        // [GIVEN] Component item with lot tracking and Reserve = Always
+        // [GIVEN] 3 positive adjustments (5, 10, 20) creating 3 ILEs with same lot number = 35 total
+        // [GIVEN] Released Production Order for 35 qty with component auto-reserved to the 3 ILEs
+        // [WHEN] Post consumption for 35 qty with the lot number
+        // [THEN] Consumption is posted successfully without error
+
+        Initialize();
+
+        // Setup quantities
+        Qty1 := 5;
+        Qty2 := 10;
+        Qty3 := 20;
+        TotalQty := Qty1 + Qty2 + Qty3;
+
+        // Create lot-tracked component item with Reserve = Always
+        CreateLotTrackedItemWithReserveAlways(ComponentItem);
+
+        // Create parent item with production BOM using the component
+        CreateParentItemWithProductionBOM(ParentItem, ComponentItem."No.");
+
+        // Create lot number
+        LotNo := LibraryUtility.GenerateGUID();
+
+        // Create 3 positive adjustments creating 3 Item Ledger Entries with same lot number
+        CreateItemJournalBatch(ItemJournalTemplate, ItemJournalBatch);
+        CreatePositiveAdjustmentWithLotTracking(ItemJournalLine, ItemJournalBatch, ComponentItem."No.", '', Qty1, LotNo);
+        CreatePositiveAdjustmentWithLotTracking(ItemJournalLine, ItemJournalBatch, ComponentItem."No.", '', Qty2, LotNo);
+        CreatePositiveAdjustmentWithLotTracking(ItemJournalLine, ItemJournalBatch, ComponentItem."No.", '', Qty3, LotNo);
+        LibraryInventory.PostItemJournalLine(ItemJournalBatch."Journal Template Name", ItemJournalBatch.Name);
+
+        // Verify 3 Item Ledger Entries created with the lot number
+        ItemLedgerEntry.SetRange("Item No.", ComponentItem."No.");
+        ItemLedgerEntry.SetRange("Lot No.", LotNo);
+        Assert.AreEqual(3, ItemLedgerEntry.Count(), 'Expected 3 Item Ledger Entries with the lot number');
+
+        // Create and refresh Released Production Order
+        LibraryManufacturing.CreateProductionOrder(
+            ProductionOrder, ProductionOrder.Status::Released,
+            ProductionOrder."Source Type"::Item, ParentItem."No.", TotalQty);
+        LibraryManufacturing.RefreshProdOrder(ProductionOrder, false, true, true, true, false);
+
+        // Auto-reserve component to the ILEs (Reserve = Always triggers auto-reservation)
+        FindProdOrderComponent(ProdOrderComponent, ProductionOrder."No.", ComponentItem."No.");
+        ProdOrderComponent.AutoReserve();
+
+        // Verify reservation entries created
+        ReservationEntry.SetRange("Item No.", ComponentItem."No.");
+        ReservationEntry.SetRange("Source Type", Database::"Prod. Order Component");
+        ReservationEntry.SetRange("Source ID", ProductionOrder."No.");
+        ReservationEntry.SetRange("Reservation Status", ReservationEntry."Reservation Status"::Reservation);
+        Assert.AreEqual(3, ReservationEntry.Count(), 'Expected 3 reservation entries linking to 3 ILEs');
+
+        // Create consumption journal with item tracking
+        CreateConsumptionJournalWithLotTracking(
+            ItemJournalBatch, ProductionOrder."No.", ComponentItem."No.", TotalQty, LotNo);
+
+        // Exercise: Post consumption - this should succeed with the fix
+        LibraryInventory.PostItemJournalLine(ItemJournalBatch."Journal Template Name", ItemJournalBatch.Name);
+
+        // Verify: Item Ledger Entry for consumption created
+        ItemLedgerEntry.Reset();
+        ItemLedgerEntry.SetRange("Item No.", ComponentItem."No.");
+        ItemLedgerEntry.SetRange("Entry Type", ItemLedgerEntry."Entry Type"::Consumption);
+        ItemLedgerEntry.SetRange("Lot No.", LotNo);
+        Assert.IsTrue(ItemLedgerEntry.FindFirst(), 'Expected consumption Item Ledger Entry');
+        Assert.AreEqual(-TotalQty, ItemLedgerEntry.Quantity, 'Expected consumption quantity to match');
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"SCM Consumption Multi Lot Rsv");
+
+        if IsInitialized then
+            exit;
+
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"SCM Consumption Multi Lot Rsv");
+
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        LibraryERMCountryData.CreateVATData();
+
+        IsInitialized := true;
+        Commit();
+
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"SCM Consumption Multi Lot Rsv");
+    end;
+
+    local procedure CreateLotTrackedItemWithReserveAlways(var Item: Record Item)
+    var
+        ItemTrackingCode: Record "Item Tracking Code";
+    begin
+        LibraryItemTracking.CreateItemTrackingCode(ItemTrackingCode, false, true);
+        LibraryInventory.CreateItem(Item);
+        Item.Validate("Item Tracking Code", ItemTrackingCode.Code);
+        Item.Validate("Lot Nos.", LibraryUtility.GetGlobalNoSeriesCode());
+        Item.Validate(Reserve, Item.Reserve::Always);
+        Item.Validate("Flushing Method", Item."Flushing Method"::Manual);
+        Item.Modify(true);
+    end;
+
+    local procedure CreateParentItemWithProductionBOM(var ParentItem: Record Item; ComponentItemNo: Code[20])
+    var
+        ProductionBOMHeader: Record "Production BOM Header";
+    begin
+        LibraryInventory.CreateItem(ParentItem);
+        LibraryManufacturing.CreateCertifiedProductionBOM(ProductionBOMHeader, ComponentItemNo, 1);
+        ParentItem.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        ParentItem.Validate("Replenishment System", ParentItem."Replenishment System"::"Prod. Order");
+        ParentItem.Modify(true);
+    end;
+
+    local procedure CreateItemJournalBatch(var ItemJournalTemplate: Record "Item Journal Template"; var ItemJournalBatch: Record "Item Journal Batch")
+    begin
+        LibraryInventory.SelectItemJournalTemplateName(ItemJournalTemplate, ItemJournalTemplate.Type::Item);
+        LibraryInventory.SelectItemJournalBatchName(ItemJournalBatch, ItemJournalTemplate.Type::Item, ItemJournalTemplate.Name);
+        LibraryInventory.ClearItemJournal(ItemJournalTemplate, ItemJournalBatch);
+    end;
+
+    local procedure CreatePositiveAdjustmentWithLotTracking(var ItemJournalLine: Record "Item Journal Line"; ItemJournalBatch: Record "Item Journal Batch"; ItemNo: Code[20]; LocationCode: Code[10]; Quantity: Decimal; LotNo: Code[50])
+    var
+        ReservationEntry: Record "Reservation Entry";
+    begin
+        LibraryInventory.CreateItemJournalLine(
+            ItemJournalLine, ItemJournalBatch."Journal Template Name", ItemJournalBatch.Name,
+            ItemJournalLine."Entry Type"::"Positive Adjmt.", ItemNo, Quantity);
+        if LocationCode <> '' then begin
+            ItemJournalLine.Validate("Location Code", LocationCode);
+            ItemJournalLine.Modify(true);
+        end;
+        LibraryItemTracking.CreateItemJournalLineItemTracking(ReservationEntry, ItemJournalLine, '', LotNo, Quantity);
+    end;
+
+    local procedure FindProdOrderComponent(var ProdOrderComponent: Record "Prod. Order Component"; ProductionOrderNo: Code[20]; ItemNo: Code[20])
+    begin
+        ProdOrderComponent.SetRange(Status, ProdOrderComponent.Status::Released);
+        ProdOrderComponent.SetRange("Prod. Order No.", ProductionOrderNo);
+        ProdOrderComponent.SetRange("Item No.", ItemNo);
+        ProdOrderComponent.FindFirst();
+    end;
+
+    local procedure CreateConsumptionJournalWithLotTracking(var ItemJournalBatch: Record "Item Journal Batch"; ProductionOrderNo: Code[20]; ItemNo: Code[20]; Quantity: Decimal; LotNo: Code[50])
+    var
+        ItemJournalTemplate: Record "Item Journal Template";
+        ItemJournalLine: Record "Item Journal Line";
+        ProdOrderLine: Record "Prod. Order Line";
+        ReservationEntry: Record "Reservation Entry";
+    begin
+        // Set up consumption journal batch
+        LibraryInventory.SelectItemJournalTemplateName(ItemJournalTemplate, ItemJournalTemplate.Type::Consumption);
+        LibraryInventory.SelectItemJournalBatchName(ItemJournalBatch, ItemJournalTemplate.Type::Consumption, ItemJournalTemplate.Name);
+        LibraryInventory.ClearItemJournal(ItemJournalTemplate, ItemJournalBatch);
+
+        // Find production order line
+        ProdOrderLine.SetRange(Status, ProdOrderLine.Status::Released);
+        ProdOrderLine.SetRange("Prod. Order No.", ProductionOrderNo);
+        ProdOrderLine.FindFirst();
+
+        // Create consumption journal line
+        LibraryInventory.CreateItemJournalLine(
+            ItemJournalLine, ItemJournalBatch."Journal Template Name", ItemJournalBatch.Name,
+            ItemJournalLine."Entry Type"::Consumption, ItemNo, Quantity);
+        ItemJournalLine.Validate("Order Type", ItemJournalLine."Order Type"::Production);
+        ItemJournalLine.Validate("Order No.", ProductionOrderNo);
+        ItemJournalLine.Validate("Order Line No.", ProdOrderLine."Line No.");
+        ItemJournalLine.Modify(true);
+
+        // Add lot tracking to consumption line
+        LibraryItemTracking.CreateItemJournalLineItemTracking(ReservationEntry, ItemJournalLine, '', LotNo, Quantity);
+    end;
+}

