+codeunit 135302 "Item Charge Return Order Tests"
+{
+    Subtype = Test;
+    TestPermissions = NonRestrictive;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Sales] [Item Charge] [Return Order]
+    end;
+
+    var
+        Assert: Codeunit Assert;
+        LibrarySales: Codeunit "Library - Sales";
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryRandom: Codeunit "Library - Random";
+        LibraryVariableStorage: Codeunit "Library - Variable Storage";
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+        isInitialized: Boolean;
+
+    [Test]
+    [HandlerFunctions('ItemChargeAssignmentSalesHandler,PostedSalesDocumentLinesHandler')]
+    [Scope('OnPrem')]
+    procedure ItemChargeReversedWhenDefaultQtyToShipIsBlank()
+    var
+        Customer: Record Customer;
+        Item: Record Item;
+        ItemCharge: Record "Item Charge";
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        SalesLineItemCharge: Record "Sales Line";
+        SalesHeaderReturn: Record "Sales Header";
+        SalesLineReturn: Record "Sales Line";
+        SalesReceivablesSetup: Record "Sales & Receivables Setup";
+        PostedInvoiceNo: Code[20];
+        ItemQty: Decimal;
+        ItemChargeQty: Decimal;
+    begin
+        // [SCENARIO] Item charge can be copied to Sales Return Order using Get Posted Document Lines to Reverse when Default Qty. to Ship is set to Blank
+        // [FEATURE] [Sales Return Order] [Item Charge] [Default Quantity to Ship]
+        Initialize();
+
+        // [GIVEN] Sales & Receivables Setup with "Default Quantity to Ship" = Blank
+        SalesReceivablesSetup.Get();
+        SalesReceivablesSetup."Default Quantity to Ship" := SalesReceivablesSetup."Default Quantity to Ship"::Blank;
+        SalesReceivablesSetup.Modify(true);
+
+        // [GIVEN] A customer
+        LibrarySales.CreateCustomer(Customer);
+
+        // [GIVEN] An item with inventory
+        LibraryInventory.CreateItem(Item);
+
+        // [GIVEN] An item charge
+        LibraryInventory.CreateItemCharge(ItemCharge);
+
+        // [GIVEN] Create a Sales Order with an item line (Qty: 25) and an item charge line (Qty: 25)
+        ItemQty := LibraryRandom.RandIntInRange(10, 30);
+        ItemChargeQty := ItemQty;
+
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Order, Customer."No.");
+
+        // Create item line
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, Item."No.", ItemQty);
+        SalesLine.Validate("Unit Price", LibraryRandom.RandDecInRange(10, 100, 2));
+        SalesLine.Modify(true);
+
+        // Create item charge line
+        LibrarySales.CreateSalesLine(SalesLineItemCharge, SalesHeader, SalesLineItemCharge.Type::"Charge (Item)", ItemCharge."No.", ItemChargeQty);
+        SalesLineItemCharge.Validate("Unit Price", LibraryRandom.RandDecInRange(10, 100, 2));
+        SalesLineItemCharge.Modify(true);
+
+        // [GIVEN] Carry out Item Charge Assignment
+        LibraryVariableStorage.Enqueue(ItemChargeQty);
+        SalesLineItemCharge.ShowItemChargeAssgnt();
+
+        // [GIVEN] Post (Ship and Invoice) the Sales Order
+        PostedInvoiceNo := LibrarySales.PostSalesDocument(SalesHeader, true, true);
+
+        // [WHEN] Create Sales Return Order and Get Posted Document Lines to Reverse for both item and charge item lines
+        LibrarySales.CreateSalesHeader(SalesHeaderReturn, SalesHeaderReturn."Document Type"::"Return Order", Customer."No.");
+        LibraryVariableStorage.Enqueue(PostedInvoiceNo);
+        SalesHeaderReturn.GetPstdDocLinesToReverse();
+
+        // [THEN] Both lines should be copied successfully without error
+        // [THEN] Verify item line exists on return order
+        SalesLineReturn.SetRange("Document Type", SalesHeaderReturn."Document Type");
+        SalesLineReturn.SetRange("Document No.", SalesHeaderReturn."No.");
+        SalesLineReturn.SetRange(Type, SalesLineReturn.Type::Item);
+        SalesLineReturn.SetRange("No.", Item."No.");
+        Assert.RecordIsNotEmpty(SalesLineReturn);
+
+        // [THEN] Verify item charge line exists on return order
+        SalesLineReturn.SetRange(Type, SalesLineReturn.Type::"Charge (Item)");
+        SalesLineReturn.SetRange("No.", ItemCharge."No.");
+        Assert.RecordIsNotEmpty(SalesLineReturn);
+
+        LibraryVariableStorage.AssertEmpty();
+    end;
+
+    local procedure Initialize()
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"Item Charge Return Order Tests");
+        LibraryVariableStorage.Clear();
+
+        if isInitialized then
+            exit;
+
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"Item Charge Return Order Tests");
+
+        LibraryERMCountryData.UpdateGeneralLedgerSetup();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        LibraryERMCountryData.UpdateSalesReceivablesSetup();
+        LibraryERMCountryData.CreateVATData();
+
+        isInitialized := true;
+        Commit();
+
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"Item Charge Return Order Tests");
+    end;
+
+    [ModalPageHandler]
+    [Scope('OnPrem')]
+    procedure ItemChargeAssignmentSalesHandler(var ItemChargeAssignmentSales: TestPage "Item Charge Assignment (Sales)")
+    var
+        QtyToAssign: Decimal;
+    begin
+        QtyToAssign := LibraryVariableStorage.DequeueDecimal();
+        ItemChargeAssignmentSales.First();
+        ItemChargeAssignmentSales."Qty. to Assign".SetValue(QtyToAssign);
+        ItemChargeAssignmentSales.OK().Invoke();
+    end;
+
+    [ModalPageHandler]
+    [Scope('OnPrem')]
+    procedure PostedSalesDocumentLinesHandler(var PostedSalesDocumentLines: TestPage "Posted Sales Document Lines")
+    var
+        PostedInvoiceNo: Code[20];
+    begin
+        PostedInvoiceNo := CopyStr(LibraryVariableStorage.DequeueText(), 1, 20);
+        PostedSalesDocumentLines.PostedInvoices.FILTER.SetFilter("Document No.", PostedInvoiceNo);
+        PostedSalesDocumentLines.OK().Invoke();
+    end;
+}

