+    [Scope('OnPrem')]
+    procedure CustomerTotalAmountNotTripledWhenShippedAndInvoiceGetsShipmentLines()
+    var
+        Customer: Record Customer;
+        Item: Record Item;
+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        SalesHeaderInvoice: Record "Sales Header";
+        SalesShipmentLine: Record "Sales Shipment Line";
+        SalesGetShipment: Codeunit "Sales-Get Shipment";
+        ShipmentNo: Code[20];
+        UnitPrice: Decimal;
+        Qty: Integer;
+        ExpectedTotalAmount: Decimal;
+    begin
+        // [SCENARIO] Customer "Total Amount" is not tripled when a Sales Order is shipped and a Sales Invoice uses Get Shipment Lines
+        // [FEATURE] [Statistics] [Sales] [Shipped Not Invoiced]
+        Initialize();
+
+        // [GIVEN] Customer
+        LibrarySales.CreateCustomer(Customer);
+
+        // [GIVEN] Item with Unit Price = 1000
+        UnitPrice := 1000;
+        Qty := 10;
+        LibraryInventory.CreateItem(Item);
+        Item.Validate("Unit Price", UnitPrice);
+        Item.Modify(true);
+
+        // [GIVEN] Sales Order with 10 PCS of Item at $1,000 each = $10,000 total
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Order, Customer."No.");
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, Item."No.", Qty);
+        SalesLine.Validate("Unit Price", UnitPrice);
+        SalesLine.Modify(true);
+        ExpectedTotalAmount := UnitPrice * Qty;
+
+        // [GIVEN] Sales Order is posted as Ship only (not invoiced)
+        ShipmentNo := LibrarySales.PostSalesDocument(SalesHeader, true, false);
+
+        // [GIVEN] Sales Invoice is created using Get Shipment Lines
+        LibrarySales.CreateSalesHeader(SalesHeaderInvoice, SalesHeaderInvoice."Document Type"::Invoice, Customer."No.");
+        SalesGetShipment.SetSalesHeader(SalesHeaderInvoice);
+        SalesShipmentLine.SetRange("Document No.", ShipmentNo);
+        SalesGetShipment.CreateInvLines(SalesShipmentLine);
+
+        // [GIVEN] Sales Invoice is released but not posted
+        LibrarySales.ReleaseSalesDocument(SalesHeaderInvoice);
+
+        // [WHEN] Calculate Customer's Total Amount
+        Customer.Get(Customer."No.");
+
+        // [THEN] Customer's Total Amount equals the sales amount ($10,000), not tripled ($30,000)
+        Assert.AreEqual(ExpectedTotalAmount, Customer.GetTotalAmountLCY(), 'Total Amount should equal the actual sales value, not be tripled.');
+    end;
+
     [Test]
     [HandlerFunctions('ConfirmHandlerYes,MessageHandler')]
     [Scope('OnPrem')]

