+    [Test]
+    [Scope('OnPrem')]
+    procedure CarryOutActionMsgRespectsActionMessageFilter()
+    var
+        Item: Record Item;
+        Vendor: Record Vendor;
+        RequisitionWkshName: Record "Requisition Wksh. Name";
+        RequisitionLine: Record "Requisition Line";
+        RequisitionLineTmp: Record "Requisition Line";
+        NewPurchOrderChoice: Option " ","Make Purch. Orders","Make Purch. Orders & Print","Copy to Req. Wksh";
+        NewLineNo: Integer;
+        CancelLineNo: Integer;
+    begin
+        // [FEATURE] [Planning] [Carry Out Action Message]
+        // [SCENARIO 508620] When a filter is set in Planning Worksheet to a specific Action Message (e.g. New)
+        // and Carry Out Action Message is completed, only the filtered lines should be processed.
+        // Previously, setting Action Message filter was being overwritten by internal SetFilter call.
+
+        // [GIVEN] Initialize test and create basic setup
+        Initialize();
+        CreateItemWithOrderReorderingPolicy(Item);
+        LibraryPurchase.CreateVendor(Vendor);
+        Item.Validate("Vendor No.", Vendor."No.");
+        Item.Modify(true);
+
+        // [GIVEN] Create a planning worksheet with two requisition lines with different Action Messages
+        LibraryPlanning.SelectRequisitionWkshName(RequisitionWkshName, RequisitionWkshName."Template Type"::Planning);
+
+        // Create a line with Action Message = New
+        CreateRequisitionLineWithActionMessage(
+            RequisitionLine, RequisitionWkshName, Item."No.", Vendor."No.",
+            RequisitionLine."Action Message"::New, LibraryRandom.RandIntInRange(5, 10));
+        NewLineNo := RequisitionLine."Line No.";
+
+        // Create a line with Action Message = Cancel
+        CreateRequisitionLineWithActionMessage(
+            RequisitionLine, RequisitionWkshName, Item."No.", Vendor."No.",
+            RequisitionLine."Action Message"::Cancel, LibraryRandom.RandIntInRange(5, 10));
+        CancelLineNo := RequisitionLine."Line No.";
+
+        // [GIVEN] Both lines have Accept Action Message = true
+        RequisitionLineTmp.SetRange("Worksheet Template Name", RequisitionWkshName."Worksheet Template Name");
+        RequisitionLineTmp.SetRange("Journal Batch Name", RequisitionWkshName.Name);
+        Assert.AreEqual(2, RequisitionLineTmp.Count(), 'Expected 2 requisition lines');
+
+        Commit();
+
+        // [WHEN] Filter requisition lines by Action Message = New and run Carry Out Action Message
+        // The filter simulates user filtering in the Planning Worksheet page by Action Message field
+        RequisitionLine.Reset();
+        RequisitionLine.SetRange("Worksheet Template Name", RequisitionWkshName."Worksheet Template Name");
+        RequisitionLine.SetRange("Journal Batch Name", RequisitionWkshName.Name);
+        RequisitionLine.SetRange("Action Message", RequisitionLine."Action Message"::New);
+        RequisitionLine.FindFirst();
+
+        // Run Carry Out Action Message with option to make purchase orders
+        LibraryPlanning.CarryOutPlanWksh(
+            RequisitionLine,
+            0,  // ProdOrderChoice: None
+            NewPurchOrderChoice::"Make Purch. Orders",  // PurchOrderChoice: Make Purchase Orders
+            0,  // TransOrderChoice: None
+            0,  // AsmOrderChoice: None
+            '', '', '', '');
+
+        // [THEN] The New line should be processed (deleted from requisition worksheet, purchase order created)
+        RequisitionLine.Reset();
+        RequisitionLine.SetRange("Worksheet Template Name", RequisitionWkshName."Worksheet Template Name");
+        RequisitionLine.SetRange("Journal Batch Name", RequisitionWkshName.Name);
+        RequisitionLine.SetRange("Line No.", NewLineNo);
+        Assert.RecordIsEmpty(RequisitionLine);
+
+        // [THEN] The Cancel line should still exist (NOT processed because it was filtered out)
+        // This is the key verification - with the bug, ALL lines would be processed regardless of filter
+        RequisitionLine.Reset();
+        RequisitionLine.SetRange("Worksheet Template Name", RequisitionWkshName."Worksheet Template Name");
+        RequisitionLine.SetRange("Journal Batch Name", RequisitionWkshName.Name);
+        RequisitionLine.SetRange("Line No.", CancelLineNo);
+        Assert.RecordIsNotEmpty(RequisitionLine);
+
+        // [THEN] Verify a purchase order was created for the New line
+        VerifyPurchaseOrderExists(Vendor."No.", Item."No.");
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(CODEUNIT::"SCM CarryOut ActionMsg Filter");
+
+        if isInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(CODEUNIT::"SCM CarryOut ActionMsg Filter");
+
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+        LibraryERMCountryData.CreateVATData();
+
+        isInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(CODEUNIT::"SCM CarryOut ActionMsg Filter");
+    end;
+
+    local procedure CreateItemWithOrderReorderingPolicy(var Item: Record Item)
+    begin
+        LibraryInventory.CreateItem(Item);
+        Item.Validate("Reordering Policy", Item."Reordering Policy"::Order);
+        Item.Validate("Replenishment System", Item."Replenishment System"::Purchase);
+        Item.Modify(true);
+    end;
+
+    local procedure CreateRequisitionLineWithActionMessage(var RequisitionLine: Record "Requisition Line"; RequisitionWkshName: Record "Requisition Wksh. Name"; ItemNo: Code[20]; VendorNo: Code[20]; ActionMessage: Enum "Action Message Type"; Quantity: Decimal)
+    begin
+        LibraryPlanning.CreateRequisitionLine(RequisitionLine, RequisitionWkshName."Worksheet Template Name", RequisitionWkshName.Name);
+        RequisitionLine.Validate(Type, RequisitionLine.Type::Item);
+        RequisitionLine.Validate("No.", ItemNo);
+        RequisitionLine.Validate("Due Date", WorkDate());
+        RequisitionLine.Validate(Quantity, Quantity);
+        RequisitionLine.Validate("Vendor No.", VendorNo);
+        RequisitionLine.Validate("Action Message", ActionMessage);
+        RequisitionLine.Validate("Accept Action Message", true);
+        RequisitionLine."Ref. Order Type" := RequisitionLine."Ref. Order Type"::Purchase;
+        RequisitionLine.Modify(true);
+    end;
+
+    local procedure VerifyPurchaseOrderExists(VendorNo: Code[20]; ItemNo: Code[20])
+    var
+        PurchaseLine: Record "Purchase Line";
+    begin
+        PurchaseLine.SetRange("Document Type", PurchaseLine."Document Type"::Order);
+        PurchaseLine.SetRange("Buy-from Vendor No.", VendorNo);
+        PurchaseLine.SetRange("No.", ItemNo);
+        Assert.RecordIsNotEmpty(PurchaseLine);
+    end;
+}

