+codeunit 134988 "Reminder Level Comm. Test"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    var
+        LibraryERM: Codeunit "Library - ERM";
+        LibraryVariableStorage: Codeunit "Library - Variable Storage";
+        Assert: Codeunit Assert;
+
+    [Test]
+    [HandlerFunctions('ConfirmHandlerNo,LanguagesModalPageHandler')]
+    procedure AddTextForLanguageWhenNoAttachmentTextsExist()
+    var
+        ReminderTerms: Record "Reminder Terms";
+        ReminderLevel: Record "Reminder Level";
+        ReminderAttachmentText: Record "Reminder Attachment Text";
+        ReminderLevelCommunicationTestPage: TestPage "Reminder Level Communication";
+        LanguageCode: Code[10];
+    begin
+        // [SCENARIO 573492] Adding text for language in Reminder Level Communication when no attachment texts exist should not error
+        // [FEATURE] Reminder Level Communication
+
+        // [GIVEN] A Reminder Terms with a Reminder Level that has no attachment texts
+        LibraryERM.CreateReminderTerms(ReminderTerms);
+        LibraryERM.CreateReminderLevel(ReminderLevel, ReminderTerms.Code);
+
+        // [GIVEN] A language code different from the current language
+        LanguageCode := LibraryERM.GetAnyLanguageDifferentFromCurrent();
+        LibraryVariableStorage.Enqueue(LanguageCode);
+
+        // [WHEN] User opens the Reminder Level Communication page, says No to the prompts for creating default texts,
+        // then uses "Add text for language" action and selects a language
+        ReminderLevelCommunicationTestPage.OpenEdit();
+        ReminderLevelCommunicationTestPage.GoToRecord(ReminderLevel);
+        // The ConfirmHandler will say No to the initial prompts for creating attachment/email texts
+        // Then we invoke the "Add New Language" action which triggers the Languages page (handled by LanguagesModalPageHandler)
+        ReminderLevelCommunicationTestPage."Add New Language".Invoke();
+        ReminderLevelCommunicationTestPage.Close();
+
+        // [THEN] No error occurs and the reminder attachment text is created for the selected language
+        ReminderLevel.Get(ReminderTerms.Code, ReminderLevel."No.");
+        Assert.IsFalse(IsNullGuid(ReminderLevel."Reminder Attachment Text"), 'Reminder Attachment Text ID should be populated');
+        ReminderAttachmentText.SetRange(Id, ReminderLevel."Reminder Attachment Text");
+        ReminderAttachmentText.SetRange("Language Code", LanguageCode);
+        Assert.IsTrue(ReminderAttachmentText.FindFirst(), 'Reminder Attachment Text record should exist for the selected language');
+    end;
+
+    [ConfirmHandler]
+    procedure ConfirmHandlerNo(Question: Text[1024]; var Reply: Boolean)
+    begin
+        // Say No to all confirmation dialogs (for creating default attachment/email texts)
+        Reply := false;
+    end;
+
+    [ModalPageHandler]
+    procedure LanguagesModalPageHandler(var Languages: TestPage Languages)
+    var
+        LanguageCode: Code[10];
+    begin
+        // Select the language code from variable storage
+        LanguageCode := CopyStr(LibraryVariableStorage.DequeueText(), 1, MaxStrLen(LanguageCode));
+        Languages.Filter.SetFilter(Code, LanguageCode);
+        Languages.First();
+        Languages.OK().Invoke();
+    end;
+}

