+        ShopifyUnitCost := 100;  // 100 FCY should become 50 LCY
+        ShopifyPrice := 5000;    // 5000 FCY should become 2500 LCY
+        ShopifyVariant."Unit Cost" := ShopifyUnitCost;
+        ShopifyVariant.Price := ShopifyPrice;
+        ShopifyVariant.Modify();
+        ShopifyVariant.SetRecFilter();
