diff --git a/App/Layers/W1/Tests/SCM-Service/ServiceItemLineStatusTest.Codeunit.al b/App/Layers/W1/Tests/SCM-Service/ServiceItemLineStatusTest.Codeunit.al
new file mode 100644
index 00000000..fbd9413b
--- /dev/null
+++ b/App/Layers/W1/Tests/SCM-Service/ServiceItemLineStatusTest.Codeunit.al
@@ -0,0 +1,138 @@
+// ------------------------------------------------------------------------------------------------
+// Copyright (c) Microsoft Corporation. All rights reserved.
+// Licensed under the MIT License. See License.txt in the project root for license information.
+// ------------------------------------------------------------------------------------------------
+namespace Microsoft.Service.Test;
+
+using Microsoft.Sales.Customer;
+using Microsoft.Service.Document;
+using Microsoft.Service.Item;
+using Microsoft.Service.Maintenance;
+
+codeunit 136199 "Service Item Line Status Test"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Service] [Service Item Line]
+    end;
+
+    var
+        LibraryService: Codeunit "Library - Service";
+        LibrarySales: Codeunit "Library - Sales";
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        IsInitialized: Boolean;
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure ServiceOrderHeaderStatusUpdatedWhenNewLineWithServiceItemNoAdded()
+    var
+        ServiceHeader: Record "Service Header";
+        ServiceItemLine: Record "Service Item Line";
+        ServiceItemLine2: Record "Service Item Line";
+        ServiceItem: Record "Service Item";
+        ServiceItem2: Record "Service Item";
+        RepairStatusFinished: Record "Repair Status";
+        RepairStatusPending: Record "Repair Status";
+    begin
+        // [SCENARIO] When adding a new service item line with a Pending repair status to a service order
+        // that has Finished status, the header status should be updated to Pending automatically.
+
+        // [GIVEN] A service order with one service item line having Finished repair status
+        Initialize();
+        CreateRepairStatusFinished(RepairStatusFinished);
+        CreateRepairStatusPending(RepairStatusPending);
+
+        LibraryService.CreateServiceItem(ServiceItem, CreateCustomer());
+        LibraryService.CreateServiceHeader(ServiceHeader, ServiceHeader."Document Type"::Order, ServiceItem."Customer No.");
+        LibraryService.CreateServiceItemLine(ServiceItemLine, ServiceHeader, ServiceItem."No.");
+
+        // Set the first line to Finished status
+        ServiceItemLine.Validate("Repair Status Code", RepairStatusFinished.Code);
+        ServiceItemLine.Modify(true);
+
+        // Verify header status is Finished
+        ServiceHeader.Get(ServiceHeader."Document Type", ServiceHeader."No.");
+        ServiceHeader.TestField(Status, ServiceHeader.Status::Finished);
+
+        // [GIVEN] A second service item with a Pending repair status set before inserting the line
+        LibraryService.CreateServiceItem(ServiceItem2, ServiceItem."Customer No.");
+
+        // [WHEN] Create a new service item line with Pending repair status and then validate Service Item No.
+        ServiceItemLine2.Init();
+        ServiceItemLine2.Validate("Document Type", ServiceHeader."Document Type");
+        ServiceItemLine2.Validate("Document No.", ServiceHeader."No.");
+        ServiceItemLine2."Line No." := GetNextLineNo(ServiceHeader);
+        ServiceItemLine2."Repair Status Code" := RepairStatusPending.Code;
+        ServiceItemLine2.Insert(true);
+
+        // Validate Service Item No. which should trigger re-validation of Repair Status Code
+        ServiceItemLine2.Validate("Service Item No.", ServiceItem2."No.");
+        ServiceItemLine2.Modify(true);
+
+        // [THEN] The service header status should be updated to Pending (priority order)
+        ServiceHeader.Get(ServiceHeader."Document Type", ServiceHeader."No.");
+        Assert.AreEqual(
+            ServiceHeader.Status::Pending,
+            ServiceHeader.Status,
+            'Service Header Status should be updated to Pending when a new line with Pending repair status is added');
+    end;
+
+    local procedure Initialize()
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"Service Item Line Status Test");
+
+        if IsInitialized then
+            exit;
+
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"Service Item Line Status Test");
+
+        IsInitialized := true;
+        Commit();
+
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"Service Item Line Status Test");
+    end;
+
+    local procedure CreateCustomer(): Code[20]
+    var
+        Customer: Record Customer;
+    begin
+        LibrarySales.CreateCustomer(Customer);
+        exit(Customer."No.");
+    end;
+
+    local procedure CreateRepairStatusFinished(var RepairStatus: Record "Repair Status")
+    begin
+        RepairStatus.SetRange(Finished, true);
+        if not RepairStatus.FindFirst() then begin
+            LibraryService.CreateRepairStatus(RepairStatus);
+            RepairStatus.Validate(Finished, true);
+            RepairStatus.Modify(true);
+        end;
+    end;
+
+    local procedure CreateRepairStatusPending(var RepairStatus: Record "Repair Status")
+    begin
+        // A Pending status is the Initial status in the repair status priority system
+        RepairStatus.SetRange(Initial, true);
+        if not RepairStatus.FindFirst() then begin
+            LibraryService.CreateRepairStatus(RepairStatus);
+            RepairStatus.Validate(Initial, true);
+            RepairStatus.Modify(true);
+        end;
+    end;
+
+    local procedure GetNextLineNo(ServiceHeader: Record "Service Header"): Integer
+    var
+        ServiceItemLine: Record "Service Item Line";
+    begin
+        ServiceItemLine.SetRange("Document Type", ServiceHeader."Document Type");
+        ServiceItemLine.SetRange("Document No.", ServiceHeader."No.");
+        if ServiceItemLine.FindLast() then
+            exit(ServiceItemLine."Line No." + 10000);
+        exit(10000);
+    end;
+}

