diff --git a/App/Layers/W1/Tests/SCM/SCMPlanningMultiSubassembly.Codeunit.al b/App/Layers/W1/Tests/SCM/SCMPlanningMultiSubassembly.Codeunit.al
new file mode 100644
index 00000000..1afc1f1f
--- /dev/null
+++ b/App/Layers/W1/Tests/SCM/SCMPlanningMultiSubassembly.Codeunit.al
@@ -0,0 +1,121 @@
+codeunit 137959 "SCM Planning Multi Subassembly"
+{
+    Subtype = Test;
+    TestPermissions = Disabled;
+
+    trigger OnRun()
+    begin
+        // [FEATURE] [Planning] [Planning Worksheet] [SCM]
+        isInitialized := false;
+    end;
+
+    var
+        LibraryInventory: Codeunit "Library - Inventory";
+        LibraryPlanning: Codeunit "Library - Planning";
+        LibraryManufacturing: Codeunit "Library - Manufacturing";
+        LibraryRandom: Codeunit "Library - Random";
+        Assert: Codeunit Assert;
+        LibraryTestInitialize: Codeunit "Library - Test Initialize";
+        isInitialized: Boolean;
+        RequisitionLineMustNotExistErr: Label 'Requisition Line must not exist for Item %1.', Comment = '%1 - Item No';
+
+    [Test]
+    [Scope('OnPrem')]
+    procedure CalcRegenPlanForComponentUsedInMultipleSubassemblies()
+    var
+        TopLevelItem: Record Item;
+        SubassemblyItemA: Record Item;
+        SubassemblyItemB: Record Item;
+        BottomLevelItem: Record Item;
+        ProductionBOMHeader: Record "Production BOM Header";
+        ProductionBOMHeaderTopLevel: Record "Production BOM Header";
+        ProductionOrder: Record "Production Order";
+        RequisitionLine: Record "Requisition Line";
+        ProdOrderComponent: Record "Prod. Order Component";
+    begin
+        // [FEATURE] [Production Order] [Regenerative Plan]
+        // [SCENARIO] When an item is consumed in multiple subassemblies of a production order, running regenerative plan
+        // should not create unnecessary planning lines if the supply already matches the demand.
+
+        // Issue: For an item that is consumed in multiple subassemblies, running planning worksheet suggests
+        // to change Quantity from 2 to 1, but then also create a new Prod. Order for 1, which is unnecessary noise.
+
+        Initialize();
+
+        // [GIVEN] Bottom level Item "I3" with Replenishment = Prod Order, Manufacturing Policy = Make-to-Order, Reordering Policy = Lot-for-Lot
+        CreateMakeToOrderLotForLotItem(BottomLevelItem);
+
+        // [GIVEN] Subassembly Items "I2A" and "I2B" with Replenishment = Prod Order, Manufacturing Policy = Make-to-Order, Reordering Policy = Lot-for-Lot
+        // [GIVEN] Both "I2A" and "I2B" have Production BOMs that include "I3" with Quantity Per = 1
+        LibraryManufacturing.CreateCertifiedProductionBOM(ProductionBOMHeader, BottomLevelItem."No.", 1);
+        CreateMakeToOrderLotForLotItem(SubassemblyItemA);
+        SubassemblyItemA.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        SubassemblyItemA.Modify(true);
+
+        Clear(ProductionBOMHeader);
+        LibraryManufacturing.CreateCertifiedProductionBOM(ProductionBOMHeader, BottomLevelItem."No.", 1);
+        CreateMakeToOrderLotForLotItem(SubassemblyItemB);
+        SubassemblyItemB.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        SubassemblyItemB.Modify(true);
+
+        // [GIVEN] Top level Item "I1" with Replenishment = Prod Order, Manufacturing Policy = Make-to-Order, Reordering Policy = Lot-for-Lot
+        // [GIVEN] "I1" has Production BOM that includes "I2A" and "I2B" with Quantity Per = 1
+        LibraryManufacturing.CreateCertifProdBOMWithTwoComp(
+            ProductionBOMHeaderTopLevel, SubassemblyItemA."No.", SubassemblyItemB."No.", 1);
+        CreateMakeToOrderLotForLotItem(TopLevelItem);
+        TopLevelItem.Validate("Production BOM No.", ProductionBOMHeaderTopLevel."No.");
+        TopLevelItem.Modify(true);
+
+        // [GIVEN] Released Production Order for "I1" with Quantity = 1
+        LibraryManufacturing.CreateAndRefreshProductionOrder(
+            ProductionOrder, ProductionOrder.Status::Released, ProductionOrder."Source Type"::Item, TopLevelItem."No.", 1);
+
+        // [GIVEN] After refresh, "I3" should have total demand of 2 (1 from I2A component + 1 from I2B component)
+        ProdOrderComponent.SetRange("Item No.", BottomLevelItem."No.");
+        Assert.AreEqual(2, ProdOrderComponent.Count, 'Expected 2 component lines for bottom level item');
+
+        // [WHEN] Calculate Regenerative Plan for Item "I3"
+        BottomLevelItem.SetRecFilter();
+        LibraryPlanning.CalcRegenPlanForPlanWksh(BottomLevelItem, WorkDate(), CalcDate('<1Y>', WorkDate()));
+
+        // [THEN] No requisition lines are created for "I3" because the supply from Prod. Order Line equals the demand from Prod. Order Components
+        FilterOnRequisitionLine(RequisitionLine, BottomLevelItem."No.");
+        Assert.IsTrue(RequisitionLine.IsEmpty, StrSubstNo(RequisitionLineMustNotExistErr, BottomLevelItem."No."));
+    end;
+
+    local procedure Initialize()
+    var
+        RequisitionLine: Record "Requisition Line";
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(CODEUNIT::"SCM Planning Multi Subassembly");
+        RequisitionLine.DeleteAll();
+
+        if isInitialized then
+            exit;
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(CODEUNIT::"SCM Planning Multi Subassembly");
+
+        LibraryERMCountryData.CreateVATData();
+        LibraryERMCountryData.UpdateGeneralPostingSetup();
+
+        isInitialized := true;
+        Commit();
+
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(CODEUNIT::"SCM Planning Multi Subassembly");
+    end;
+
+    local procedure CreateMakeToOrderLotForLotItem(var Item: Record Item)
+    begin
+        LibraryInventory.CreateItem(Item);
+        Item.Validate("Replenishment System", Item."Replenishment System"::"Prod. Order");
+        Item.Validate("Manufacturing Policy", Item."Manufacturing Policy"::"Make-to-Order");
+        Item.Validate("Reordering Policy", Item."Reordering Policy"::"Lot-for-Lot");
+        Item.Modify(true);
+    end;
+
+    local procedure FilterOnRequisitionLine(var RequisitionLine: Record "Requisition Line"; No: Code[20])
+    begin
+        RequisitionLine.SetRange(Type, RequisitionLine.Type::Item);
+        RequisitionLine.SetRange("No.", No);
+    end;
+}

