+    [Test]
+    [HandlerFunctions('ConfirmHandlerYes')]
+    [Scope('OnPrem')]
+    procedure UndoTransferShptAfterRevaluation()
+    var
+        Item: Record Item;
+        FromLocation: Record Location;
+        ToLocation: Record Location;
+        TransferHeader: Record "Transfer Header";
+        TransferLine: Record "Transfer Line";
+        ItemLedgerEntry: Record "Item Ledger Entry";
+        ItemJournalLine: Record "Item Journal Line";
+        ItemJournalTemplate: Record "Item Journal Template";
+        ItemJournalBatch: Record "Item Journal Batch";
+        TotalCostAmount: Decimal;
+        Qty: Decimal;
+        OriginalUnitCost: Decimal;
+        RevaluedUnitCost: Decimal;
+    begin
+        // [FEATURE] [Transfer] [Undo Shipment] [Revaluation]
+        // [SCENARIO] Undo Transfer Shipment Line after revaluing the original positive adjustment item ledger entry
+        // should result in correct cost amounts (total cost = 0 for all transfer ILEs)
+        Initialize();
+
+        // [GIVEN] Create an item and two locations
+        Qty := 1;
+        OriginalUnitCost := 10;
+        RevaluedUnitCost := 12;
+        LibraryInventory.CreateItem(Item);
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(FromLocation);
+        LibraryWarehouse.CreateLocationWithInventoryPostingSetup(ToLocation);
+
+        // [GIVEN] Create a positive adjustment for the item at the From location
+        CreateAndPostItemJnlWithCostLocationVariant(
+            ItemJournalLine."Entry Type"::"Positive Adjmt.", Item."No.", Qty, OriginalUnitCost, FromLocation.Code, '');
+
+        // [GIVEN] Find the positive adjustment Item Ledger Entry
+        ItemLedgerEntry.SetRange("Item No.", Item."No.");
+        ItemLedgerEntry.SetRange("Entry Type", ItemLedgerEntry."Entry Type"::"Positive Adjmt.");
+        ItemLedgerEntry.FindFirst();
+
+        // [GIVEN] Create and ship a transfer order
+        CreateTransferOrderNoRoute(TransferHeader, TransferLine, FromLocation.Code, ToLocation.Code, Item."No.", '', Qty);
+        LibraryInventory.PostTransferHeader(TransferHeader, true, false);
+
+        // [GIVEN] Revalue the original positive adjustment entry to a higher cost
+        LibraryInventory.SelectItemJournalTemplateName(ItemJournalTemplate, ItemJournalTemplate.Type::Revaluation);
+        LibraryInventory.SelectItemJournalBatchName(ItemJournalBatch, ItemJournalTemplate.Type, ItemJournalTemplate.Name);
+        LibraryInventory.CreateItemJnlLineWithNoItem(
+            ItemJournalLine, ItemJournalBatch, ItemJournalTemplate.Name, ItemJournalBatch.Name, ItemJournalLine."Entry Type"::"Positive Adjmt.");
+        ItemJournalLine.Validate("Value Entry Type", ItemJournalLine."Value Entry Type"::Revaluation);
+        ItemJournalLine.Validate("Item No.", Item."No.");
+        ItemJournalLine.Validate("Applies-to Entry", ItemLedgerEntry."Entry No.");
+        ItemJournalLine.Validate("Unit Cost (Revalued)", RevaluedUnitCost);
+        ItemJournalLine.Modify(true);
+        LibraryInventory.PostItemJournalLine(ItemJournalTemplate.Name, ItemJournalBatch.Name);
+
+        // [GIVEN] Run cost adjustment
+        LibraryCosting.AdjustCostItemEntries(Item."No.", '');
+
+        // [WHEN] Undo the posted transfer shipment
+        LibraryInventory.UndoTransferShipments(TransferHeader."No.");
+
+        // [WHEN] Run cost adjustment again
+        LibraryCosting.AdjustCostItemEntries(Item."No.", '');
+
+        // [THEN] The sum of Cost Amount (Actual) for all transfer Item Ledger Entries is zero
+        ItemLedgerEntry.Reset();
+        ItemLedgerEntry.SetRange("Item No.", Item."No.");
+        ItemLedgerEntry.SetRange("Entry Type", ItemLedgerEntry."Entry Type"::Transfer);
+        TotalCostAmount := 0;
+        if ItemLedgerEntry.FindSet() then
+            repeat
+                ItemLedgerEntry.CalcFields("Cost Amount (Actual)");
+                TotalCostAmount += ItemLedgerEntry."Cost Amount (Actual)";
+            until ItemLedgerEntry.Next() = 0;
+
+        Assert.AreEqual(0, TotalCostAmount, 'Total Cost Amount (Actual) for transfer entries should be zero after undo and cost adjustment');
+    end;
+
