+    [Test]
+    [Scope('OnPrem')]
+    procedure CalcRegenPlanForSKUWithProductionBOMPlansComponentOnFirstRun()
+    var
+        CompItem: Record Item;
+        ProdItem: Record Item;
+        Location: Record Location;
+        ManufacturingSetup: Record "Manufacturing Setup";
+        StockkeepingUnitComp: Record "Stockkeeping Unit";
+        StockkeepingUnitProd: Record "Stockkeeping Unit";
+        ProductionBOMHeader: Record "Production BOM Header";
