+        SalesHeader: Record "Sales Header";
+        SalesLine: Record "Sales Line";
+        Customer: Record Customer;
+        RequisitionLine: Record "Requisition Line";
+    begin
+        // [SCENARIO] When Calculate Regenerative Plan is run for items with SKU that has Production BOM No. assigned,
+        // the component item should be planned in the first run, not requiring a second calculation.
+        // This validates that low-level codes are properly recalculated when Production BOM is assigned to SKU.
+        Initialize();
