+
+        // [GIVEN] Create a Location
+        LibraryWarehouse.CreateLocation(Location);
+
+        // [GIVEN] Create a component item with Purchase replenishment
+        LibraryInventory.CreateItem(CompItem);
+        CompItem.Validate("Replenishment System", CompItem."Replenishment System"::Purchase);
+        CompItem.Validate("Reordering Policy", CompItem."Reordering Policy"::Order);
+        CompItem.Modify(true);
+
+        // [GIVEN] Create a production item with Prod. Order replenishment
+        LibraryInventory.CreateItem(ProdItem);
+        ProdItem.Validate("Replenishment System", ProdItem."Replenishment System"::"Prod. Order");
+        ProdItem.Validate("Reordering Policy", ProdItem."Reordering Policy"::"Lot-for-Lot");
+        ProdItem.Validate("Manufacturing Policy", ProdItem."Manufacturing Policy"::"Make-to-Stock");
+        ProdItem.Modify(true);
+
+        // [GIVEN] Create a certified Production BOM with the component item
+        LibraryManufacturing.CreateProductionBOMHeader(ProductionBOMHeader, ProdItem."Base Unit of Measure");
+        LibraryManufacturing.CreateProductionBOMLine(
+            ProductionBOMHeader, ProductionBOMLine, '', ProductionBOMLine.Type::Item, CompItem."No.", 1);
+        LibraryManufacturing.UpdateProductionBOMStatus(ProductionBOMHeader, ProductionBOMHeader.Status::Certified);
+
+        // [GIVEN] Create SKU for component item at the location with Purchase replenishment and Order policy
+        LibraryInventory.CreateStockkeepingUnitForLocationAndVariant(StockkeepingUnitComp, Location.Code, CompItem."No.", '');
+        StockkeepingUnitComp.Validate("Replenishment System", StockkeepingUnitComp."Replenishment System"::Purchase);
+        StockkeepingUnitComp.Validate("Reordering Policy", StockkeepingUnitComp."Reordering Policy"::Order);
+        StockkeepingUnitComp.Modify(true);
+
+        // [GIVEN] Create SKU for production item at the location with Prod. Order replenishment and assign Production BOM
+        // NOTE: The fix ensures that assigning Production BOM No. to SKU triggers low-level code recalculation
+        LibraryInventory.CreateStockkeepingUnitForLocationAndVariant(StockkeepingUnitProd, Location.Code, ProdItem."No.", '');
+        StockkeepingUnitProd.Validate("Replenishment System", StockkeepingUnitProd."Replenishment System"::"Prod. Order");
+        StockkeepingUnitProd.Validate("Reordering Policy", StockkeepingUnitProd."Reordering Policy"::"Lot-for-Lot");
+        StockkeepingUnitProd.Validate("Production BOM No.", ProductionBOMHeader."No.");
+        StockkeepingUnitProd.Modify(true);
+
+        // [GIVEN] Create a Sales Order for the production item at the location
+        LibrarySales.CreateCustomer(Customer);
+        LibrarySales.CreateSalesHeader(SalesHeader, SalesHeader."Document Type"::Order, Customer."No.");
+        LibrarySales.CreateSalesLine(SalesLine, SalesHeader, SalesLine.Type::Item, ProdItem."No.", LibraryRandom.RandIntInRange(5, 10));
+        SalesLine.Validate("Location Code", Location.Code);
+        SalesLine.Modify(true);
+
+        // [WHEN] Calculate Regenerative Plan for both items (single run)
+        ProdItem.SetFilter("No.", '%1|%2', ProdItem."No.", CompItem."No.");
+        ProdItem.SetFilter("Location Filter", Location.Code);
