+        Assert: Codeunit Assert;
+        isInitialized: Boolean;
+
+    [Test]
+    procedure NonDeductibleVATClearedWhenDirectUnitCostSetToZero()
+    var
+        VATPostingSetup: Record "VAT Posting Setup";
+        PurchHeader: Record "Purchase Header";
+        PurchLine: Record "Purchase Line";
+    begin
+        // [SCENARIO] When Changing the Unit Amount to 0 in the purchase invoice line, the Non Deductible VAT should be removed
+        // [FEATURE] [Non-Deductible VAT] [Purchase Invoice]
+        Initialize();
+
+        // [GIVEN] Non-Deductible VAT Posting Setup with Non-Deductible VAT % > 0
+        LibraryNonDeductibleVAT.CreateNonDeductibleNormalVATPostingSetup(VATPostingSetup);
+
+        // [GIVEN] Purchase invoice with a line containing an item with Direct Unit Cost > 0
+        LibraryPurchase.CreatePurchHeader(
+            PurchHeader, PurchHeader."Document Type"::Invoice,
+            LibraryPurchase.CreateVendorWithVATBusPostingGroup(VATPostingSetup."VAT Bus. Posting Group"));
+        CreatePurchLineItemWithVATProdPostingGroup(PurchLine, PurchHeader, VATPostingSetup."VAT Prod. Posting Group");
+
+        // [GIVEN] The purchase line has Non-Deductible VAT Base and Amount > 0
+        Assert.IsTrue(PurchLine."Non-Deductible VAT Base" > 0, 'Non-Deductible VAT Base should be greater than 0 initially');
+        Assert.IsTrue(PurchLine."Non-Deductible VAT Amount" > 0, 'Non-Deductible VAT Amount should be greater than 0 initially');
+
+        // [WHEN] Change the Direct Unit Cost to 0
+        PurchLine.Validate("Direct Unit Cost", 0);
+        PurchLine.Modify(true);
+
+        // [THEN] The Non-Deductible VAT Base and Amount should be cleared (set to 0)
+        Assert.AreEqual(0, PurchLine."Non-Deductible VAT Base", 'Non-Deductible VAT Base should be 0 after setting Direct Unit Cost to 0');
+        Assert.AreEqual(0, PurchLine."Non-Deductible VAT Amount", 'Non-Deductible VAT Amount should be 0 after setting Direct Unit Cost to 0');
+    end;
+
+    local procedure Initialize()
+    var
+        LibraryERMCountryData: Codeunit "Library - ERM Country Data";
+    begin
+        LibraryTestInitialize.OnTestInitialize(Codeunit::"Non-Ded VAT Clear On Zero Amt");
+        LibrarySetupStorage.Restore();
+        if isInitialized then
+            exit;
+
+        LibraryTestInitialize.OnBeforeTestSuiteInitialize(Codeunit::"Non-Ded VAT Clear On Zero Amt");
+        LibraryNonDeductibleVAT.EnableNonDeductibleVAT();
+        LibraryERMCountryData.UpdatePurchasesPayablesSetup();
+        LibrarySetupStorage.Save(Database::"VAT Setup");
+        isInitialized := true;
+        Commit();
+        LibraryTestInitialize.OnAfterTestSuiteInitialize(Codeunit::"Non-Ded VAT Clear On Zero Amt");
+    end;
+
+    local procedure CreatePurchLineItemWithVATProdPostingGroup(var PurchLine: Record "Purchase Line"; PurchHeader: Record "Purchase Header"; VATProdPostGroupCode: Code[20])
+    begin
+        LibraryPurchase.CreatePurchaseLine(
+            PurchLine, PurchHeader, PurchLine.Type::Item, LibraryInventory.CreateItemWithVATProdPostingGroup(VATProdPostGroupCode), LibraryRandom.RandInt(100));
+        PurchLine.Validate("Direct Unit Cost", LibraryRandom.RandDec(100, 2));
+        PurchLine.Modify(true);
+    end;
+}

